{
  "name": "FleetFlow Pro",
  "description": "A comprehensive fleet management system featuring driver/vehicle registration, intelligent check-out checklists, route tracking with Google Maps integration, and a global analytics dashboard.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  startTime: string;
  endTime?: string;
  distance?: number;
}

export interface AppState {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  checklists: Checklist[];
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getRouteInsights = async (origin: string, destination: string, lat?: number, lng?: number) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Provide a detailed route summary for a trip from ${origin} to ${destination}. Mention estimated traffic patterns and any points of interest for professional drivers.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: lat && lng ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    return {
      text: response.text,
      grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Error fetching route insights:", error);
    return { text: "Error fetching route details. Please check your network.", grounding: [] };
  }
};

export const getFleetStatsAnalysis = async (fleetData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this fleet data and provide 3 key management insights: ${JSON.stringify(fleetData)}`,
    });
    return response.text;
  } catch (error) {
    return "Insights unavailable at the moment.";
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  checklists: Checklist[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  endTrip: (tripId: string, currentKm: number) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>([
    { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
    { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
    { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
  ]);

  const [drivers, setDrivers] = useState<Driver[]>([
    { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
    { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
    { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
  ]);

  const [activeTrips, setActiveTrips] = useState<Trip[]>([]);
  const [checklists, setChecklists] = useState<Checklist[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);

    // Update vehicle status
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));

    // Update driver active status
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));

    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v
    ));

    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d
    ));
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, checklists,
      addVehicle, addDriver, startTrip, endTrip,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

