import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { getFleetStatsAnalysis } from '../services/geminiService';
import { VehicleStatus } from '../types';

const DashboardOverview: React.FC = () => {
  const { vehicles, drivers, activeTrips } = useFleet();
  const [aiInsights, setAiInsights] = useState<string>("Analisando dados da frota...");

  useEffect(() => {
    const fetchInsights = async () => {
      const insights = await getFleetStatsAnalysis({ 
        totalVehicles: vehicles.length, 
        activeTrips: activeTrips.length,
        statusCounts: {
          available: vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length,
          maintenance: vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length,
          inUse: vehicles.filter(v => v.status === VehicleStatus.IN_USE).length,
        }
      });
      setAiInsights(insights || "Não foi possível gerar insights agora.");
    };
    fetchInsights();
  }, [vehicles, activeTrips]);

  const statusData = [
    { name: 'Disponível', value: vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length },
    { name: 'Em Uso', value: vehicles.filter(v => v.status === VehicleStatus.IN_USE).length },
    { name: 'Manutenção', value: vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length },
  ];

  const COLORS = ['#10B981', '#3B82F6', '#EF4444'];

  const kmData = vehicles.map(v => ({ name: v.plate, km: v.currentKm }));

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Dashboard Geral</h2>
        <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-sm font-medium">
          Atualizado agora
        </span>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Veículos Totais', value: vehicles.length, icon: 'fa-truck', color: 'bg-blue-500' },
          { label: 'Motoristas', value: drivers.length, icon: 'fa-users', color: 'bg-purple-500' },
          { label: 'Viagens Ativas', value: activeTrips.length, icon: 'fa-play', color: 'bg-green-500' },
          { label: 'Em Manutenção', value: vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length, icon: 'fa-wrench', color: 'bg-red-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
            <div className={`${stat.color} w-12 h-12 rounded-lg flex items-center justify-center text-white shadow-lg shadow-slate-200`}>
              <i className={`fas ${stat.icon} text-xl`}></i>
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold mb-6">Quilometragem por Veículo</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={kmData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="km" fill="#3b82f6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col items-center">
          <h3 className="text-lg font-bold mb-4 self-start">Status da Frota</h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex flex-wrap justify-center gap-4 mt-4">
            {statusData.map((item, i) => (
              <div key={i} className="flex items-center gap-2 text-xs font-medium">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i] }}></div>
                <span>{item.name}: {item.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* AI Insights Section */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-6 rounded-xl text-white shadow-xl shadow-blue-900/10">
        <div className="flex items-center gap-3 mb-4">
          <div className="bg-white/20 p-2 rounded-lg">
            <i className="fas fa-brain text-xl"></i>
          </div>
          <h3 className="text-lg font-bold">Insights de Gestão IA (Gemini)</h3>
        </div>
        <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg border border-white/20">
          <p className="text-blue-50 leading-relaxed whitespace-pre-wrap italic">
            "{aiInsights}"
          </p>
        </div>
      </div>
    </div>
  );
};

export default DashboardOverview;

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { getRouteInsights } from '../services/geminiService';

const OperationWizard: React.FC = () => {
  const { vehicles, currentUser, startTrip } = useFleet();
  const [step, setStep] = useState(1); // 1: Vehicle Selection, 2: Checklist, 3: Route

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: ''
  });

  const [routeInfo, setRouteInfo] = useState<any>(null);
  const [loadingRoute, setLoadingRoute] = useState(false);

  // Set initial KM when vehicle is selected
  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ ...prev, km: selectedVehicle.currentKm, fuelLevel: selectedVehicle.fuelLevel }));
    }
  }, [selectedVehicle]);

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      startTime: new Date().toISOString()
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: new Date().toISOString()
    };

    startTrip(newTrip, finalChecklist);
    alert('Viagem iniciada com sucesso!');
    // Reset wizard
    setStep(1);
    setSelectedVehicle(null);
  };

  const fetchRouteDetails = async () => {
    if (!route.origin || !route.destination) return;
    setLoadingRoute(true);
    const info = await getRouteInsights(route.origin, route.destination);
    setRouteInfo(info);
    setLoadingRoute(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-4">
      {/* Stepper Header */}
      <div className="flex items-center justify-between mb-8 px-4">
        {[
          { step: 1, label: 'Veículo', icon: 'fa-truck-pickup' },
          { step: 2, label: 'Checklist', icon: 'fa-clipboard-check' },
          { step: 3, label: 'Rota', icon: 'fa-map-marked-alt' }
        ].map((s) => (
          <div key={s.step} className="flex flex-col items-center flex-1">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${
              step >= s.step ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white border-slate-200 text-slate-400'
            }`}>
              <i className={`fas ${s.icon}`}></i>
            </div>
            <span className={`text-xs mt-2 font-bold uppercase tracking-wider ${step >= s.step ? 'text-blue-600' : 'text-slate-400'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        {step === 1 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Qual veículo você está pegando?</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => (
                <button
                  key={v.id}
                  onClick={() => setSelectedVehicle(v)}
                  className={`p-6 rounded-xl border-2 text-left transition-all flex items-center gap-4 ${
                    selectedVehicle?.id === v.id ? 'border-blue-600 bg-blue-50 ring-4 ring-blue-100' : 'border-slate-100 hover:border-blue-200'
                  }`}
                >
                  <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                    <i className="fas fa-truck text-xl"></i>
                  </div>
                  <div className="flex-1">
                    <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                    <p className="text-sm text-slate-500">{v.brand} {v.model}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs font-bold text-blue-600 uppercase">Disponível</p>
                    <p className="text-xs text-slate-400">{v.currentKm} km</p>
                  </div>
                </button>
              ))}
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length === 0 && (
                <p className="col-span-full text-center py-10 text-slate-400">Nenhum veículo disponível no momento.</p>
              )}
            </div>
            <div className="mt-8 flex justify-end">
              <button
                disabled={!selectedVehicle}
                onClick={() => setStep(2)}
                className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-2">Checklist de Segurança</h3>
            <p className="text-slate-500 mb-8">Veículo: <span className="font-bold text-blue-600">{selectedVehicle?.plate}</span></p>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Quilometragem Atual</label>
                  <input
                    type="number"
                    value={checklist.km}
                    onChange={(e) => setChecklist({ ...checklist, km: parseInt(e.target.value) })}
                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium"
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Nível de Combustível (%)</label>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={checklist.fuelLevel}
                    onChange={(e) => setChecklist({ ...checklist, fuelLevel: parseInt(e.target.value) })}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 mt-4"
                  />
                  <div className="flex justify-between text-xs font-bold text-slate-400 mt-2">
                    <span>Vazio</span>
                    <span className="text-blue-600">{checklist.fuelLevel}%</span>
                    <span>Cheio</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {[
                  { key: 'oilChecked', label: 'Verificar Óleo', icon: 'fa-oil-can' },
                  { key: 'waterChecked', label: 'Verificar Água', icon: 'fa-tint' },
                  { key: 'tiresChecked', label: 'Pneus Calibrados', icon: 'fa-car' }
                ].map(item => (
                  <button
                    key={item.key}
                    onClick={() => setChecklist({ ...checklist, [item.key]: !checklist[item.key as keyof Checklist] })}
                    className={`p-4 rounded-xl border-2 flex items-center justify-center gap-3 transition-all ${
                      checklist[item.key as keyof Checklist] ? 'bg-green-50 border-green-500 text-green-700' : 'bg-slate-50 border-slate-100 text-slate-400'
                    }`}
                  >
                    <i className={`fas ${item.icon}`}></i>
                    <span className="font-bold text-sm">{item.label}</span>
