import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { getRouteInsights } from '../services/geminiService';

const OperationWizard: React.FC = () => {
  const { vehicles, currentUser, startTrip } = useFleet();
  const [step, setStep] = useState(1); // 1: Vehicle Selection, 2: Checklist, 3: Route

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: '',
    city: '',
    state: '',
    zipCode: '',
    plannedDeparture: '',
    plannedArrival: ''
  });

  const [routeInfo, setRouteInfo] = useState<any>(null);
  const [loadingRoute, setLoadingRoute] = useState(false);

  // Set initial KM when vehicle is selected
  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ ...prev, km: selectedVehicle.currentKm, fuelLevel: selectedVehicle.fuelLevel }));
    }
  }, [selectedVehicle]);

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      city: route.city,
      state: route.state,
      zipCode: route.zipCode,
      plannedDeparture: route.plannedDeparture,
      plannedArrival: route.plannedArrival,
      startTime: new Date().toISOString()
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: new Date().toISOString()
    };

    startTrip(newTrip, finalChecklist);
    alert('Viagem iniciada com sucesso!');
    // Reset wizard
    setStep(1);
    setSelectedVehicle(null);
    setRoute({
      origin: '',
      destination: '',
      city: '',
      state: '',
      zipCode: '',
      plannedDeparture: '',
      plannedArrival: ''
    });
  };

  const fetchRouteDetails = async () => {
    if (!route.origin || !route.destination) return;
    setLoadingRoute(true);
    // Include city and state in the context for better AI grounding
    const locationContext = `${route.destination}, ${route.city} - ${route.state}`;
    const info = await getRouteInsights(route.origin, locationContext);
    setRouteInfo(info);
    setLoadingRoute(false);
