        )}

        {step === 3 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Planejamento de Rota & Horários</h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
