                    R$ {fines.reduce((sum, f) => sum + f.value, 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                  <td></td>
                </tr>
              </tfoot>
            </table>
          ) : (
            <div className="p-12 text-center text-slate-400">
              <i className="fas fa-check-double text-3xl mb-4 text-green-200"></i>
              <p className="font-medium">Nenhuma infração registrada. Excelente!</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

