              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setFinishingTripId(null)}
                  className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  onClick={confirmFinish}
                  disabled={endKm < (vehicles.find(v => v.id === activeTrips.find(t => t.id === finishingTripId)?.vehicleId)?.currentKm || 0)}
                  className="flex-1 py-3 bg-green-600 text-white rounded-xl font-bold shadow-lg shadow-green-200 hover:bg-green-700 disabled:opacity-50"
                >
                  Confirmar Chegada
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

