import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle } from '../types';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, endTrip, cancelTrip } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [endTime, setEndTime] = useState<string>(new Date().toISOString().slice(0, 16));
  const [now, setNow] = useState(new Date());

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    // Status Logic
    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      endTrip(finishingTripId, endKm, new Date(endTime).toISOString());
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso!');
    }
  };

  const handleCancel = (tripId: string) => {
