export default DriverManagement;

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

const KM_MAINTENANCE_INTERVAL = 10000;
const KM_ALERT_THRESHOLD = 500;
const DAYS_MAINTENANCE_INTERVAL = 180;
const DAYS_ALERT_THRESHOLD = 15;

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
    checkMaintenanceAlerts();
  }, [vehicles, maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords));
  }, [maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_fines', JSON.stringify(fines));
  }, [fines]);

  useEffect(() => {
    localStorage.setItem('fleet_drivers', JSON.stringify(drivers));
  }, [drivers]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_checklists', JSON.stringify(checklists));
  }, [checklists]);

  const checkMaintenanceAlerts = useCallback(() => {
    const newNotifications: AppNotification[] = [];
    const now = new Date();

    vehicles.forEach(vehicle => {
      // Find the latest maintenance record for this specific vehicle
      const vehicleMaintenances = maintenanceRecords
        .filter(r => r.vehicleId === vehicle.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const lastRecord = vehicleMaintenances[0];

      // 1. KM ALERT CALCULATION
      // If there's a last record, next maintenance is lastRecord.km + interval. 
      // Otherwise, use the standard multiples of 10k.
      let nextKmMaintenance;
      if (lastRecord) {
        // Find the vehicle's KM at the time of last maintenance from checklists if possible, 
        // but since MaintenanceRecord doesn't have it, we use the vehicle's currentKm as a proxy 
        // if we just added it, or we simply use the next 10k block.
        nextKmMaintenance = (Math.floor(vehicle.currentKm / KM_MAINTENANCE_INTERVAL) + 1) * KM_MAINTENANCE_INTERVAL;
      } else {
        nextKmMaintenance = Math.ceil((vehicle.currentKm + 1) / KM_MAINTENANCE_INTERVAL) * KM_MAINTENANCE_INTERVAL;
      }

      if (nextKmMaintenance - vehicle.currentKm <= KM_ALERT_THRESHOLD) {
        newNotifications.push({
          id: `km-${vehicle.id}-${nextKmMaintenance}`,
          type: 'maintenance_km',
          title: 'Manutenção por KM',
          message: `O veículo ${vehicle.plate} está chegando a ${nextKmMaintenance}km. Agende uma revisão.`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }

      // 2. DATE ALERT CALCULATION
      if (lastRecord) {
        const lastDate = new Date(lastRecord.date);
        const nextDate = new Date(lastDate);
        nextDate.setDate(lastDate.getDate() + DAYS_MAINTENANCE_INTERVAL);
        const diffTime = nextDate.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (diffDays <= DAYS_ALERT_THRESHOLD && diffDays > -30) { // Alerta se estiver perto ou até 30 dias atrasado
          newNotifications.push({
            id: `date-${vehicle.id}-${nextDate.toISOString()}`,
            type: 'maintenance_date',
            title: 'Manutenção por Prazo',
            message: `O veículo ${vehicle.plate} completará 6 meses desde a última revisão em ${diffDays <= 0 ? 'breve' : diffDays + ' dias'}.`,
            vehicleId: vehicle.id,
            timestamp: now.toISOString(),
            isRead: false
          });
        }
      }

      // 3. FUEL ALERT
      if (vehicle.fuelLevel < 15) {
        newNotifications.push({
          id: `fuel-${vehicle.id}`,
          type: 'low_fuel',
          title: 'Combustível Baixo',
          message: `O veículo ${vehicle.plate} está com nível crítico de combustível (${vehicle.fuelLevel}%).`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }
    });

    setNotifications(prev => {
      const existingIds = new Set(newNotifications.map(n => n.id));

      // Keep:
      // - Notifications that are NOT of type maintenance
      // - Notifications of type maintenance that are still in our 'newNotifications' list
      // - Notifications that are already READ (history)
      const keptNotifications = prev.filter(n => {
        const isMaintenanceType = n.type === 'maintenance_km' || n.type === 'maintenance_date';
        if (n.isRead) return true;
        if (!isMaintenanceType) return true;

        // For unread maintenance alerts, only keep if they are still relevant (present in newNotifications)
        return existingIds.has(n.id);
      });

      // Add truly new ones
      const alreadyInListIds = new Set(keptNotifications.map(n => n.id));
      const toAdd = newNotifications.filter(n => !alreadyInListIds.has(n.id));

      return [...toAdd, ...keptNotifications].slice(0, 50);
    });
  }, [vehicles, maintenanceRecords]);

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => {
    setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
    if (currentUser?.id === id) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const deleteDriver = (id: string) => {
    setDrivers(prev => prev.filter(d => d.id !== id));
    if (currentUser?.id === id) logout();
  };

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const finishedTrip = { ...trip, endTime, distance: currentKm - (trip.distance || 0) }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
    // The useEffect watching maintenanceRecords will trigger checkMaintenanceAlerts automatically
  };

  const addFine = (fine: Fine) => {
    setFines(prev => [fine, ...prev]);
    setNotifications(prev => [{
      id: fine.id,
      type: 'new_fine',
      title: 'Nova Multa Registrada',
      message: `Uma nova multa foi registrada para o motorista selecionado no veículo ${vehicles.find(v => v.id === fine.vehicleId)?.plate}.`,
      vehicleId: fine.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteFine = (id: string) => {
    setFines(prev => prev.filter(f => f.id !== id));
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, checklists, maintenanceRecords, notifications, fines,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, endTrip, cancelTrip, addMaintenanceRecord, addFine, deleteFine, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

const KM_MAINTENANCE_INTERVAL = 10000;
const KM_ALERT_THRESHOLD = 500;
const DAYS_MAINTENANCE_INTERVAL = 180;
const DAYS_ALERT_THRESHOLD = 15;

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
    checkMaintenanceAlerts();
  }, [vehicles, maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords));
  }, [maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_fines', JSON.stringify(fines));
  }, [fines]);

  useEffect(() => {
    localStorage.setItem('fleet_drivers', JSON.stringify(drivers));
  }, [drivers]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_checklists', JSON.stringify(checklists));
  }, [checklists]);

  const checkMaintenanceAlerts = useCallback(() => {
    const newNotifications: AppNotification[] = [];
    const now = new Date();

    vehicles.forEach(vehicle => {
      // Pega o registro de manutenção mais recente deste veículo
      const vMaintenances = maintenanceRecords
        .filter(r => r.vehicleId === vehicle.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const lastRecord = vMaintenances[0];

      // 1. CÁLCULO DE ALERTA POR KM
      // Define o próximo alvo de manutenção baseado no intervalo de 10k
      let nextKmMaintenance;
      if (lastRecord) {
        // Usa o próximo bloco de 10k após a última manutenção conhecida ou KM atual
        nextKmMaintenance = (Math.floor(vehicle.currentKm / KM_MAINTENANCE_INTERVAL) + 1) * KM_MAINTENANCE_INTERVAL;
      } else {
        nextKmMaintenance = Math.ceil((vehicle.currentKm + 1) / KM_MAINTENANCE_INTERVAL) * KM_MAINTENANCE_INTERVAL;
      }

      if (nextKmMaintenance - vehicle.currentKm <= KM_ALERT_THRESHOLD) {
        newNotifications.push({
          id: `km-${vehicle.id}-${nextKmMaintenance}`,
          type: 'maintenance_km',
          title: 'Manutenção por KM',
          message: `O veículo ${vehicle.plate} está chegando a ${nextKmMaintenance}km. Agende uma revisão.`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }

      // 2. CÁLCULO DE ALERTA POR DATA (6 meses)
      if (lastRecord) {
        const lastDate = new Date(lastRecord.date);
        const nextDate = new Date(lastDate);
        nextDate.setDate(lastDate.getDate() + DAYS_MAINTENANCE_INTERVAL);
        const diffTime = nextDate.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (diffDays <= DAYS_ALERT_THRESHOLD) {
          newNotifications.push({
            id: `date-${vehicle.id}-${nextDate.toISOString()}`,
            type: 'maintenance_date',
            title: 'Manutenção por Prazo',
            message: `O veículo ${vehicle.plate} completará 6 meses desde a última revisão em ${diffDays <= 0 ? 'breve' : diffDays + ' dias'}.`,
            vehicleId: vehicle.id,
            timestamp: now.toISOString(),
            isRead: false
          });
        }
      }

      // 3. COMBUSTÍVEL
      if (vehicle.fuelLevel < 15) {
        newNotifications.push({
          id: `fuel-${vehicle.id}`,
          type: 'low_fuel',
          title: 'Combustível Baixo',
          message: `O veículo ${vehicle.plate} está com nível crítico de combustível (${vehicle.fuelLevel}%).`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }
    });

    setNotifications(prev => {
      const activeNewIds = new Set(newNotifications.map(n => n.id));

      // Remove notificações de manutenção antigas/não lidas que não estão mais na lista de cálculos atuais
      const filteredOld = prev.filter(n => {
        const isMaintenance = n.type === 'maintenance_km' || n.type === 'maintenance_date';
        if (n.isRead) return true; // Mantém histórico lido
        if (!isMaintenance) return true; // Mantém outros tipos (multas, etc)
        return activeNewIds.has(n.id); // Remove se não for mais um alerta ativo calculado agora
      });

      const currentIds = new Set(filteredOld.map(n => n.id));
      const trulyNew = newNotifications.filter(n => !currentIds.has(n.id));

      return [...trulyNew, ...filteredOld].slice(0, 50);
    });
  }, [vehicles, maintenanceRecords]);

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => {
    setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
    if (currentUser?.id === id) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const deleteDriver = (id: string) => {
    setDrivers(prev => prev.filter(d => d.id !== id));
    if (currentUser?.id === id) logout();
  };

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const finishedTrip = { ...trip, endTime, distance: currentKm - (trip.distance || 0) }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
    // O useEffect observando maintenanceRecords disparará checkMaintenanceAlerts
  };

  const addFine = (fine: Fine) => {
    setFines(prev => [fine, ...prev]);
    setNotifications(prev => [{
      id: fine.id,
      type: 'new_fine',
      title: 'Nova Multa Registrada',
      message: `Uma nova multa foi registrada para o condutor no veículo ${vehicles.find(v => v.id === fine.vehicleId)?.plate}.`,
      vehicleId: fine.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteFine = (id: string) => {
    setFines(prev => prev.filter(f => f.id !== id));
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, checklists, maintenanceRecords, notifications, fines,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, endTrip, cancelTrip, addMaintenanceRecord, addFine, deleteFine, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle } from '../types';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, endTrip, cancelTrip } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [endTime, setEndTime] = useState<string>(new Date().toISOString().slice(0, 16));
  const [now, setNow] = useState(new Date());

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    // Status Logic
    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      endTrip(finishingTripId, endKm, new Date(endTime).toISOString());
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso!');
    }
  };

  const handleCancel = (tripId: string) => {
    if (confirm('ATENÇÃO: Deseja realmente cancelar esta operação? O veículo e o motorista serão liberados imediatamente e o status voltará para "Disponível".')) {
      cancelTrip(tripId);
      alert('Operação cancelada. Veículo liberado.');
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase shadow-sm">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all transform hover:-translate-y-1">
                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs shadow-inner">
                      {vehicle?.plate}
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                      <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Saída</p>
                    <p className="text-xs font-medium">{new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  {/* Status Indicator Bar */}
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                    {trip.plannedArrival && (
                      <span className="text-[10px] text-slate-400 font-medium">
                        ETA: {new Date(trip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white shadow-sm overflow-hidden ring-1 ring-slate-100">
                      {driver?.avatar ? (
                        <img src={driver.avatar} alt="" className="w-full h-full object-cover" />
