                        </div>
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Destino</p>
                          <p className="text-sm text-slate-800 font-bold truncate">{trip.destination}, {trip.city}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="pt-4 flex gap-2">
                    <button 
                      onClick={() => handleFinish(trip)}
                      className="flex-1 bg-emerald-600 text-white py-2.5 rounded-xl font-bold text-xs hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100 active:scale-95"
                    >
                      <i className="fas fa-check-circle mr-2"></i> Encerrar
                    </button>
                    <button 
                      onClick={() => handleCancel(trip.id)}
                      className="px-4 py-2.5 border border-slate-200 text-slate-400 hover:text-red-600 hover:bg-red-50 hover:border-red-100 rounded-xl transition-all group"
                      title="Cancelar Viagem"
                    >
                      <i className="fas fa-ban group-hover:scale-110 transition-transform"></i>
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border border-dashed border-slate-200 shadow-sm">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
              <i className="fas fa-map-location-dot text-4xl"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Céu Limpo</h3>
            <p className="text-slate-400 text-sm mt-2 max-w-xs mx-auto">Nenhuma viagem em andamento no momento. Novas viagens aparecerão aqui assim que forem iniciadas.</p>
          </div>
        )}
      </div>

      {/* Finishing Modal Overlay */}
      {finishingTripId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-900 text-white">
              <h3 className="text-lg font-bold">Encerrar Viagem</h3>
              <p className="text-slate-400 text-xs mt-1">Informe os dados finais para concluir o trajeto.</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">KM de Chegada</label>
                <div className="relative">
                  <i className="fas fa-gauge absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="number"
                    value={endKm}
                    onChange={(e) => setEndKm(parseInt(e.target.value))}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800"
                  />
                </div>
                <p className="text-[10px] text-slate-400 mt-1 italic font-medium">Mínimo sugerido: {vehicles.find(v => v.id === activeTrips.find(t => t.id === finishingTripId)?.vehicleId)?.currentKm} km</p>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Data/Hora de Chegada</label>
                <div className="relative">
                  <i className="fas fa-calendar-check absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="datetime-local"
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-medium text-slate-800"
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setFinishingTripId(null)}
                  className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors border border-transparent hover:border-slate-100"
                >
                  Cancelar
                </button>
                <button 
                  onClick={confirmFinish}
                  disabled={endKm < (vehicles.find(v => v.id === activeTrips.find(t => t.id === finishingTripId)?.vehicleId)?.currentKm || 0)}
                  className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-200 hover:bg-emerald-700 disabled:opacity-50 transition-all"
                >
                  Confirmar Chegada
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripMonitoring;

import React, { useState, useRef } from 'react';
import { useFleet } from '../context/FleetContext';
import { Fine, Driver } from '../types';

const DriverManagement: React.FC = () => {
  const { drivers, vehicles, fines, addFine, addDriver, updateDriver, deleteDriver, deleteFine } = useFleet();
  const [showFineForm, setShowFineForm] = useState(false);
  const [showDriverForm, setShowDriverForm] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editAvatarInputRef = useRef<HTMLInputElement>(null);
  const [editingDriverId, setEditingDriverId] = useState<string | null>(null);

  // Deletion Confirmation State
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'driver' | 'fine', label: string } | null>(null);

  const [newFine, setNewFine] = useState({
    driverId: '',
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    value: '',
    points: '',
    description: ''
  });

  const [newDriver, setNewDriver] = useState({
    name: '',
    license: '',
    username: '',
    password: '',
    avatar: ''
  });

  const handleFineSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newFine.driverId || !newFine.vehicleId || !newFine.value) return;

    const fine: Fine = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: newFine.driverId,
      vehicleId: newFine.vehicleId,
      date: newFine.date,
      value: parseFloat(newFine.value),
      points: parseInt(newFine.points) || 0,
      description: newFine.description
    };

    addFine(fine);
    setNewFine({
      driverId: '',
      vehicleId: '',
      date: new Date().toISOString().split('T')[0],
      value: '',
      points: '',
      description: ''
    });
    setShowFineForm(false);
    alert('Multa registrada com sucesso!');
  };

  const handleDriverSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDriver.name || !newDriver.license || !newDriver.username) return;

    const driver: Driver = {
      id: Math.random().toString(36).substr(2, 9),
      name: newDriver.name,
      license: newDriver.license,
      username: newDriver.username,
      password: newDriver.password || '123',
      avatar: newDriver.avatar
    };

    addDriver(driver);
    setNewDriver({
      name: '',
      license: '',
      username: '',
      password: '',
      avatar: ''
    });
    setShowDriverForm(false);
    alert('Motorista cadastrado com sucesso!');
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewDriver(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdateAvatar = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingDriverId) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateDriver(editingDriverId, { avatar: reader.result as string });
        setEditingDriverId(null);
        alert('Foto de perfil atualizada!');
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpdateAvatar = (driverId: string) => {
    setEditingDriverId(driverId);
    editAvatarInputRef.current?.click();
  };

  const executeDelete = () => {
    if (!confirmDelete) return;

    if (confirmDelete.type === 'driver') {
      deleteDriver(confirmDelete.id);
    } else {
      deleteFine(confirmDelete.id);
    }

    setConfirmDelete(null);
  };

  const scrollToDriver = (driverId: string) => {
    const element = document.getElementById(`driver-card-${driverId}`);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      element.classList.add('ring-4', 'ring-blue-400', 'ring-opacity-50');
      setTimeout(() => {
        element.classList.remove('ring-4', 'ring-blue-400', 'ring-opacity-50');
      }, 2000);
    }
  };

  return (
    <div className="space-y-8 relative">
      {/* Hidden input for editing existing driver avatar */}
      <input 
        type="file" 
        ref={editAvatarInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={handleUpdateAvatar} 
      />

      {/* Confirmation Dialog */}
      {confirmDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 text-center">
              <div className="w-16 h-16 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <i className="fas fa-exclamation-triangle text-2xl"></i>
              </div>
              <h3 className="text-xl font-bold text-slate-800">Confirmar Exclusão</h3>
              <p className="text-slate-500 mt-2 text-sm">
                Você está prestes a excluir <strong>{confirmDelete.label}</strong>. 
                Esta ação não poderá ser desfeita.
              </p>
            </div>
            <div className="bg-slate-50 p-4 flex gap-3">
              <button 
                onClick={() => setConfirmDelete(null)}
                className="flex-1 py-2.5 bg-white border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={executeDelete}
                className="flex-1 py-2.5 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 shadow-lg shadow-red-200 transition-all"
              >
                Excluir
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Motoristas & Infrações</h2>
        <div className="flex gap-2">
          <button 
            onClick={() => {
              setShowFineForm(!showFineForm);
              setShowDriverForm(false);
            }}
            className="bg-red-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-red-700 flex items-center gap-2 shadow-lg shadow-red-200 transition-all"
          >
            <i className={`fas ${showFineForm ? 'fa-times' : 'fa-file-invoice-dollar'}`}></i>
            {showFineForm ? 'Cancelar' : 'Registrar Multa'}
          </button>
          <button 
            onClick={() => {
              setShowDriverForm(!showDriverForm);
              setShowFineForm(false);
            }}
            className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200 transition-all"
          >
            <i className={`fas ${showDriverForm ? 'fa-times' : 'fa-user-plus'}`}></i>
            {showDriverForm ? 'Cancelar' : 'Novo Motorista'}
          </button>
        </div>
      </div>

      {/* Register Driver Form */}
      {showDriverForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border-l-4 border-blue-600 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <i className="fas fa-id-card text-blue-400"></i>
            Cadastro de Novo Motorista
          </h3>
          <form onSubmit={handleDriverSubmit} className="space-y-6">
            <div className="flex flex-col md:flex-row gap-6">
              <div className="flex flex-col items-center gap-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-32 h-32 rounded-full bg-slate-100 border-2 border-dashed border-slate-300 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all overflow-hidden group"
                >
                  {newDriver.avatar ? (
                    <img src={newDriver.avatar} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <>
                      <i className="fas fa-camera text-slate-400 text-2xl group-hover:text-blue-500"></i>
                      <span className="text-[10px] font-bold text-slate-400 mt-2 uppercase">Upload Foto</span>
                    </>
                  )}
                </div>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*" 
                  onChange={handleImageUpload} 
                />
              </div>

              <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nome Completo</label>
                  <input
                    required
                    type="text"
                    placeholder="Nome do motorista"
                    value={newDriver.name}
                    onChange={(e) => setNewDriver({ ...newDriver, name: e.target.value })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm font-medium"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Número da CNH</label>
                  <input
                    required
                    type="text"
                    placeholder="00000000000"
                    value={newDriver.license}
                    onChange={(e) => setNewDriver({ ...newDriver, license: e.target.value })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm font-medium"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Username</label>
                  <input
                    required
                    type="text"
                    placeholder="usuario.acesso"
                    value={newDriver.username}
                    onChange={(e) => setNewDriver({ ...newDriver, username: e.target.value.toLowerCase().replace(/\s/g, '') })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm font-medium"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Senha Inicial</label>
                  <input
                    type="password"
                    placeholder="••••••••"
                    value={newDriver.password}
                    onChange={(e) => setNewDriver({ ...newDriver, password: e.target.value })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm font-medium"
                  />
                </div>
              </div>
            </div>
            <div className="flex justify-end">
              <button 
                type="submit"
                className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
              >
                Cadastrar Motorista
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Register Fine Form */}
      {showFineForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border-l-4 border-red-600 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <i className="fas fa-gavel text-red-400"></i>
            Registrar Auto de Infração
          </h3>
          <form onSubmit={handleFineSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Motorista</label>
              <select
                required
                value={newFine.driverId}
                onChange={(e) => setNewFine({ ...newFine, driverId: e.target.value })}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium"
              >
                <option value="">Selecione o condutor...</option>
                {drivers.map(d => (
                  <option key={d.id} value={d.id}>{d.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Veículo</label>
              <select
                required
                value={newFine.vehicleId}
                onChange={(e) => setNewFine({ ...newFine, vehicleId: e.target.value })}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium"
              >
                <option value="">Selecione o veículo...</option>
                {vehicles.map(v => (
                  <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Data da Infração</label>
              <input
                required
                type="date"
                value={newFine.date}
                onChange={(e) => setNewFine({ ...newFine, date: e.target.value })}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium"
              />
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Valor (R$)</label>
                <input
                  required
                  type="number"
                  step="0.01"
                  placeholder="0,00"
                  value={newFine.value}
                  onChange={(e) => setNewFine({ ...newFine, value: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Pontos</label>
                <input
                  type="number"
                  placeholder="0"
                  value={newFine.points}
                  onChange={(e) => setNewFine({ ...newFine, points: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium"
                />
              </div>
            </div>
            <div className="md:col-span-3">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Descrição da Infração</label>
              <textarea
                placeholder="Ex: Excesso de velocidade (Art. 218 CTB)..."
                value={newFine.description}
                onChange={(e) => setNewFine({ ...newFine, description: e.target.value })}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:outline-none text-sm font-medium h-20 resize-none"
              />
            </div>
            <div className="flex items-end">
              <button 
                type="submit"
                className="w-full bg-red-600 text-white py-3 rounded-lg font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-100"
              >
                Salvar Infração
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Driver List Cards */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2">Motoristas Ativos</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {drivers.map(driver => {
            const driverFines = fines.filter(f => f.driverId === driver.id);
            const totalFinesValue = driverFines.reduce((sum, f) => sum + f.value, 0);
            const totalPoints = driverFines.reduce((sum, f) => sum + f.points, 0);

            return (
              <div id={`driver-card-${driver.id}`} key={driver.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 relative overflow-hidden group transition-all duration-500">
                {driver.activeVehicleId && (
                  <div className="absolute top-0 right-0 bg-blue-600 text-white px-3 py-1 rounded-bl-lg text-[10px] font-bold uppercase">
                    Em Viagem
                  </div>
                )}
                <div className="flex items-center gap-4 mb-6">
                  <div className="relative group/avatar">
                    <div className="w-16 h-16 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center text-xl font-bold border-2 border-white shadow-sm ring-1 ring-blue-100 overflow-hidden">
                      {driver.avatar ? (
                        <img src={driver.avatar} alt={driver.name} className="w-full h-full object-cover" />
                      ) : (
                        driver.name.charAt(0)
                      )}
                    </div>
                    {/* Floating Upload Button */}
                    <button 
                      onClick={() => triggerUpdateAvatar(driver.id)}
                      className="absolute -bottom-1 -right-1 w-7 h-7 bg-white text-slate-600 rounded-full shadow-md border border-slate-100 flex items-center justify-center hover:bg-blue-600 hover:text-white transition-all transform scale-0 group-hover/avatar:scale-100"
                      title="Alterar Foto"
                    >
                      <i className="fas fa-camera text-[10px]"></i>
                    </button>
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-800 text-lg">{driver.name}</h3>
                    <p className="text-sm text-slate-500">CNH: {driver.license}</p>
                  </div>
                </div>

                <div className="space-y-3">
                  <div className="flex justify-between text-sm py-2 border-b border-slate-50">
                    <span className="text-slate-500 font-medium">Pontuação Acumulada:</span>
                    <span className={`font-bold ${totalPoints >= 20 ? 'text-red-600' : 'text-slate-800'}`}>
                      {totalPoints} pts
                    </span>
                  </div>
                  <div className="flex justify-between text-sm py-2 border-b border-slate-50">
                    <span className="text-slate-500 font-medium">Total em Multas:</span>
                    <span className="text-red-600 font-bold">
                      R$ {totalFinesValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm py-2 border-b border-slate-50">
                    <span className="text-slate-500 font-medium">Veículo Atual:</span>
                    <span className={`font-bold ${driver.activeVehicleId ? 'text-blue-600' : 'text-slate-400'}`}>
                      {driver.activeVehicleId 
                        ? vehicles.find(v => v.id === driver.activeVehicleId)?.plate 
                        : 'Nenhum'}
                    </span>
                  </div>
                </div>

                <div className="mt-6 flex gap-2">
                  <button className="flex-1 bg-slate-50 text-slate-600 py-2 rounded-lg font-bold text-sm hover:bg-slate-100 transition-colors">
                    Histórico
                  </button>
                  <button 
                    onClick={() => setConfirmDelete({ id: driver.id, type: 'driver', label: driver.name })}
                    className="p-2 text-slate-400 hover:text-red-600 transition-colors" 
                    title="Excluir Motorista"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                  <button className="p-2 text-slate-400 hover:text-blue-600" title="Configurações"><i className="fas fa-cog"></i></button>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Fines History Table */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2 flex items-center gap-2">
          <i className="fas fa-history"></i>
          Histórico de Infrações Registradas
        </h3>
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          {fines.length > 0 ? (
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
