                        {fine.description || '-'}
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => setConfirmDelete({ id: fine.id, type: 'fine', label: `a multa de R$ ${fine.value.toFixed(2)}` })}
                          className="p-1.5 text-slate-300 hover:text-red-600 transition-colors opacity-0 group-hover:opacity-100" 
                          title="Remover Multa"
                        >
                          <i className="fas fa-trash-alt text-xs"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot className="bg-slate-50/50">
                <tr>
                  <td colSpan={4} className="px-6 py-4 text-right text-xs font-bold text-slate-500 uppercase">Total Acumulado em Infrações</td>
                  <td className="px-6 py-4 text-right font-bold text-red-700">
                    R$ {fines.reduce((sum, f) => sum + f.value, 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                  <td></td>
                  <td></td>
                </tr>
              </tfoot>
            </table>
          ) : (
            <div className="p-12 text-center text-slate-400">
              <i className="fas fa-check-double text-3xl mb-4 text-green-200"></i>
              <p className="font-medium">Nenhuma infração registrada. Excelente!</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

