import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

const KM_MAINTENANCE_INTERVAL = 10000;
const KM_ALERT_THRESHOLD = 500;
const DAYS_MAINTENANCE_INTERVAL = 180;
const DAYS_ALERT_THRESHOLD = 15;

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [occurrences, setOccurrences] = useState<Occurrence[]>(() => {
    const saved = localStorage.getItem('fleet_occurrences');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
    checkMaintenanceAlerts();
  }, [vehicles, maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords));
  }, [maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_fines', JSON.stringify(fines));
  }, [fines]);

  useEffect(() => {
    localStorage.setItem('fleet_drivers', JSON.stringify(drivers));
  }, [drivers]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_checklists', JSON.stringify(checklists));
  }, [checklists]);

  useEffect(() => {
    localStorage.setItem('fleet_occurrences', JSON.stringify(occurrences));
  }, [occurrences]);

  const checkMaintenanceAlerts = useCallback(() => {
    const newNotifications: AppNotification[] = [];
    const now = new Date();

    vehicles.forEach(vehicle => {
      const vMaintenances = maintenanceRecords
        .filter(r => r.vehicleId === vehicle.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const lastRecord = vMaintenances[0];

      let nextKmMaintenance;
      if (lastRecord) {
        nextKmMaintenance = (Math.floor(vehicle.currentKm / KM_MAINTENANCE_INTERVAL) + 1) * KM_MAINTENANCE_INTERVAL;
      } else {
        nextKmMaintenance = Math.ceil((vehicle.currentKm + 1) / KM_MAINTENANCE_INTERVAL) * KM_MAINTENANCE_INTERVAL;
      }

      if (nextKmMaintenance - vehicle.currentKm <= KM_ALERT_THRESHOLD) {
        newNotifications.push({
          id: `km-${vehicle.id}-${nextKmMaintenance}`,
          type: 'maintenance_km',
          title: 'Manutenção por KM',
          message: `O veículo ${vehicle.plate} está chegando a ${nextKmMaintenance}km. Agende uma revisão.`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }

      if (lastRecord) {
        const lastDate = new Date(lastRecord.date);
        const nextDate = new Date(lastDate);
        nextDate.setDate(lastDate.getDate() + DAYS_MAINTENANCE_INTERVAL);
        const diffTime = nextDate.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (diffDays <= DAYS_ALERT_THRESHOLD) {
          newNotifications.push({
            id: `date-${vehicle.id}-${nextDate.toISOString()}`,
            type: 'maintenance_date',
            title: 'Manutenção por Prazo',
            message: `O veículo ${vehicle.plate} completará 6 meses desde a última revisão em ${diffDays <= 0 ? 'breve' : diffDays + ' dias'}.`,
            vehicleId: vehicle.id,
            timestamp: now.toISOString(),
            isRead: false
          });
        }
      }

      if (vehicle.fuelLevel < 15) {
        newNotifications.push({
          id: `fuel-${vehicle.id}`,
          type: 'low_fuel',
          title: 'Combustível Baixo',
          message: `O veículo ${vehicle.plate} está com nível crítico de combustível (${vehicle.fuelLevel}%).`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }
    });

    setNotifications(prev => {
      const activeNewIds = new Set(newNotifications.map(n => n.id));
      const filteredOld = prev.filter(n => {
        const isMaintenance = n.type === 'maintenance_km' || n.type === 'maintenance_date';
        if (n.isRead) return true;
        if (!isMaintenance) return true;
        return activeNewIds.has(n.id);
      });
      const currentIds = new Set(filteredOld.map(n => n.id));
      const trulyNew = newNotifications.filter(n => !currentIds.has(n.id));
      return [...trulyNew, ...filteredOld].slice(0, 50);
    });
  }, [vehicles, maintenanceRecords]);

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => {
    setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
    if (currentUser?.id === id) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const deleteDriver = (id: string) => {
    setDrivers(prev => prev.filter(d => d.id !== id));
    if (currentUser?.id === id) logout();
  };

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const finishedTrip = { ...trip, endTime, distance: currentKm - (trip.distance || 0) }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
  };

  const addFine = (fine: Fine) => {
    setFines(prev => [fine, ...prev]);
    setNotifications(prev => [{
      id: fine.id,
      type: 'new_fine',
      title: 'Nova Multa Registrada',
      message: `Uma nova multa foi registrada para o condutor no veículo ${vehicles.find(v => v.id === fine.vehicleId)?.plate}.`,
      vehicleId: fine.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteFine = (id: string) => {
    setFines(prev => prev.filter(f => f.id !== id));
  };

  const addOccurrence = (occ: Occurrence) => {
    setOccurrences(prev => [occ, ...prev]);
    setNotifications(prev => [{
      id: occ.id,
      type: 'occurrence',
      title: `Ocorrência: ${occ.type}`,
      message: `Nova ocorrência relatada pelo condutor ${drivers.find(d => d.id === occ.driverId)?.name} no veículo ${vehicles.find(v => v.id === occ.vehicleId)?.plate}.`,
      vehicleId: occ.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, checklists, maintenanceRecords, notifications, fines, occurrences,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, endTrip, cancelTrip, addMaintenanceRecord, addFine, deleteFine, addOccurrence, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle, Occurrence, OccurrenceSeverity } from '../types';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, occurrences, endTrip, cancelTrip, addOccurrence } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [endTime, setEndTime] = useState<string>(new Date().toISOString().slice(0, 16));
  const [now, setNow] = useState(new Date());

  // Occurrence Modal State
  const [reportingTrip, setReportingTrip] = useState<Trip | null>(null);
  const [newOccurrence, setNewOccurrence] = useState({
    type: '',
    description: '',
    severity: OccurrenceSeverity.LOW
  });

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      endTrip(finishingTripId, endKm, new Date(endTime).toISOString());
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso!');
    }
  };

  const handleCancel = (tripId: string) => {
    if (confirm('ATENÇÃO: Deseja realmente cancelar esta operação? O veículo e o motorista serão liberados imediatamente e o status voltará para "Disponível".')) {
      cancelTrip(tripId);
      alert('Operação cancelada. Veículo liberado.');
    }
  };

  const handleReportOccurrence = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reportingTrip || !newOccurrence.type || !newOccurrence.description) return;

    const occ: Occurrence = {
      id: Math.random().toString(36).substr(2, 9),
      tripId: reportingTrip.id,
      vehicleId: reportingTrip.vehicleId,
      driverId: reportingTrip.driverId,
      type: newOccurrence.type,
      description: newOccurrence.description,
      severity: newOccurrence.severity,
      timestamp: new Date().toISOString(),
      resolved: false
    };

    addOccurrence(occ);
    setReportingTrip(null);
    setNewOccurrence({ type: '', description: '', severity: OccurrenceSeverity.LOW });
    alert('Ocorrência registrada com sucesso. A central de controle foi notificada.');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase shadow-sm">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);
            const tripOccurrences = occurrences.filter(o => o.tripId === trip.id);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all transform hover:-translate-y-1 relative">
                {tripOccurrences.length > 0 && (
                  <div className="absolute top-2 left-2 z-10 flex gap-1">
                    <span className="bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-full animate-bounce shadow-lg">
                      {tripOccurrences.length} Ocorrência(s)
                    </span>
                  </div>
                )}

                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs shadow-inner">
                      {vehicle?.plate}
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                      <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Saída</p>
                    <p className="text-xs font-medium">{new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                    {trip.plannedArrival && (
                      <span className="text-[10px] text-slate-400 font-medium">
                        ETA: {new Date(trip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white shadow-sm overflow-hidden ring-1 ring-slate-100">
                      {driver?.avatar ? (
                        <img src={driver.avatar} alt="" className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">
                          {driver?.name.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                      <p className="text-[10px] text-slate-500 uppercase font-medium">CNH: {driver?.license}</p>
                    </div>
                    <button 
                      onClick={() => setReportingTrip(trip)}
                      className="w-8 h-8 rounded-full bg-orange-50 text-orange-600 flex items-center justify-center hover:bg-orange-100 transition-colors"
                      title="Relatar Ocorrência"
                    >
                      <i className="fas fa-triangle-exclamation"></i>
                    </button>
                  </div>

                  <div className="space-y-3">
                    <div className="flex gap-3">
                      <div className="flex flex-col items-center">
                        <i className="fas fa-circle-dot text-blue-500 text-[10px] mt-1"></i>
                        <div className="w-px h-full bg-slate-200 my-1"></div>
                        <i className="fas fa-location-dot text-red-500 text-[10px]"></i>
                      </div>
                      <div className="flex-1 space-y-3">
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Origem</p>
                          <p className="text-sm text-slate-700 font-medium truncate">{trip.origin}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Destino</p>
                          <p className="text-sm text-slate-800 font-bold truncate">{trip.destination}, {trip.city}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="pt-4 flex gap-2">
                    <button 
                      onClick={() => handleFinish(trip)}
                      className="flex-1 bg-emerald-600 text-white py-2.5 rounded-xl font-bold text-xs hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100 active:scale-95"
                    >
                      <i className="fas fa-check-circle mr-2"></i> Encerrar
                    </button>
                    <button 
                      onClick={() => handleCancel(trip.id)}
                      className="px-4 py-2.5 border border-slate-200 text-slate-400 hover:text-red-600 hover:bg-red-50 hover:border-red-100 rounded-xl transition-all group"
                      title="Cancelar Viagem"
                    >
                      <i className="fas fa-ban group-hover:scale-110 transition-transform"></i>
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border border-dashed border-slate-200 shadow-sm">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
              <i className="fas fa-map-location-dot text-4xl"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Céu Limpo</h3>
            <p className="text-slate-400 text-sm mt-2 max-w-xs mx-auto">Nenhuma viagem em andamento no momento.</p>
          </div>
        )}
      </div>

      {/* Finishing Modal */}
      {finishingTripId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-900 text-white">
              <h3 className="text-lg font-bold">Encerrar Viagem</h3>
              <p className="text-slate-400 text-xs mt-1">Informe os dados finais para concluir o trajeto.</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">KM de Chegada</label>
                <div className="relative">
                  <i className="fas fa-gauge absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="number"
                    value={endKm}
                    onChange={(e) => setEndKm(parseInt(e.target.value))}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800"
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Data/Hora de Chegada</label>
                <div className="relative">
                  <i className="fas fa-calendar-check absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="datetime-local"
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-medium text-slate-800"
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setFinishingTripId(null)} className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors">Cancelar</button>
                <button onClick={confirmFinish} className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-200 hover:bg-emerald-700 transition-all">Confirmar Chegada</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Occurrence Modal */}
      {reportingTrip && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-orange-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-lg font-bold">Relatar Ocorrência</h3>
                <p className="text-orange-100 text-xs mt-1">Veículo: {vehicles.find(v => v.id === reportingTrip.vehicleId)?.plate}</p>
              </div>
              <i className="fas fa-triangle-exclamation text-2xl opacity-50"></i>
            </div>

            <form onSubmit={handleReportOccurrence} className="p-6 space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Tipo de Incidente</label>
                  <select 
                    required
                    value={newOccurrence.type}
                    onChange={(e) => setNewOccurrence({ ...newOccurrence, type: e.target.value })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none font-medium text-slate-800"
                  >
                    <option value="">Selecione...</option>
                    <option value="Acidente / Colisão">Acidente / Colisão</option>
                    <option value="Falha Mecânica">Falha Mecânica</option>
                    <option value="Pneu Furado">Pneu Furado</option>
                    <option value="Atraso por Trânsito">Atraso por Trânsito</option>
                    <option value="Problema com Carga">Problema com Carga</option>
                    <option value="Bloqueio de Via">Bloqueio de Via</option>
                    <option value="Outros">Outros</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Severidade</label>
                  <div className="flex gap-2">
                    {[
                      { val: OccurrenceSeverity.LOW, label: 'Baixa', color: 'bg-blue-100 text-blue-600 border-blue-200' },
                      { val: OccurrenceSeverity.MEDIUM, label: 'Média', color: 'bg-orange-100 text-orange-600 border-orange-200' },
                      { val: OccurrenceSeverity.HIGH, label: 'Alta', color: 'bg-red-100 text-red-600 border-red-200' }
                    ].map(s => (
                      <button
                        key={s.val}
                        type="button"
                        onClick={() => setNewOccurrence({ ...newOccurrence, severity: s.val })}
                        className={`flex-1 py-2 text-[10px] font-bold rounded-lg border transition-all ${
                          newOccurrence.severity === s.val ? 'ring-2 ring-slate-800 ring-offset-1 ' + s.color : 'bg-white text-slate-400 border-slate-100'
                        }`}
                      >
                        {s.label}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Descrição dos Fatos</label>
                <textarea
                  required
                  placeholder="Descreva o que aconteceu em detalhes para a equipe de controle..."
                  value={newOccurrence.description}
                  onChange={(e) => setNewOccurrence({ ...newOccurrence, description: e.target.value })}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none text-sm min-h-[120px] resize-none"
                />
              </div>

              <div className="flex gap-3 pt-2">
                <button 
                  type="button" 
                  onClick={() => setReportingTrip(null)}
                  className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 bg-orange-600 text-white rounded-xl font-bold shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all"
                >
                  Enviar Relato
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripMonitoring;

import React, { useState, useEffect, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { getFleetStatsAnalysis } from '../services/geminiService';
import { VehicleStatus, OccurrenceSeverity } from '../types';

const DashboardOverview: React.FC = () => {
  const { vehicles, drivers, activeTrips, notifications, checklists, occurrences } = useFleet();
  const [aiInsights, setAiInsights] = useState<string>("Analisando dados da frota...");

  const usageStats = useMemo(() => {
    return vehicles.map(v => {
      const vChecklists = checklists.filter(c => c.vehicleId === v.id).sort((a, b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );

      const distanceDriven = vChecklists.length > 1 
        ? vChecklists[vChecklists.length - 1].km - vChecklists[0].km 
        : 0;

      const efficiencyFactor = v.model.includes('Sprinter') ? 12 : v.model.includes('Hilux') ? 9 : 10;
      const avgConsumption = (Math.random() * 2 + (efficiencyFactor - 1)).toFixed(1);

      return {
        id: v.id,
        plate: v.plate,
        model: v.model,
        totalKm: v.currentKm,
        drivenKm: distanceDriven,
        avgConsumption: parseFloat(avgConsumption),
        tripsCount: vChecklists.length,
        fuelScore: v.fuelLevel > 50 ? 'Bom' : 'Baixo'
      };
    });
  }, [vehicles, checklists]);

  const fleetStats = useMemo(() => {
    const total = vehicles.length || 1;
    const available = vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length;
    const inUse = vehicles.filter(v => v.status === VehicleStatus.IN_USE).length;
    const maintenance = vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length;

    return {
      available,
      inUse,
      maintenance,
      total: vehicles.length,
      pAvailable: (available / total * 100).toFixed(0),
      pInUse: (inUse / total * 100).toFixed(0),
      pMaintenance: (maintenance / total * 100).toFixed(0)
    };
  }, [vehicles]);

  const fleetAvgConsumption = useMemo(() => {
    if (usageStats.length === 0) return 0;
    return (usageStats.reduce((sum, s) => sum + s.avgConsumption, 0) / usageStats.length).toFixed(1);
  }, [usageStats]);

  useEffect(() => {
    const fetchInsights = async () => {
      const insights = await getFleetStatsAnalysis({ 
        totalVehicles: vehicles.length, 
        activeTrips: activeTrips.length,
        statusCounts: {
          available: fleetStats.available,
          maintenance: fleetStats.maintenance,
          inUse: fleetStats.inUse,
        },
        usageStats: usageStats,
        pendingAlerts: notifications.filter(n => !n.isRead).length,
        totalOccurrences: occurrences.length,
        highSeverityOccurrences: occurrences.filter(o => o.severity === OccurrenceSeverity.HIGH).length
      });
      setAiInsights(insights || "Não foi possível gerar insights agora.");
    };
    fetchInsights();
  }, [vehicles, activeTrips, notifications, usageStats, fleetStats, occurrences]);

  const statusData = [
    { name: 'Disponível', value: fleetStats.available },
    { name: 'Em Uso', value: fleetStats.inUse },
    { name: 'Manutenção', value: fleetStats.maintenance },
  ];

  const COLORS = ['#10B981', '#3B82F6', '#EF4444'];
  const kmData = vehicles.map(v => ({ name: v.plate, km: v.currentKm }));
  const activeAlerts = notifications.filter(n => !n.isRead).slice(0, 3);
  const recentOccurrences = occurrences.slice(0, 3);

  return (
    <div className="space-y-6 pb-12">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Dashboard Geral</h2>
        <div className="flex gap-2">
           <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
            Consumo Médio: {fleetAvgConsumption} km/L
          </span>
          <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-bold">
            Sistema Ativo
          </span>
        </div>
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Distribuição do Status da Frota</h3>
          <span className="text-xs font-bold text-slate-400">{vehicles.length} veículos totais</span>
        </div>

        <div className="flex h-4 w-full bg-slate-100 rounded-full overflow-hidden mb-6">
          <div style={{ width: `${fleetStats.pAvailable}%` }} className="bg-emerald-500 h-full"></div>
          <div style={{ width: `${fleetStats.pInUse}%` }} className="bg-blue-500 h-full"></div>
          <div style={{ width: `${fleetStats.pMaintenance}%` }} className="bg-red-500 h-full"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="flex items-center gap-3 p-3 rounded-xl bg-emerald-50 border border-emerald-100">
            <div className="w-8 h-8 rounded-lg bg-emerald-500 flex items-center justify-center text-white"><i className="fas fa-check"></i></div>
            <div>
              <p className="text-[10px] font-bold text-emerald-600 uppercase">Disponível</p>
              <p className="text-lg font-bold text-emerald-800">{fleetStats.available}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-blue-50 border border-blue-100">
            <div className="w-8 h-8 rounded-lg bg-blue-500 flex items-center justify-center text-white"><i className="fas fa-route"></i></div>
            <div>
              <p className="text-[10px] font-bold text-blue-600 uppercase">Em Uso</p>
              <p className="text-lg font-bold text-blue-800">{fleetStats.inUse}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-red-50 border border-red-100">
            <div className="w-8 h-8 rounded-lg bg-red-500 flex items-center justify-center text-white"><i className="fas fa-wrench"></i></div>
            <div>
              <p className="text-[10px] font-bold text-red-600 uppercase">Manutenção</p>
              <p className="text-lg font-bold text-red-800">{fleetStats.maintenance}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Veículos Totais', value: vehicles.length, icon: 'fa-truck', color: 'bg-blue-500' },
          { label: 'Ocorrências', value: occurrences.length, icon: 'fa-triangle-exclamation', color: 'bg-orange-500' },
          { label: 'Viagens Ativas', value: activeTrips.length, icon: 'fa-play', color: 'bg-green-500' },
          { label: 'Alertas Ativos', value: notifications.filter(n => !n.isRead).length, icon: 'fa-exclamation-triangle', color: 'bg-orange-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
            <div className={`${stat.color} w-12 h-12 rounded-lg flex items-center justify-center text-white shadow-lg shadow-slate-200`}>
              <i className={`fas ${stat.icon} text-xl`}></i>
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Quilometragem por Veículo</h3>
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={kmData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <YAxis axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                  <Bar dataKey="km" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-6 rounded-xl text-white shadow-xl shadow-blue-900/10">
            <div className="flex items-center gap-3 mb-4">
              <div className="bg-white/20 p-2 rounded-lg"><i className="fas fa-brain text-xl"></i></div>
              <h3 className="text-lg font-bold">Insights de Gestão IA (Gemini)</h3>
            </div>
            <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg border border-white/20">
              <p className="text-blue-50 leading-relaxed whitespace-pre-wrap italic">"{aiInsights}"</p>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-bold">Ocorrências Recentes</h3>
              <i className="fas fa-history text-slate-300"></i>
            </div>
            <div className="space-y-3">
              {recentOccurrences.length > 0 ? (
                recentOccurrences.map(occ => (
                  <div key={occ.id} className={`p-3 border-l-4 rounded-r-lg group hover:bg-slate-50 transition-all ${
                    occ.severity === OccurrenceSeverity.HIGH ? 'border-red-500 bg-red-50/30' : 
                    occ.severity === OccurrenceSeverity.MEDIUM ? 'border-orange-500 bg-orange-50/30' : 'border-blue-500 bg-blue-50/30'
                  }`}>
                    <div className="flex justify-between items-start">
                      <p className="text-xs font-bold text-slate-800">{occ.type}</p>
                      <span className="text-[8px] font-bold text-slate-400">{new Date(occ.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-1">{occ.description}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <p className="text-xs font-medium italic">Nenhuma ocorrência registrada.</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-4">Alertas Críticos</h3>
            <div className="space-y-3">
              {activeAlerts.length > 0 ? (
                activeAlerts.map(alert => (
                  <div key={alert.id} className="p-3 bg-slate-50 border-l-4 border-orange-500 rounded-r-lg">
                    <p className="text-xs font-bold text-slate-800">{alert.title}</p>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-2">{alert.message}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <i className="fas fa-check-circle text-xl mb-2 text-green-200"></i>
                  <p className="text-xs font-medium italic">Nenhum alerta ativo.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardOverview;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  serviceType: string;
  cost: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
