        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2">Viagens Planejadas</h3>
        {scheduledTrips.length > 0 ? (
          scheduledTrips.sort((a,b) => new Date(a.scheduledDate).getTime() - new Date(b.scheduledDate).getTime()).map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const restricted = vehicle && checkSPRodizio(vehicle.plate, new Date(trip.scheduledDate));

            return (
              <div key={trip.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center gap-6 hover:shadow-md transition-all">
                <div className="w-full md:w-32 flex flex-col items-center justify-center p-3 bg-slate-50 rounded-xl border border-slate-100 shrink-0">
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{new Date(trip.scheduledDate).toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
                  <span className="text-2xl font-black text-slate-800">{new Date(trip.scheduledDate).getDate()}</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{new Date(trip.scheduledDate).toLocaleDateString('pt-BR', { month: 'short' })}</span>
                </div>

                <div className="flex-1 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Motorista</p>
                    <p className="font-bold text-slate-800">{driver?.name}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                    <div className="flex items-center gap-2">
                      <p className="font-bold text-indigo-600">{vehicle?.plate}</p>
                      {restricted && (
                         <span className="bg-black text-white text-[8px] font-black px-1.5 py-0.5 rounded" title="Restrição de Rodízio em SP">RODÍZIO SP</span>
                      )}
                    </div>
                  </div>
                  <div className="lg:col-span-2">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Destino</p>
                    <p className="font-bold text-slate-800 truncate">{trip.destination}, {trip.city}</p>
                  </div>
                </div>

                <div className="flex gap-2">
                  <button 
                    onClick={() => deleteScheduledTrip(trip.id)}
                    className="w-10 h-10 rounded-full bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-100 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                  <button className="w-10 h-10 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 transition-colors">
                    <i className="fas fa-edit"></i>
                  </button>
                </div>
              </div>
            );
          })
        ) : (
          <div className="py-20 text-center bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <i className="fas fa-calendar-day text-4xl text-slate-200 mb-4"></i>
            <p className="text-slate-400 font-medium italic">Nenhuma viagem agendada no momento.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SchedulingPage;

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { getRouteInsights } from '../services/geminiService';
import { checkSPRodizio } from '../utils/trafficRules';

const OperationWizard: React.FC = () => {
  const { vehicles, currentUser, startTrip } = useFleet();
  const [step, setStep] = useState(1); // 1: Vehicle Selection, 2: Checklist, 3: Route

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: '',
    city: '',
    state: '',
    zipCode: '',
    plannedDeparture: '',
    plannedArrival: ''
  });

  const [routeInfo, setRouteInfo] = useState<any>(null);
  const [loadingRoute, setLoadingRoute] = useState(false);

  // Set initial KM when vehicle is selected
  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ 
        ...prev, 
        km: selectedVehicle.currentKm, 
        fuelLevel: selectedVehicle.fuelLevel,
        oilChecked: false,
        waterChecked: false,
        tiresChecked: false 
      }));
    }
  }, [selectedVehicle]);

  const isChecklistValid = 
    checklist.oilChecked && 
    checklist.waterChecked && 
    checklist.tiresChecked && 
    (checklist.km ?? 0) >= (selectedVehicle?.currentKm ?? 0);

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      city: route.city,
      state: route.state,
      zipCode: route.zipCode,
      plannedDeparture: route.plannedDeparture,
      plannedArrival: route.plannedArrival,
      startTime: new Date().toISOString()
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: new Date().toISOString()
    };

    startTrip(newTrip, finalChecklist);
    alert('Viagem iniciada com sucesso!');
    // Reset wizard
    setStep(1);
    setSelectedVehicle(null);
    setRoute({
      origin: '',
      destination: '',
      city: '',
      state: '',
      zipCode: '',
      plannedDeparture: '',
      plannedArrival: ''
    });
  };

  const fetchRouteDetails = async () => {
    if (!route.origin || !route.destination) return;
    setLoadingRoute(true);
    const locationContext = `${route.destination}, ${route.city} - ${route.state}`;
    const info = await getRouteInsights(route.origin, locationContext);
    setRouteInfo(info);
    setLoadingRoute(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-4">
      {/* Stepper Header */}
      <div className="flex items-center justify-between mb-8 px-4">
        {[
          { step: 1, label: 'Veículo', icon: 'fa-truck-pickup' },
          { step: 2, label: 'Checklist', icon: 'fa-clipboard-check' },
          { step: 3, label: 'Rota', icon: 'fa-map-marked-alt' }
        ].map((s) => (
          <div key={s.step} className="flex flex-col items-center flex-1">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${
              step >= s.step ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white border-slate-200 text-slate-400'
            }`}>
              <i className={`fas ${s.icon}`}></i>
            </div>
            <span className={`text-xs mt-2 font-bold uppercase tracking-wider ${step >= s.step ? 'text-blue-600' : 'text-slate-400'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        {step === 1 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Qual veículo você está pegando?</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => {
                const restrictedToday = checkSPRodizio(v.plate);
                return (
                  <button
                    key={v.id}
                    onClick={() => setSelectedVehicle(v)}
                    className={`p-6 rounded-xl border-2 text-left transition-all flex flex-col gap-4 relative ${
                      selectedVehicle?.id === v.id ? 'border-blue-600 bg-blue-50 ring-4 ring-blue-100' : 'border-slate-100 hover:border-blue-200'
                    }`}
                  >
                    {restrictedToday && (
                       <div className="absolute top-2 right-2 flex items-center gap-1 bg-amber-500 text-black font-black text-[8px] px-1.5 py-0.5 rounded shadow-sm">
                         <i className="fas fa-exclamation-triangle"></i> RODÍZIO SP HOJE
                       </div>
                    )}
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                        <i className="fas fa-truck text-xl"></i>
                      </div>
                      <div className="flex-1">
                        <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                        <p className="text-sm text-slate-500">{v.brand} {v.model}</p>
                      </div>
                    </div>
                    <div className="flex justify-between items-end border-t border-slate-100 pt-3 mt-1">
                      <p className="text-xs text-slate-400">{v.currentKm.toLocaleString()} km</p>
                      <p className="text-xs font-bold text-blue-600 uppercase">Disponível</p>
                    </div>
                  </button>
                );
              })}
            </div>
            <div className="mt-8 flex justify-end">
              <button
                disabled={!selectedVehicle}
                onClick={() => setStep(2)}
                className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="p-8">
            <div className="flex items-center justify-between mb-2">
               <h3 className="text-xl font-bold text-slate-800">Checklist de Segurança</h3>
               {!isChecklistValid && (
                 <span className="text-[10px] font-bold text-red-500 bg-red-50 px-2 py-1 rounded-full uppercase animate-pulse">
                   Validação Pendente
                 </span>
               )}
            </div>
            <p className="text-slate-500 mb-8">Veículo: <span className="font-bold text-blue-600">{selectedVehicle?.plate}</span></p>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="relative">
                  <label className="block text-sm font-bold text-slate-700 mb-2">Quilometragem Atual</label>
                  <input
                    type="number"
                    min={selectedVehicle?.currentKm}
                    value={checklist.km}
                    onChange={(e) => setChecklist({ ...checklist, km: parseInt(e.target.value) })}
                    className={`w-full p-3 rounded-xl border focus:outline-none font-medium transition-all ${
                      (checklist.km ?? 0) >= (selectedVehicle?.currentKm ?? 0) 
                        ? 'border-green-200 bg-green-50/30 focus:ring-green-500' 
                        : 'border-slate-200 focus:ring-blue-500'
                    }`}
                  />
                  <p className="text-[10px] mt-1 text-slate-400">Mínimo: {selectedVehicle?.currentKm} km</p>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Nível de Combustível (%)</label>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={checklist.fuelLevel}
                    onChange={(e) => setChecklist({ ...checklist, fuelLevel: parseInt(e.target.value) })}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 mt-4"
                  />
                  <div className="flex justify-between text-xs font-bold text-slate-400 mt-2">
                    <span>Vazio</span>
                    <span className="text-blue-600">{checklist.fuelLevel}%</span>
                    <span>Cheio</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {[
                  { key: 'oilChecked', label: 'Verificar Óleo', icon: 'fa-oil-can' },
                  { key: 'waterChecked', label: 'Verificar Água', icon: 'fa-tint' },
                  { key: 'tiresChecked', label: 'Pneus Calibrados', icon: 'fa-car' }
                ].map(item => {
                  const isChecked = checklist[item.key as keyof Checklist];
                  return (
                    <button
                      key={item.key}
                      onClick={() => setChecklist({ ...checklist, [item.key]: !isChecked })}
                      className={`p-5 rounded-xl border-2 flex flex-col items-center justify-center gap-3 transition-all relative overflow-hidden group ${
                        isChecked 
                          ? 'bg-green-50 border-green-500 text-green-700 shadow-inner' 
                          : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200 hover:bg-slate-50'
                      }`}
                    >
                      <i className={`fas ${item.icon} text-xl transition-transform ${isChecked ? 'scale-110' : 'group-hover:scale-110'}`}></i>
                      <span className="font-bold text-xs uppercase tracking-tight">{item.label}</span>

                      {isChecked ? (
                        <div className="absolute top-2 right-2 text-green-600 text-xs">
                          <i className="fas fa-check-circle"></i>
                        </div>
                      ) : (
                        <div className="absolute top-2 right-2 text-slate-200 text-xs">
                          <i className="fas fa-circle-notch"></i>
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Observações Adicionais</label>
                <textarea
                  placeholder="Arranhões, luzes acesas, etc..."
                  value={checklist.comments}
                  onChange={(e) => setChecklist({ ...checklist, comments: e.target.value })}
                  className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none h-24 resize-none text-sm"
                />
              </div>
            </div>

            <div className="mt-8 flex justify-between items-center">
              <button onClick={() => setStep(1)} className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors">
                Voltar
              </button>
              <div className="flex flex-col items-end gap-2">
                {!isChecklistValid && (
                  <p className="text-[10px] text-red-400 font-medium italic">Marque todos os itens acima para prosseguir</p>
                )}
                <button
                  disabled={!isChecklistValid}
                  onClick={() => setStep(3)}
                  className={`px-8 py-3 rounded-xl font-bold transition-all flex items-center gap-2 shadow-lg ${
                    isChecklistValid 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200' 
                      : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'
                  }`}
                >
                  Próximo Passo <i className="fas fa-arrow-right"></i>
                </button>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Planejamento de Rota & Horários</h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-5">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Ponto de Origem</label>
                  <div className="relative">
                    <i className="fas fa-circle-dot absolute left-4 top-1/2 -translate-y-1/2 text-blue-500"></i>
                    <input
                      placeholder="Ex: Garagem Central"
                      value={route.origin}
                      onChange={(e) => setRoute({ ...route, origin: e.target.value })}
                      className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                  </div>
                </div>

                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-4">
                  <div className="flex items-center gap-2 text-slate-700 font-bold text-xs uppercase mb-1">
                    <i className="fas fa-location-dot text-red-500"></i>
                    Destino do Trajeto
                  </div>

                  <div>
                    <input
                      placeholder="Endereço / Local de Destino"
                      value={route.destination}
                      onChange={(e) => setRoute({ ...route, destination: e.target.value })}
                      className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <input
                      placeholder="Cidade"
                      value={route.city}
                      onChange={(e) => setRoute({ ...route, city: e.target.value })}
                      className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                    <div className="grid grid-cols-2 gap-2">
                       <input
                        placeholder="UF"
                        maxLength={2}
                        value={route.state}
                        onChange={(e) => setRoute({ ...route, state: e.target.value.toUpperCase() })}
                        className="w-full px-3 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm text-center"
                      />
                      <input
                        placeholder="CEP"
                        value={route.zipCode}
                        onChange={(e) => setRoute({ ...route, zipCode: e.target.value })}
                        className="w-full px-3 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                      />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Saída Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedDeparture}
                      onChange={(e) => setRoute({ ...route, plannedDeparture: e.target.value })}
                      className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-xs"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Chegada Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedArrival}
                      onChange={(e) => setRoute({ ...route, plannedArrival: e.target.value })}
                      className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-xs"
                    />
                  </div>
                </div>

                <button
                  onClick={fetchRouteDetails}
                  disabled={!route.origin || !route.destination || loadingRoute}
                  className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:opacity-50 flex items-center justify-center gap-2 transition-all"
                >
                  {loadingRoute ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-search-location"></i>}
                  Consultar Rota Inteligente
                </button>
              </div>

              <div className="bg-slate-50 rounded-xl p-6 border border-slate-200 relative min-h-[350px]">
                {loadingRoute ? (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400">
                    <i className="fas fa-robot text-3xl mb-4 animate-bounce"></i>
                    <p className="font-medium text-center px-4">O Gemini está analisando as melhores rotas e condições de trânsito...</p>
                  </div>
                ) : routeInfo ? (
                  <div className="space-y-4">
                    <div className="flex items-center gap-2 text-blue-600 font-bold mb-2">
                      <i className="fas fa-info-circle"></i>
                      <span>Resumo do Trajeto</span>
                    </div>
                    <p className="text-sm text-slate-600 leading-relaxed italic">"{routeInfo.text}"</p>

                    {routeInfo.grounding.length > 0 && (
                      <div className="pt-4 border-t border-slate-200">
                        <p className="text-xs font-bold text-slate-400 uppercase mb-2">Fontes do Google Maps</p>
                        <div className="flex flex-wrap gap-2">
                          {routeInfo.grounding.map((chunk: any, i: number) => (
                            chunk.googleSearch && (
                              <a key={i} href={chunk.googleSearch.uri} target="_blank" className="text-[10px] bg-white border px-2 py-1 rounded text-blue-500 hover:underline">
                                {chunk.googleSearch.title}
                              </a>
                            )
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 text-center px-8">
                    <i className="fas fa-map text-4xl mb-4"></i>
                    <p className="text-sm">Insira origem e destino para ver estatísticas do trajeto e orientações de trânsito.</p>
                  </div>
                )}
              </div>
            </div>

            <div className="mt-8 flex justify-between">
              <button onClick={() => setStep(2)} className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl">Voltar</button>
              <button
                onClick={handleStartTrip}
                disabled={!route.origin || !route.destination || !route.city}
                className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all flex items-center gap-2 disabled:opacity-50"
              >
                Confirmar Saída do Veículo <i className="fas fa-check-circle"></i>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default OperationWizard;

import React, { useState, useRef, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, onTabChange }) => {
  const { currentUser, logout, notifications, markNotificationAsRead } = useFleet();
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const menuItems = [
    { id: 'dashboard', icon: 'fa-chart-pie', label: 'Dashboard' },
    { id: 'fleet', icon: 'fa-truck', label: 'Frota' },
    { id: 'drivers', icon: 'fa-users', label: 'Motoristas' },
    { id: 'scheduling', icon: 'fa-calendar-alt', label: 'Agenda' },
    { id: 'operation', icon: 'fa-key', label: 'Operação (Saída)' },
    { id: 'monitoring', icon: 'fa-map-location-dot', label: 'Monitoramento' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col hidden md:flex">
        <div className="p-6 border-b border-slate-800">
          <h1 className="text-xl font-bold flex items-center gap-2">
            <i className="fas fa-route text-blue-500"></i>
            FleetFlow <span className="text-blue-500">Pro</span>
          </h1>
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
                activeTab === item.id 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <i className={`fas ${item.icon} w-5`}></i>
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3">
            <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center font-bold overflow-hidden">
              {currentUser?.avatar ? (
                <img src={currentUser.avatar} alt="" className="w-full h-full object-cover" />
              ) : (
                currentUser?.name.charAt(0)
              )}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium truncate">{currentUser?.name}</p>
              <p className="text-xs text-slate-500 truncate">@{currentUser?.username}</p>
