interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, onTabChange }) => {
  const { currentUser, logout, notifications, markNotificationAsRead } = useFleet();
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const menuItems = [
    { id: 'dashboard', icon: 'fa-chart-pie', label: 'Dashboard' },
    { id: 'fleet', icon: 'fa-truck', label: 'Frota' },
    { id: 'drivers', icon: 'fa-users', label: 'Motoristas' },
    { id: 'scheduling', icon: 'fa-calendar-alt', label: 'Agenda' },
    { id: 'operation', icon: 'fa-key', label: 'Operação (Saída)' },
    { id: 'monitoring', icon: 'fa-map-location-dot', label: 'Monitoramento' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col hidden md:flex shadow-sm z-20">
        <div className="p-8 flex justify-center">
          <Logo size="sm" />
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          <div className="px-4 mb-4">
             <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Menu Principal</span>
          </div>
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all group ${
                activeTab === item.id 
                ? 'bg-slate-900 text-white shadow-xl shadow-slate-200' 
                : 'text-slate-400 hover:bg-slate-50 hover:text-slate-900'
              }`}
            >
              <i className={`fas ${item.icon} w-5 text-sm transition-transform group-hover:scale-110`}></i>
              <span className="font-bold text-xs uppercase tracking-tight">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-6">
          <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-10 h-10 rounded-2xl bg-white border border-slate-100 shadow-sm flex items-center justify-center font-bold overflow-hidden ring-2 ring-slate-100 ring-offset-2">
                {currentUser?.avatar ? (
                  <img src={currentUser.avatar} alt="" className="w-full h-full object-cover" />
                ) : (
                  <span className="text-slate-400">{currentUser?.name.charAt(0)}</span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-black text-slate-800 truncate uppercase tracking-tighter">{currentUser?.name}</p>
                <p className="text-[10px] text-slate-400 truncate font-bold">@{currentUser?.username}</p>
              </div>
            </div>
            <button 
              onClick={logout} 
              className="w-full py-2 bg-white text-red-500 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-100 hover:bg-red-50 transition-colors"
            >
              Sair do Sistema
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Topbar / Header */}
        <header className="bg-white/80 backdrop-blur-md border-b border-slate-100 p-4 flex items-center justify-between md:justify-end gap-4 shadow-sm z-10">
          <div className="md:hidden">
            <Logo size="sm" />
          </div>

          <div className="flex items-center gap-4">
            {/* Notification Center */}
            <div className="relative" ref={notificationRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="w-11 h-11 rounded-2xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-slate-600 hover:border-slate-300 transition-all relative shadow-sm"
              >
                <i className="fas fa-bell text-sm"></i>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-blue-600 text-white text-[9px] font-black w-5 h-5 rounded-lg flex items-center justify-center border-2 border-white shadow-lg">
                    {unreadCount}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in zoom-in duration-200">
                  <div className="p-5 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="font-black text-slate-800 text-[10px] uppercase tracking-[0.2em]">Notificações</h3>
                    <span className="text-[9px] text-blue-600 font-black uppercase tracking-widest">{notifications.length} alertas</span>
                  </div>
                  <div className="max-h-[400px] overflow-y-auto">
                    {notifications.length > 0 ? (
                      notifications.map(n => (
                        <div 
                          key={n.id} 
                          onClick={() => markNotificationAsRead(n.id)}
                          className={`p-5 border-b border-slate-50 hover:bg-slate-50 cursor-pointer transition-colors flex gap-4 ${!n.isRead ? 'bg-blue-50/20' : ''}`}
                        >
                          <div className={`w-9 h-9 rounded-2xl flex items-center justify-center flex-shrink-0 shadow-sm ${
                            n.type === 'low_fuel' ? 'bg-orange-100 text-orange-600' : 
                            n.type === 'occurrence' ? 'bg-red-100 text-red-600' :
                            n.type === 'schedule' ? 'bg-indigo-100 text-indigo-600' : 'bg-blue-100 text-blue-600'
                          }`}>
                            <i className={`fas ${
                              n.type === 'low_fuel' ? 'fa-gas-pump' : 
                              n.type === 'occurrence' ? 'fa-triangle-exclamation' :
                              n.type === 'schedule' ? 'fa-calendar-alt' : 'fa-wrench'
                            } text-xs`}></i>
                          </div>
                          <div className="flex-1">
                            <div className="flex justify-between items-start mb-1">
                              <p className="text-[10px] font-black text-slate-800 uppercase tracking-tight">{n.title}</p>
                              <span className="text-[9px] text-slate-300 font-bold">{new Date(n.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                            <p className="text-xs text-slate-500 leading-relaxed">{n.message}</p>
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="p-12 text-center">
                        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-100">
                           <i className="fas fa-check-double text-slate-200 text-2xl"></i>
                        </div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Tudo em dia!</p>
                      </div>
                    )}
                  </div>
                  <div className="p-4 text-center border-t border-slate-50 bg-slate-50/30">
                    <button className="text-[9px] font-black text-blue-600 hover:text-blue-800 uppercase tracking-[0.2em] transition-colors">Limpar Histórico</button>
                  </div>
                </div>
              )}
            </div>

            <button onClick={logout} className="md:hidden w-11 h-11 bg-white border border-slate-100 rounded-2xl text-slate-400 flex items-center justify-center shadow-sm">
              <i className="fas fa-sign-out-alt"></i>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          {children}
        </div>

        {/* Mobile Tab Bar */}
        <nav className="md:hidden bg-white/90 backdrop-blur-md border-t border-slate-100 flex items-center justify-around p-3 z-20">
          {menuItems.slice(0, 5).map(item => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`flex flex-col items-center p-2 rounded-2xl transition-all ${
                activeTab === item.id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-300'
              }`}
            >
              <i className={`fas ${item.icon} text-lg`}></i>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  serviceType: string;
  cost: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string; // Base64 image string
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  distance?: number;
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

export interface AppState {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
}

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { getRouteInsights } from '../services/geminiService';
import { checkSPRodizio } from '../utils/trafficRules';

const OperationWizard: React.FC = () => {
  const { vehicles, currentUser, startTrip } = useFleet();
  const [step, setStep] = useState(1); // 1: Vehicle Selection, 2: Checklist, 3: Route

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: '',
    city: '',
    state: '',
    zipCode: '',
    plannedDeparture: '',
    plannedArrival: '',
    observations: ''
  });

  const [routeInfo, setRouteInfo] = useState<any>(null);
  const [loadingRoute, setLoadingRoute] = useState(false);

  // Set initial KM when vehicle is selected
  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ 
        ...prev, 
        km: selectedVehicle.currentKm, 
        fuelLevel: selectedVehicle.fuelLevel,
        oilChecked: false,
        waterChecked: false,
        tiresChecked: false 
      }));
    }
  }, [selectedVehicle]);

  const isChecklistValid = 
    checklist.oilChecked && 
    checklist.waterChecked && 
    checklist.tiresChecked && 
    (checklist.km ?? 0) >= (selectedVehicle?.currentKm ?? 0);

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      city: route.city,
      state: route.state,
      zipCode: route.zipCode,
      plannedDeparture: route.plannedDeparture,
      plannedArrival: route.plannedArrival,
      startTime: new Date().toISOString(),
      observations: route.observations
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: new Date().toISOString()
    };

    startTrip(newTrip, finalChecklist);
    alert('Viagem iniciada com sucesso!');
    // Reset wizard
    setStep(1);
    setSelectedVehicle(null);
    setRoute({
      origin: '',
      destination: '',
      city: '',
      state: '',
      zipCode: '',
      plannedDeparture: '',
      plannedArrival: '',
      observations: ''
    });
  };

  const fetchRouteDetails = async () => {
    if (!route.origin || !route.destination) return;
    setLoadingRoute(true);
    const locationContext = `${route.destination}, ${route.city} - ${route.state}`;
    const info = await getRouteInsights(route.origin, locationContext);
    setRouteInfo(info);
    setLoadingRoute(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-4">
      {/* Stepper Header */}
      <div className="flex items-center justify-between mb-8 px-4">
        {[
          { step: 1, label: 'Veículo', icon: 'fa-truck-pickup' },
          { step: 2, label: 'Checklist', icon: 'fa-clipboard-check' },
          { step: 3, label: 'Rota', icon: 'fa-map-marked-alt' }
        ].map((s) => (
          <div key={s.step} className="flex flex-col items-center flex-1">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${
              step >= s.step ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white border-slate-200 text-slate-400'
            }`}>
              <i className={`fas ${s.icon}`}></i>
            </div>
            <span className={`text-xs mt-2 font-bold uppercase tracking-wider ${step >= s.step ? 'text-blue-600' : 'text-slate-400'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        {step === 1 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Qual veículo você está pegando?</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => {
                const restrictedToday = checkSPRodizio(v.plate);
                return (
                  <button
                    key={v.id}
                    onClick={() => setSelectedVehicle(v)}
                    className={`p-6 rounded-xl border-2 text-left transition-all flex flex-col gap-4 relative ${
                      selectedVehicle?.id === v.id ? 'border-blue-600 bg-blue-50 ring-4 ring-blue-100' : 'border-slate-100 hover:border-blue-200'
                    }`}
                  >
                    {restrictedToday && (
                       <div className="absolute top-2 right-2 flex items-center gap-1 bg-amber-500 text-black font-black text-[8px] px-1.5 py-0.5 rounded shadow-sm">
                         <i className="fas fa-exclamation-triangle"></i> RODÍZIO SP HOJE
                       </div>
                    )}
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                        <i className="fas fa-truck text-xl"></i>
                      </div>
                      <div className="flex-1">
                        <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                        <p className="text-sm text-slate-500">{v.brand} {v.model}</p>
                      </div>
                    </div>
                    <div className="flex justify-between items-end border-t border-slate-100 pt-3 mt-1">
                      <p className="text-xs text-slate-400">{v.currentKm.toLocaleString()} km</p>
                      <p className="text-xs font-bold text-blue-600 uppercase">Disponível</p>
                    </div>
                  </button>
                );
              })}
            </div>
            <div className="mt-8 flex justify-end">
              <button
                disabled={!selectedVehicle}
                onClick={() => setStep(2)}
                className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="p-8">
            <div className="flex items-center justify-between mb-2">
               <h3 className="text-xl font-bold text-slate-800">Checklist de Segurança</h3>
               {!isChecklistValid && (
                 <span className="text-[10px] font-bold text-red-500 bg-red-50 px-2 py-1 rounded-full uppercase animate-pulse">
                   Validação Pendente
                 </span>
               )}
            </div>
            <p className="text-slate-500 mb-8">Veículo: <span className="font-bold text-blue-600">{selectedVehicle?.plate}</span></p>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="relative">
                  <label className="block text-sm font-bold text-slate-700 mb-2">Quilometragem Atual</label>
                  <input
                    type="number"
                    min={selectedVehicle?.currentKm}
                    value={checklist.km}
                    onChange={(e) => setChecklist({ ...checklist, km: parseInt(e.target.value) })}
                    className={`w-full p-3 rounded-xl border focus:outline-none font-medium transition-all ${
                      (checklist.km ?? 0) >= (selectedVehicle?.currentKm ?? 0) 
                        ? 'border-green-200 bg-green-50/30 focus:ring-green-500' 
                        : 'border-slate-200 focus:ring-blue-500'
                    }`}
                  />
                  <p className="text-[10px] mt-1 text-slate-400">Mínimo: {selectedVehicle?.currentKm} km</p>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-2">Nível de Combustível (%)</label>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={checklist.fuelLevel}
                    onChange={(e) => setChecklist({ ...checklist, fuelLevel: parseInt(e.target.value) })}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 mt-4"
                  />
                  <div className="flex justify-between text-xs font-bold text-slate-400 mt-2">
                    <span>Vazio</span>
                    <span className="text-blue-600">{checklist.fuelLevel}%</span>
                    <span>Cheio</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {[
                  { key: 'oilChecked', label: 'Verificar Óleo', icon: 'fa-oil-can' },
                  { key: 'waterChecked', label: 'Verificar Água', icon: 'fa-tint' },
                  { key: 'tiresChecked', label: 'Pneus Calibrados', icon: 'fa-car' }
                ].map(item => {
                  const isChecked = checklist[item.key as keyof Checklist];
                  return (
                    <button
                      key={item.key}
                      onClick={() => setChecklist({ ...checklist, [item.key]: !isChecked })}
                      className={`p-5 rounded-xl border-2 flex flex-col items-center justify-center gap-3 transition-all relative overflow-hidden group ${
                        isChecked 
                          ? 'bg-green-50 border-green-500 text-green-700 shadow-inner' 
                          : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200 hover:bg-slate-50'
                      }`}
                    >
                      <i className={`fas ${item.icon} text-xl transition-transform ${isChecked ? 'scale-110' : 'group-hover:scale-110'}`}></i>
                      <span className="font-bold text-xs uppercase tracking-tight">{item.label}</span>

                      {isChecked ? (
                        <div className="absolute top-2 right-2 text-green-600 text-xs">
                          <i className="fas fa-check-circle"></i>
                        </div>
                      ) : (
                        <div className="absolute top-2 right-2 text-slate-200 text-xs">
                          <i className="fas fa-circle-notch"></i>
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Observações Adicionais</label>
                <textarea
                  placeholder="Arranhões, luzes acesas, etc..."
                  value={checklist.comments}
                  onChange={(e) => setChecklist({ ...checklist, comments: e.target.value })}
                  className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none h-24 resize-none text-sm"
                />
              </div>
            </div>

            <div className="mt-8 flex justify-between items-center">
              <button onClick={() => setStep(1)} className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors">
                Voltar
              </button>
              <div className="flex flex-col items-end gap-2">
                {!isChecklistValid && (
                  <p className="text-[10px] text-red-400 font-medium italic">Marque todos os itens acima para prosseguir</p>
                )}
                <button
                  disabled={!isChecklistValid}
                  onClick={() => setStep(3)}
                  className={`px-8 py-3 rounded-xl font-bold transition-all flex items-center gap-2 shadow-lg ${
                    isChecklistValid 
                      ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200' 
                      : 'bg-slate-100 text-slate-300 cursor-not-allowed shadow-none'
                  }`}
                >
                  Próximo Passo <i className="fas fa-arrow-right"></i>
                </button>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Planejamento de Rota & Horários</h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-5">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Ponto de Origem</label>
                  <div className="relative">
                    <i className="fas fa-circle-dot absolute left-4 top-1/2 -translate-y-1/2 text-blue-500"></i>
                    <input
                      placeholder="Ex: Garagem Central"
                      value={route.origin}
                      onChange={(e) => setRoute({ ...route, origin: e.target.value })}
                      className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                  </div>
                </div>

                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-4">
                  <div className="flex items-center gap-2 text-slate-700 font-bold text-xs uppercase mb-1">
                    <i className="fas fa-location-dot text-red-500"></i>
                    Destino do Trajeto
                  </div>

                  <div>
                    <input
                      placeholder="Endereço / Local de Destino"
                      value={route.destination}
                      onChange={(e) => setRoute({ ...route, destination: e.target.value })}
                      className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <input
                      placeholder="Cidade"
                      value={route.city}
                      onChange={(e) => setRoute({ ...route, city: e.target.value })}
                      className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                    />
                    <div className="grid grid-cols-2 gap-2">
                       <input
                        placeholder="UF"
                        maxLength={2}
                        value={route.state}
                        onChange={(e) => setRoute({ ...route, state: e.target.value.toUpperCase() })}
                        className="w-full px-3 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm text-center"
                      />
                      <input
                        placeholder="CEP"
                        value={route.zipCode}
                        onChange={(e) => setRoute({ ...route, zipCode: e.target.value })}
                        className="w-full px-3 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm"
                      />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Saída Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedDeparture}
                      onChange={(e) => setRoute({ ...route, plannedDeparture: e.target.value })}
                      className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-xs"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Chegada Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedArrival}
                      onChange={(e) => setRoute({ ...route, plannedArrival: e.target.value })}
                      className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-xs"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5 uppercase tracking-wide text-[11px]">Observações da Viagem</label>
                  <textarea
                    placeholder="Informações adicionais sobre a rota ou entrega..."
                    value={route.observations}
                    onChange={(e) => setRoute({ ...route, observations: e.target.value })}
                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm h-20 resize-none"
                  />
                </div>

                <button
                  onClick={fetchRouteDetails}
                  disabled={!route.origin || !route.destination || loadingRoute}
                  className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:opacity-50 flex items-center justify-center gap-2 transition-all"
                >
                  {loadingRoute ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-search-location"></i>}
                  Consultar Rota Inteligente
                </button>
              </div>

              <div className="bg-slate-50 rounded-xl p-6 border border-slate-200 relative min-h-[350px]">
                {loadingRoute ? (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400">
                    <i className="fas fa-robot text-3xl mb-4 animate-bounce"></i>
                    <p className="font-medium text-center px-4">O Gemini está analisando as melhores rotas e condições de trânsito...</p>
                  </div>
                ) : routeInfo ? (
                  <div className="space-y-4">
                    <div className="flex items-center gap-2 text-blue-600 font-bold mb-2">
                      <i className="fas fa-info-circle"></i>
                      <span>Resumo do Trajeto</span>
                    </div>
                    <p className="text-sm text-slate-600 leading-relaxed italic">"{routeInfo.text}"</p>

                    {routeInfo.grounding.length > 0 && (
                      <div className="pt-4 border-t border-slate-200">
                        <p className="text-xs font-bold text-slate-400 uppercase mb-2">Fontes do Google Maps</p>
                        <div className="flex flex-wrap gap-2">
                          {routeInfo.grounding.map((chunk: any, i: number) => (
                            chunk.googleSearch && (
                              <a key={i} href={chunk.googleSearch.uri} target="_blank" className="text-[10px] bg-white border px-2 py-1 rounded text-blue-500 hover:underline">
                                {chunk.googleSearch.title}
                              </a>
                            )
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 text-center px-8">
                    <i className="fas fa-map text-4xl mb-4"></i>
                    <p className="text-sm">Insira origem e destino para ver estatísticas do trajeto e orientações de trânsito.</p>
                  </div>
                )}
              </div>
            </div>

            <div className="mt-8 flex justify-between">
              <button onClick={() => setStep(2)} className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl">Voltar</button>
              <button
                onClick={handleStartTrip}
                disabled={!route.origin || !route.destination || !route.city}
                className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all flex items-center gap-2 disabled:opacity-50"
              >
                Confirmar Saída do Veículo <i className="fas fa-check-circle"></i>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default OperationWizard;

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle, Occurrence, OccurrenceSeverity } from '../types';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, occurrences, endTrip, cancelTrip, addOccurrence } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [endTime, setEndTime] = useState<string>(new Date().toISOString().slice(0, 16));
  const [now, setNow] = useState(new Date());

  // Occurrence Modal State
  const [reportingTrip, setReportingTrip] = useState<Trip | null>(null);
  const [newOccurrence, setNewOccurrence] = useState({
    type: '',
    description: '',
    severity: OccurrenceSeverity.LOW
  });

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      endTrip(finishingTripId, endKm, new Date(endTime).toISOString());
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso!');
    }
  };

  const handleCancel = (tripId: string) => {
    if (confirm('ATENÇÃO: Deseja realmente cancelar esta operação? O veículo e o motorista serão liberados imediatamente e o status voltará para "Disponível".')) {
      cancelTrip(tripId);
      alert('Operação cancelada. Veículo liberado.');
    }
  };

  const handleReportOccurrence = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reportingTrip || !newOccurrence.type || !newOccurrence.description) return;

    const occ: Occurrence = {
      id: Math.random().toString(36).substr(2, 9),
      tripId: reportingTrip.id,
      vehicleId: reportingTrip.vehicleId,
      driverId: reportingTrip.driverId,
      type: newOccurrence.type,
      description: newOccurrence.description,
      severity: newOccurrence.severity,
      timestamp: new Date().toISOString(),
      resolved: false
    };

    addOccurrence(occ);
    setReportingTrip(null);
    setNewOccurrence({ type: '', description: '', severity: OccurrenceSeverity.LOW });
    alert('Ocorrência registrada com sucesso. A central de controle foi notificada.');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase shadow-sm">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);
            const tripOccurrences = occurrences.filter(o => o.tripId === trip.id);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all transform hover:-translate-y-1 relative">
                {tripOccurrences.length > 0 && (
                  <div className="absolute top-2 left-2 z-10 flex gap-1">
                    <span className="bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-full animate-bounce shadow-lg">
                      {tripOccurrences.length} Ocorrência(s)
                    </span>
                  </div>
                )}

                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs shadow-inner">
                      {vehicle?.plate}
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                      <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Saída</p>
                    <p className="text-xs font-medium">{new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                    {trip.plannedArrival && (
                      <span className="text-[10px] text-slate-400 font-medium">
                        ETA: {new Date(trip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white shadow-sm overflow-hidden ring-1 ring-slate-100">
                      {driver?.avatar ? (
                        <img src={driver.avatar} alt="" className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">
                          {driver?.name.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                      <p className="text-[10px] text-slate-500 uppercase font-medium">CNH: {driver?.license}</p>
                    </div>
                    <button 
                      onClick={() => setReportingTrip(trip)}
                      className="w-8 h-8 rounded-full bg-orange-50 text-orange-600 flex items-center justify-center hover:bg-orange-100 transition-colors"
                      title="Relatar Ocorrência"
                    >
                      <i className="fas fa-triangle-exclamation"></i>
                    </button>
                  </div>

                  <div className="space-y-3">
                    <div className="flex gap-3">
                      <div className="flex flex-col items-center">
                        <i className="fas fa-circle-dot text-blue-500 text-[10px] mt-1"></i>
                        <div className="w-px h-full bg-slate-200 my-1"></div>
                        <i className="fas fa-location-dot text-red-500 text-[10px]"></i>
                      </div>
                      <div className="flex-1 space-y-3">
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Origem</p>
                          <p className="text-sm text-slate-700 font-medium truncate">{trip.origin}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Destino</p>
                          <p className="text-sm text-slate-800 font-bold truncate">{trip.destination}, {trip.city}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  {trip.observations && (
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Observações</p>
                      <p className="text-xs text-slate-600 italic line-clamp-2">{trip.observations}</p>
                    </div>
                  )}

                  <div className="pt-4 flex gap-2">
                    <button 
                      onClick={() => handleFinish(trip)}
                      className="flex-1 bg-emerald-600 text-white py-2.5 rounded-xl font-bold text-xs hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100 active:scale-95"
                    >
                      <i className="fas fa-check-circle mr-2"></i> Encerrar
                    </button>
                    <button 
                      onClick={() => handleCancel(trip.id)}
                      className="px-4 py-2.5 border border-slate-200 text-slate-400 hover:text-red-600 hover:bg-red-50 hover:border-red-100 rounded-xl transition-all group"
                      title="Cancelar Viagem"
                    >
                      <i className="fas fa-ban group-hover:scale-110 transition-transform"></i>
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border border-dashed border-slate-200 shadow-sm">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
              <i className="fas fa-map-location-dot text-4xl"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Céu Limpo</h3>
            <p className="text-slate-400 text-sm mt-2 max-w-xs mx-auto">Nenhuma viagem em andamento no momento.</p>
          </div>
        )}
      </div>

      {/* Finishing Modal */}
      {finishingTripId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-900 text-white">
              <h3 className="text-lg font-bold">Encerrar Viagem</h3>
              <p className="text-slate-400 text-xs mt-1">Informe os dados finais para concluir o trajeto.</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">KM de Chegada</label>
                <div className="relative">
                  <i className="fas fa-gauge absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="number"
                    value={endKm}
                    onChange={(e) => setEndKm(parseInt(e.target.value))}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800"
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Data/Hora de Chegada</label>
                <div className="relative">
                  <i className="fas fa-calendar-check absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
                  <input 
                    type="datetime-local"
                    value={endTime}
                    onChange={(e) => setEndTime(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-medium text-slate-800"
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setFinishingTripId(null)} className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors">Cancelar</button>
                <button onClick={confirmFinish} className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-bold shadow-lg shadow-emerald-200 hover:bg-emerald-700 transition-all">Confirmar Chegada</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Occurrence Modal */}
      {reportingTrip && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-orange-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-lg font-bold">Relatar Ocorrência</h3>
                <p className="text-orange-100 text-xs mt-1">Veículo: {vehicles.find(v => v.id === reportingTrip.vehicleId)?.plate}</p>
              </div>
              <i className="fas fa-triangle-exclamation text-2xl opacity-50"></i>
            </div>

            <form onSubmit={handleReportOccurrence} className="p-6 space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Tipo de Incidente</label>
                  <select 
                    required
                    value={newOccurrence.type}
                    onChange={(e) => setNewOccurrence({ ...newOccurrence, type: e.target.value })}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none font-medium text-slate-800"
                  >
                    <option value="">Selecione...</option>
                    <option value="Acidente / Colisão">Acidente / Colisão</option>
                    <option value="Falha Mecânica">Falha Mecânica</option>
                    <option value="Pneu Furado">Pneu Furado</option>
                    <option value="Atraso por Trânsito">Atraso por Trânsito</option>
                    <option value="Problema com Carga">Problema com Carga</option>
                    <option value="Bloqueio de Via">Bloqueio de Via</option>
                    <option value="Outros">Outros</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Severidade</label>
                  <div className="flex gap-2">
                    {[
                      { val: OccurrenceSeverity.LOW, label: 'Baixa', color: 'bg-blue-100 text-blue-600 border-blue-200' },
                      { val: OccurrenceSeverity.MEDIUM, label: 'Média', color: 'bg-orange-100 text-orange-600 border-orange-200' },
                      { val: OccurrenceSeverity.HIGH, label: 'Alta', color: 'bg-red-100 text-red-600 border-red-200' }
                    ].map(s => (
                      <button
                        key={s.val}
                        type="button"
                        onClick={() => setNewOccurrence({ ...newOccurrence, severity: s.val })}
                        className={`flex-1 py-2 text-[10px] font-bold rounded-lg border transition-all ${
                          newOccurrence.severity === s.val ? 'ring-2 ring-slate-800 ring-offset-1 ' + s.color : 'bg-white text-slate-400 border-slate-100'
                        }`}
                      >
                        {s.label}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Descrição dos Fatos</label>
                <textarea
                  required
                  placeholder="Descreva o que aconteceu em detalhes para a equipe de controle..."
                  value={newOccurrence.description}
                  onChange={(e) => setNewOccurrence({ ...newOccurrence, description: e.target.value })}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-500 outline-none text-sm min-h-[120px] resize-none"
                />
              </div>

              <div className="flex gap-3 pt-2">
                <button 
                  type="button" 
                  onClick={() => setReportingTrip(null)}
                  className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 bg-orange-600 text-white rounded-xl font-bold shadow-lg shadow-orange-200 hover:bg-orange-700 transition-all"
                >
                  Enviar Relato
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripMonitoring;

import React, { useState, useRef, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import Logo from './Logo';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, onTabChange }) => {
  const { currentUser, logout, notifications, markNotificationAsRead } = useFleet();
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;
  const isAdmin = currentUser?.username === 'admin';

  const menuItems = [
    { id: 'dashboard', icon: 'fa-chart-pie', label: 'Dashboard', adminOnly: false },
    { id: 'fleet', icon: 'fa-truck', label: 'Frota', adminOnly: true },
    { id: 'drivers', icon: 'fa-users', label: 'Motoristas', adminOnly: true },
    { id: 'scheduling', icon: 'fa-calendar-alt', label: 'Agenda', adminOnly: true },
    { id: 'operation', icon: 'fa-key', label: 'Operação (Saída)', adminOnly: false },
    { id: 'monitoring', icon: 'fa-map-location-dot', label: 'Monitoramento', adminOnly: true },
  ];

  // Filter items based on user role
  const visibleMenuItems = menuItems.filter(item => !item.adminOnly || isAdmin);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col hidden md:flex shadow-sm z-20">
        <div className="p-8 flex justify-center">
          <Logo size="sm" />
