                      <span className="text-[8px] font-bold text-slate-400">{new Date(occ.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-1">{occ.description}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <p className="text-xs font-medium italic">Nenhuma ocorrência registrada.</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-4">Alertas Críticos</h3>
            <div className="space-y-3">
              {activeAlerts.length > 0 ? (
                activeAlerts.map(alert => (
                  <div key={alert.id} className="p-3 bg-slate-50 border-l-4 border-orange-500 rounded-r-lg">
                    <p className="text-xs font-bold text-slate-800">{alert.title}</p>
