    notes: ''
  });

  const selectedVehicle = vehicles.find(v => v.id === newSchedule.vehicleId);
  const isRestricted = selectedVehicle && checkSPRodizio(selectedVehicle.plate, new Date(newSchedule.scheduledDate));

  const handleOpenMaps = () => {
    if (!newSchedule.destination) return;
    const query = encodeURIComponent(`${newSchedule.destination}${newSchedule.city ? ', ' + newSchedule.city : ''}`);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const handleAddSchedule = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newSchedule.driverId || !newSchedule.vehicleId || !newSchedule.destination) return;

    const trip: ScheduledTrip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: newSchedule.driverId,
      vehicleId: newSchedule.vehicleId,
      scheduledDate: newSchedule.scheduledDate,
      origin: newSchedule.origin,
      destination: newSchedule.destination,
      city: newSchedule.city,
      notes: newSchedule.notes
    };

    addScheduledTrip(trip);
    setNewSchedule({
      driverId: '',
      vehicleId: '',
      scheduledDate: new Date().toISOString().split('T')[0],
      origin: '',
      destination: '',
      city: '',
      notes: ''
    });
    setShowForm(false);
    alert('Viagem agendada com sucesso!');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Agenda de Viagens</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-200 transition-all"
        >
          <i className={`fas ${showForm ? 'fa-times' : 'fa-calendar-plus'}`}></i>
          {showForm ? 'Cancelar' : 'Agendar Viagem'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleAddSchedule} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Motorista</label>
                <select
                  required
                  value={newSchedule.driverId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, driverId: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                >
                  <option value="">Selecione o condutor...</option>
                  {drivers.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Veículo</label>
                <select
                  required
                  value={newSchedule.vehicleId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, vehicleId: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                >
                  <option value="">Selecione o veículo...</option>
                  {vehicles.map(v => (
                    <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Data da Viagem</label>
                <input
                  required
                  type="date"
                  value={newSchedule.scheduledDate}
                  onChange={(e) => setNewSchedule({ ...newSchedule, scheduledDate: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                />
              </div>
            </div>

            {/* Alerta de Rodízio de SP */}
            {isRestricted && (
              <div className="bg-amber-50 border-2 border-amber-500/50 p-4 rounded-xl flex items-start gap-4 animate-pulse">
                <div className="w-12 h-12 bg-amber-500 text-black rounded-lg flex items-center justify-center text-2xl font-black shrink-0">
                  <i className="fas fa-exclamation-triangle"></i>
                </div>
                <div>
                  <h4 className="font-black text-amber-900 uppercase text-xs tracking-widest">Alerta de Rodízio SP</h4>
                  <p className="text-sm text-amber-800 font-medium">
                    O veículo <span className="font-bold underline">{selectedVehicle.plate}</span> possui restrição de circulação em São Paulo às <span className="font-bold">{getRodizioDayLabel(selectedVehicle.plate)}s</span>. 
                    Verifique o horário da viagem para evitar multas!
                  </p>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Origem</label>
                <input
                  placeholder="Ex: Garagem Central"
                  value={newSchedule.origin}
                  onChange={(e) => setNewSchedule({ ...newSchedule, origin: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Destino</label>
                <div className="flex gap-2">
                  <input
                    required
                    placeholder="Ex: Cliente Alfa"
                    value={newSchedule.destination}
                    onChange={(e) => setNewSchedule({ ...newSchedule, destination: e.target.value })}
                    className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                  />
                  <button
                    type="button"
                    onClick={handleOpenMaps}
                    disabled={!newSchedule.destination}
                    className="w-11 h-11 bg-white border border-slate-200 text-slate-400 hover:text-red-600 hover:border-red-100 rounded-xl flex items-center justify-center transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-sm"
                    title="Ver no Google Maps"
                  >
                    <i className="fas fa-map-location-dot"></i>
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Cidade/UF</label>
                <input
                  placeholder="Ex: São Paulo / SP"
                  value={newSchedule.city}
                  onChange={(e) => setNewSchedule({ ...newSchedule, city: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium"
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Notas Adicionais</label>
              <textarea
                placeholder="Observações sobre a carga, contatos no local..."
                value={newSchedule.notes}
                onChange={(e) => setNewSchedule({ ...newSchedule, notes: e.target.value })}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium h-24 resize-none"
              />
            </div>

            <div className="flex justify-end">
              <button 
                type="submit"
                className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
              >
                Salvar Agendamento
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2">Viagens Planejadas</h3>
        {scheduledTrips.length > 0 ? (
          scheduledTrips.sort((a,b) => new Date(a.scheduledDate).getTime() - new Date(b.scheduledDate).getTime()).map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const restricted = vehicle && checkSPRodizio(vehicle.plate, new Date(trip.scheduledDate));

            return (
              <div key={trip.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center gap-6 hover:shadow-md transition-all">
                <div className="w-full md:w-32 flex flex-col items-center justify-center p-3 bg-slate-50 rounded-xl border border-slate-100 shrink-0">
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{new Date(trip.scheduledDate).toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
                  <span className="text-2xl font-black text-slate-800">{new Date(trip.scheduledDate).getDate()}</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{new Date(trip.scheduledDate).toLocaleDateString('pt-BR', { month: 'short' })}</span>
                </div>

                <div className="flex-1 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Motorista</p>
                    <p className="font-bold text-slate-800">{driver?.name}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                    <div className="flex items-center gap-2">
                      <p className="font-bold text-indigo-600">{vehicle?.plate}</p>
                      {restricted && (
                         <span className="bg-black text-white text-[8px] font-black px-1.5 py-0.5 rounded" title="Restrição de Rodízio em SP">RODÍZIO SP</span>
                      )}
                    </div>
                  </div>
                  <div className="lg:col-span-2">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Destino</p>
                    <div className="flex items-center gap-2">
                      <p className="font-bold text-slate-800 truncate">{trip.destination}, {trip.city}</p>
                      <button
                        onClick={() => {
                          const query = encodeURIComponent(`${trip.destination}${trip.city ? ', ' + trip.city : ''}`);
                          window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
                        }}
                        className="text-slate-300 hover:text-red-500 transition-colors"
                        title="Abrir no Maps"
                      >
                        <i className="fas fa-location-dot text-[10px]"></i>
                      </button>
                    </div>
                  </div>
                </div>

                <div className="flex gap-2">
                  <button 
                    onClick={() => deleteScheduledTrip(trip.id)}
                    className="w-10 h-10 rounded-full bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-100 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                  <button className="w-10 h-10 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 transition-colors">
                    <i className="fas fa-edit"></i>
                  </button>
                </div>
              </div>
            );
          })
        ) : (
          <div className="py-20 text-center bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <i className="fas fa-calendar-day text-4xl text-slate-200 mb-4"></i>
            <p className="text-slate-400 font-medium italic">Nenhuma viagem agendada no momento.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SchedulingPage;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  serviceType: string;
  cost: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string; // Base64 image string
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  waypoints?: string[]; // Novos locais adicionados durante a rota
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  distance?: number;
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

export interface AppState {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence, ScheduledTrip } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  updateTrip: (tripId: string, updates: Partial<Trip>) => void;
  addScheduledTrip: (trip: ScheduledTrip) => void;
  deleteScheduledTrip: (id: string) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

const KM_MAINTENANCE_INTERVAL = 10000;
const KM_ALERT_THRESHOLD = 500;
const DAYS_MAINTENANCE_INTERVAL = 180;
const DAYS_ALERT_THRESHOLD = 15;

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [scheduledTrips, setScheduledTrips] = useState<ScheduledTrip[]>(() => {
    const saved = localStorage.getItem('fleet_scheduled_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [occurrences, setOccurrences] = useState<Occurrence[]>(() => {
    const saved = localStorage.getItem('fleet_occurrences');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
    checkMaintenanceAlerts();
  }, [vehicles, maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords));
  }, [maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_fines', JSON.stringify(fines));
  }, [fines]);

  useEffect(() => {
    localStorage.setItem('fleet_drivers', JSON.stringify(drivers));
  }, [drivers]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_scheduled_trips', JSON.stringify(scheduledTrips));
  }, [scheduledTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_checklists', JSON.stringify(checklists));
  }, [checklists]);

  useEffect(() => {
    localStorage.setItem('fleet_occurrences', JSON.stringify(occurrences));
  }, [occurrences]);

  const checkMaintenanceAlerts = useCallback(() => {
    const newNotifications: AppNotification[] = [];
    const now = new Date();

    vehicles.forEach(vehicle => {
      const vMaintenances = maintenanceRecords
        .filter(r => r.vehicleId === vehicle.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const lastRecord = vMaintenances[0];

      let nextKmMaintenance;
      if (lastRecord) {
        nextKmMaintenance = (Math.floor(vehicle.currentKm / KM_MAINTENANCE_INTERVAL) + 1) * KM_MAINTENANCE_INTERVAL;
      } else {
        nextKmMaintenance = Math.ceil((vehicle.currentKm + 1) / KM_MAINTENANCE_INTERVAL) * KM_MAINTENANCE_INTERVAL;
      }

      if (nextKmMaintenance - vehicle.currentKm <= KM_ALERT_THRESHOLD) {
        newNotifications.push({
          id: `km-${vehicle.id}-${nextKmMaintenance}`,
          type: 'maintenance_km',
          title: 'Manutenção por KM',
          message: `O veículo ${vehicle.plate} está chegando a ${nextKmMaintenance}km. Agende uma revisão.`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }

      if (lastRecord) {
        const lastDate = new Date(lastRecord.date);
        const nextDate = new Date(lastDate);
        nextDate.setDate(lastDate.getDate() + DAYS_MAINTENANCE_INTERVAL);
        const diffTime = nextDate.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (diffDays <= DAYS_ALERT_THRESHOLD) {
          newNotifications.push({
            id: `date-${vehicle.id}-${nextDate.toISOString()}`,
            type: 'maintenance_date',
            title: 'Manutenção por Prazo',
            message: `O veículo ${vehicle.plate} completará 6 meses desde a última revisão em ${diffDays <= 0 ? 'breve' : diffDays + ' dias'}.`,
            vehicleId: vehicle.id,
            timestamp: now.toISOString(),
            isRead: false
          });
        }
      }

      if (vehicle.fuelLevel < 15) {
        newNotifications.push({
          id: `fuel-${vehicle.id}`,
          type: 'low_fuel',
          title: 'Combustível Baixo',
          message: `O veículo ${vehicle.plate} está com nível crítico de combustível (${vehicle.fuelLevel}%).`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }
    });

    setNotifications(prev => {
      const activeNewIds = new Set(newNotifications.map(n => n.id));
      const filteredOld = prev.filter(n => {
        const isMaintenance = n.type === 'maintenance_km' || n.type === 'maintenance_date';
        if (n.isRead) return true;
        if (!isMaintenance) return true;
        return activeNewIds.has(n.id);
      });
      const currentIds = new Set(filteredOld.map(n => n.id));
      const trulyNew = newNotifications.filter(n => !currentIds.has(n.id));
      return [...trulyNew, ...filteredOld].slice(0, 50);
    });
  }, [vehicles, maintenanceRecords]);

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => {
    setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
    if (currentUser?.id === id) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const deleteDriver = (id: string) => {
    setDrivers(prev => prev.filter(d => d.id !== id));
    if (currentUser?.id === id) logout();
  };

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const updateTrip = (tripId: string, updates: Partial<Trip>) => {
    setActiveTrips(prev => prev.map(t => t.id === tripId ? { ...t, ...updates } : t));
  };

  const addScheduledTrip = (trip: ScheduledTrip) => {
    setScheduledTrips(prev => [trip, ...prev]);
    setNotifications(prev => [{
      id: trip.id,
      type: 'schedule',
      title: 'Nova Viagem Agendada',
      message: `Uma nova viagem para ${trip.destination} foi agendada para o dia ${new Date(trip.scheduledDate).toLocaleDateString('pt-BR')}.`,
      vehicleId: trip.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteScheduledTrip = (id: string) => {
    setScheduledTrips(prev => prev.filter(t => t.id !== id));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const finishedTrip = { ...trip, endTime, distance: currentKm - (trip.distance || 0) }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
  };

  const addFine = (fine: Fine) => {
    setFines(prev => [fine, ...prev]);
    setNotifications(prev => [{
      id: fine.id,
      type: 'new_fine',
      title: 'Nova Multa Registrada',
      message: `Uma nova multa foi registrada para o condutor no veículo ${vehicles.find(v => v.id === fine.vehicleId)?.plate}.`,
      vehicleId: fine.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteFine = (id: string) => {
    setFines(prev => prev.filter(f => f.id !== id));
  };

  const addOccurrence = (occ: Occurrence) => {
    setOccurrences(prev => [occ, ...prev]);
    setNotifications(prev => [{
      id: occ.id,
      type: 'occurrence',
      title: `Ocorrência: ${occ.type}`,
      message: `Nova ocorrência relatada pelo condutor ${drivers.find(d => d.id === occ.driverId)?.name} no veículo ${vehicles.find(v => v.id === occ.vehicleId)?.plate}.`,
      vehicleId: occ.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, scheduledTrips, checklists, maintenanceRecords, notifications, fines, occurrences,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, updateTrip, addScheduledTrip, deleteScheduledTrip, endTrip, cancelTrip, addMaintenanceRecord, addFine, deleteFine, addOccurrence, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

