                <div className="w-full md:w-32 flex flex-col items-center justify-center p-3 bg-slate-50 rounded-xl border border-slate-100 shrink-0">
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{tripDate.toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
                  <span className="text-2xl font-black text-slate-800">{tripDate.getDate()}</span>
