import React, { useState, useEffect, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { getFleetStatsAnalysis } from '../services/geminiService';
import { VehicleStatus, OccurrenceSeverity, Trip } from '../types';

const DashboardOverview: React.FC = () => {
  const { vehicles, drivers, activeTrips, notifications, checklists, occurrences, currentUser, updateTrip, endTrip } = useFleet();
  const [aiInsights, setAiInsights] = useState<string>("Analisando dados da frota...");

  const isAdmin = currentUser?.username === 'admin';
  const myActiveTrip = useMemo(() => activeTrips.find(t => t.driverId === currentUser?.id), [activeTrips, currentUser]);

  // Edit states for Driver
  const [editingTrip, setEditingTrip] = useState(false);
  const [tempDestination, setTempDestination] = useState('');
  const [tempCity, setTempCity] = useState('');
  const [tempState, setTempState] = useState('');
  const [tempArrival, setTempArrival] = useState('');
  const [newWaypoint, setNewWaypoint] = useState('');

  // Sincronizar estados temporários quando o modal abre
  useEffect(() => {
    if (editingTrip && myActiveTrip) {
      setTempDestination(myActiveTrip.destination || '');
      setTempCity(myActiveTrip.city || '');
      setTempState(myActiveTrip.state || '');
      setTempArrival(myActiveTrip.plannedArrival ? myActiveTrip.plannedArrival.slice(0, 16) : '');
    }
  }, [editingTrip, myActiveTrip]);

  const usageStats = useMemo(() => {
    return vehicles.map(v => {
      const vChecklists = checklists.filter(c => c.vehicleId === v.id).sort((a, b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );

      const distanceDriven = vChecklists.length > 1 
        ? vChecklists[vChecklists.length - 1].km - vChecklists[0].km 
        : 0;

      const efficiencyFactor = v.model.includes('Sprinter') ? 12 : v.model.includes('Hilux') ? 9 : 10;
      const avgConsumption = (Math.random() * 2 + (efficiencyFactor - 1)).toFixed(1);

      return {
        id: v.id,
        plate: v.plate,
        model: v.model,
        totalKm: v.currentKm,
        drivenKm: distanceDriven,
        avgConsumption: parseFloat(avgConsumption),
        tripsCount: vChecklists.length,
        fuelScore: v.fuelLevel > 50 ? 'Bom' : 'Baixo'
      };
    });
  }, [vehicles, checklists]);

  const fleetStats = useMemo(() => {
    const total = vehicles.length || 1;
    const available = vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length;
    const inUse = vehicles.filter(v => v.status === VehicleStatus.IN_USE).length;
    const maintenance = vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length;

    return {
      available,
      inUse,
      maintenance,
      total: vehicles.length,
      pAvailable: (available / total * 100).toFixed(0),
      pInUse: (inUse / total * 100).toFixed(0),
      pMaintenance: (maintenance / total * 100).toFixed(0)
    };
  }, [vehicles]);

  const fleetAvgConsumption = useMemo(() => {
    if (usageStats.length === 0) return 0;
    return (usageStats.reduce((sum, s) => sum + s.avgConsumption, 0) / usageStats.length).toFixed(1);
  }, [usageStats]);

  useEffect(() => {
    const fetchInsights = async () => {
      const insights = await getFleetStatsAnalysis({ 
        totalVehicles: vehicles.length, 
        activeTrips: activeTrips.length,
        statusCounts: {
          available: fleetStats.available,
          maintenance: fleetStats.maintenance,
          inUse: fleetStats.inUse,
        },
        usageStats: usageStats,
        pendingAlerts: notifications.filter(n => !n.isRead).length,
        totalOccurrences: occurrences.length,
        highSeverityOccurrences: occurrences.filter(o => o.severity === OccurrenceSeverity.HIGH).length
      });
      setAiInsights(insights || "Não foi possível gerar insights agora.");
    };
    fetchInsights();
  }, [vehicles, activeTrips, notifications, usageStats, fleetStats, occurrences]);

  const kmData = vehicles.map(v => ({ name: v.plate, km: v.currentKm }));
  const activeAlerts = notifications.filter(n => !n.isRead).slice(0, 3);
  const recentOccurrences = occurrences.slice(0, 3);

  // Handlers for Driver Management
  const handleAdjustArrival = (hours: number) => {
    if (!myActiveTrip?.plannedArrival) return;
    const current = new Date(myActiveTrip.plannedArrival);
    current.setHours(current.getHours() + hours);
    updateTrip(myActiveTrip.id, { plannedArrival: current.toISOString() });
  };

  const handleUpdateRoute = () => {
    if (!myActiveTrip) return;
    const updates: Partial<Trip> = {};
    if (tempDestination) updates.destination = tempDestination;
    if (tempCity) updates.city = tempCity;
    if (tempState) updates.state = tempState;
    if (tempArrival) updates.plannedArrival = new Date(tempArrival).toISOString();

    updateTrip(myActiveTrip.id, updates);
    setEditingTrip(false);
    alert('Rota e informações de destino atualizadas!');
  };

  const handleAddWaypoint = () => {
    if (!myActiveTrip || !newWaypoint) return;
    const waypoints = [...(myActiveTrip.waypoints || []), newWaypoint];
    updateTrip(myActiveTrip.id, { waypoints });
    setNewWaypoint('');
  };

  const handleFinalArrival = () => {
    if (!myActiveTrip) return;
    const vehicle = vehicles.find(v => v.id === myActiveTrip.vehicleId);
    if (!vehicle) return;

    const km = prompt(`Informe o KM final do veículo ${vehicle.plate}:`, vehicle.currentKm.toString());
    if (km) {
      endTrip(myActiveTrip.id, parseInt(km), new Date().toISOString());
      alert('Viagem encerrada com sucesso! Veículo liberado.');
    }
  };

  return (
    <div className="space-y-6 pb-12">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Dashboard Geral</h2>
          <p className="text-xs text-slate-400 font-medium">Bem-vindo, {currentUser?.name}.</p>
        </div>
        <div className="flex gap-2">
           <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
            Consumo Médio: {fleetAvgConsumption} km/L
          </span>
          <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-bold">
            {isAdmin ? 'Acesso Administrativo' : 'Acesso Condutor'}
          </span>
        </div>
      </div>

      {/* DRIVER ACTIVE TRIP WIDGET */}
      {!isAdmin && myActiveTrip && (
        <div className="bg-slate-900 text-white rounded-3xl p-6 shadow-2xl border border-slate-800 overflow-hidden relative group">
          <div className="absolute top-4 right-4 flex gap-2">
            <span className="bg-emerald-500 text-white text-[10px] font-black px-2 py-1 rounded-full animate-pulse flex items-center gap-1">
              <i className="fas fa-satellite-dish"></i> EM ROTA
            </span>
          </div>

          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-xl shadow-lg shadow-blue-500/20">
                  <i className="fas fa-truck-moving"></i>
                </div>
                <div>
                  <h3 className="text-lg font-black uppercase tracking-tight">Gerenciar Viagem Ativa</h3>
                  <p className="text-blue-400 text-xs font-bold">{vehicles.find(v => v.id === myActiveTrip.vehicleId)?.plate} • {vehicles.find(v => v.id === myActiveTrip.vehicleId)?.model}</p>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
                  <p className="text-[10px] text-slate-400 uppercase font-black mb-1">Destino Final</p>
                  <p className="text-sm font-bold truncate">{myActiveTrip.destination}{myActiveTrip.city ? `, ${myActiveTrip.city}` : ''}</p>
                </div>
                <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
                  <p className="text-[10px] text-slate-400 uppercase font-black mb-1">Previsão de Chegada</p>
                  <div className="flex items-center justify-between">
                    <span className="text-sm font-bold">{myActiveTrip.plannedArrival ? new Date(myActiveTrip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '--:--'}</span>
                    <div className="flex gap-1">
                      <button onClick={() => handleAdjustArrival(-1)} className="w-6 h-6 bg-white/10 rounded flex items-center justify-center hover:bg-white/20">-</button>
                      <button onClick={() => handleAdjustArrival(1)} className="w-6 h-6 bg-white/10 rounded flex items-center justify-center hover:bg-white/20">+</button>
                    </div>
                  </div>
                </div>
              </div>

              {myActiveTrip.waypoints && myActiveTrip.waypoints.length > 0 && (
                <div className="space-y-2">
                  <p className="text-[10px] text-slate-400 uppercase font-black">Próximas Paradas</p>
                  <div className="flex flex-wrap gap-2">
                    {myActiveTrip.waypoints.map((wp, i) => (
                      <span key={i} className="bg-blue-900/40 text-blue-300 text-[10px] font-bold px-3 py-1.5 rounded-xl border border-blue-800/50 flex items-center gap-2">
                        <i className="fas fa-location-dot"></i> {wp}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="w-full md:w-64 flex flex-col gap-3 justify-center">
              <button 
                onClick={() => setEditingTrip(true)}
                className="w-full py-3 bg-white/10 hover:bg-white/20 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all border border-white/5"
              >
                <i className="fas fa-route mr-2"></i> Alterar Rota
              </button>
              <button 
                onClick={handleFinalArrival}
                className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-emerald-900/40"
              >
                <i className="fas fa-check-circle mr-2"></i> Cheguei ao Local
              </button>
            </div>
          </div>
        </div>
      )}

      {/* EDIT TRIP MODAL (DRIVER) */}
      {editingTrip && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl w-full max-w-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="text-lg font-black uppercase tracking-tight">Alteração de Trajeto</h3>
                <p className="text-slate-400 text-[10px] uppercase font-bold">Ajuste os dados do destino final</p>
              </div>
              <button onClick={() => setEditingTrip(false)} className="w-10 h-10 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/20 transition-all">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="p-8 space-y-6">
              <div className="space-y-4">
                <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 space-y-4">
                  <div className="flex items-center gap-2 text-slate-800 font-black text-[10px] uppercase tracking-widest">
                    <i className="fas fa-map-marker-alt text-red-500"></i>
                    Novo Destino Principal
                  </div>

                  <div>
                    <input 
                      type="text"
                      value={tempDestination}
                      onChange={(e) => setTempDestination(e.target.value)}
                      placeholder="Nome do local / Endereço..."
                      className="w-full p-4 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                  </div>

                  <div className="grid grid-cols-3 gap-3">
                    <div className="col-span-2">
                      <input 
                        type="text"
                        value={tempCity}
                        onChange={(e) => setTempCity(e.target.value)}
                        placeholder="Cidade"
                        className="w-full p-4 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-medium text-slate-800"
                      />
                    </div>
                    <div>
                      <input 
                        type="text"
                        maxLength={2}
                        value={tempState}
                        onChange={(e) => setTempState(e.target.value.toUpperCase())}
                        placeholder="UF"
                        className="w-full p-4 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-black text-center text-slate-800"
                      />
