                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Adicionar Parada Intermediária (Opcional)</label>
                  <div className="flex gap-2">
                    <input 
                      type="text"
                      value={newWaypoint}
                      onChange={(e) => setNewWaypoint(e.target.value)}
                      placeholder="Ex: Posto Graal, Cliente Secundário..."
