                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Previsão Estimada de Término</label>
                  <input 
                    type="datetime-local"
                    value={tempArrival}
                    onChange={(e) => setTempArrival(e.target.value)}
