                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <button onClick={() => setEditingTrip(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[11px] tracking-widest hover:bg-slate-50 rounded-2xl transition-all">Descartar</button>
                <button 
                  onClick={handleUpdateRoute}
                  className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-[11px] tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-100"
                >
                  Salvar Nova Rota
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Real-time Active Trips Monitor (Admin Only) */}
      {isAdmin && activeTrips.length > 0 && (
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="flex items-center justify-between mb-6">
             <div className="flex items-center gap-3">
               <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center">
                 <i className="fas fa-satellite-dish animate-pulse"></i>
               </div>
               <div>
                 <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Viagens Ativas em Tempo Real</h3>
