          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {activeTrips.map(trip => {
              const vehicle = vehicles.find(v => v.id === trip.vehicleId);
              const driver = drivers.find(d => d.id === trip.driverId);
              return (
                <div key={trip.id} className="bg-slate-50 border border-slate-100 p-4 rounded-2xl hover:border-blue-200 transition-all group">
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-xl bg-white border border-slate-100 flex items-center justify-center font-black text-[10px] text-blue-600 shadow-sm">
                        {vehicle?.plate}
                      </div>
                      <div>
                        <p className="text-[10px] font-black text-slate-800 uppercase">{driver?.name}</p>
                        <p className="text-[8px] text-slate-400 font-bold">{vehicle?.model}</p>
                      </div>
                    </div>
                    <span className="text-[8px] font-black text-blue-500 bg-white border border-blue-100 px-1.5 py-0.5 rounded uppercase">Em Rota</span>
                  </div>
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <i className="fas fa-location-arrow text-slate-300 text-[10px]"></i>
                      <p className="text-[10px] text-slate-600 font-bold truncate">Para: {trip.destination}{trip.city ? `, ${trip.city}` : ''}</p>
                    </div>
                    <div className="h-1 w-full bg-slate-200 rounded-full overflow-hidden">
                       <div className="h-full bg-blue-500 animate-progress" style={{ width: '45%' }}></div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Status da Frota</h3>
          <span className="text-xs font-bold text-slate-400">{vehicles.length} veículos totais</span>
        </div>

        <div className="flex h-4 w-full bg-slate-100 rounded-full overflow-hidden mb-6">
          <div style={{ width: `${fleetStats.pAvailable}%` }} className="bg-emerald-500 h-full"></div>
          <div style={{ width: `${fleetStats.pInUse}%` }} className="bg-blue-500 h-full"></div>
          <div style={{ width: `${fleetStats.pMaintenance}%` }} className="bg-red-500 h-full"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="flex items-center gap-3 p-3 rounded-xl bg-emerald-50 border border-emerald-100">
            <div className="w-8 h-8 rounded-lg bg-emerald-500 flex items-center justify-center text-white"><i className="fas fa-check"></i></div>
            <div>
              <p className="text-[10px] font-bold text-emerald-600 uppercase">Disponível</p>
              <p className="text-lg font-bold text-emerald-800">{fleetStats.available}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-blue-50 border border-blue-100">
            <div className="w-8 h-8 rounded-lg bg-blue-500 flex items-center justify-center text-white"><i className="fas fa-route"></i></div>
            <div>
              <p className="text-[10px] font-bold text-blue-600 uppercase">Em Uso</p>
              <p className="text-lg font-bold text-blue-800">{fleetStats.inUse}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-red-50 border border-red-100">
            <div className="w-8 h-8 rounded-lg bg-red-500 flex items-center justify-center text-white"><i className="fas fa-wrench"></i></div>
            <div>
              <p className="text-[10px] font-bold text-red-600 uppercase">Manutenção</p>
              <p className="text-lg font-bold text-red-800">{fleetStats.maintenance}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Veículos Totais', value: vehicles.length, icon: 'fa-truck', color: 'bg-blue-500' },
          { label: 'Ocorrências', value: occurrences.length, icon: 'fa-triangle-exclamation', color: 'bg-orange-500' },
          { label: 'Viagens Ativas', value: activeTrips.length, icon: 'fa-play', color: 'bg-green-500' },
          { label: 'Alertas Ativos', value: notifications.filter(n => !n.isRead).length, icon: 'fa-exclamation-triangle', color: 'bg-orange-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
            <div className={`${stat.color} w-12 h-12 rounded-lg flex items-center justify-center text-white shadow-lg shadow-slate-200`}>
              <i className={`fas ${stat.icon} text-xl`}></i>
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Quilometragem por Veículo</h3>
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={kmData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <YAxis axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                  <Bar dataKey="km" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-6 rounded-xl text-white shadow-xl shadow-blue-900/10">
            <div className="flex items-center gap-3 mb-4">
              <div className="bg-white/20 p-2 rounded-lg"><i className="fas fa-brain text-xl"></i></div>
              <h3 className="text-lg font-bold">Insights de Gestão IA (Gemini)</h3>
            </div>
            <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg border border-white/20">
              <p className="text-blue-50 leading-relaxed whitespace-pre-wrap italic">"{aiInsights}"</p>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-bold">Ocorrências Recentes</h3>
              <i className="fas fa-history text-slate-300"></i>
            </div>
            <div className="space-y-3">
              {recentOccurrences.length > 0 ? (
                recentOccurrences.map(occ => (
                  <div key={occ.id} className={`p-3 border-l-4 rounded-r-lg group hover:bg-slate-50 transition-all ${
                    occ.severity === OccurrenceSeverity.HIGH ? 'border-red-500 bg-red-50/30' : 
                    occ.severity === OccurrenceSeverity.MEDIUM ? 'border-orange-500 bg-orange-50/30' : 'border-blue-500 bg-blue-50/30'
                  }`}>
                    <div className="flex justify-between items-start">
                      <p className="text-xs font-bold text-slate-800">{occ.type}</p>
                      <span className="text-[8px] font-bold text-slate-400">{new Date(occ.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-1">{occ.description}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <p className="text-xs font-medium italic">Nenhuma ocorrência registrada.</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-4">Alertas Críticos</h3>
            <div className="space-y-3">
              {activeAlerts.length > 0 ? (
                activeAlerts.map(alert => (
                  <div key={alert.id} className="p-3 bg-slate-50 border-l-4 border-orange-500 rounded-r-lg">
                    <p className="text-xs font-bold text-slate-800">{alert.title}</p>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-2">{alert.message}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <i className="fas fa-check-circle text-xl mb-2 text-green-200"></i>
                  <p className="text-xs font-medium italic">Nenhum alerta ativo.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardOverview;

import React, { useState, useEffect, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { getFleetStatsAnalysis } from '../services/geminiService';
import { VehicleStatus, OccurrenceSeverity, Trip } from '../types';

const DashboardOverview: React.FC = () => {
  const { vehicles, drivers, activeTrips, notifications, checklists, occurrences, currentUser, updateTrip, endTrip } = useFleet();
  const [aiInsights, setAiInsights] = useState<string>("Analisando dados da frota...");

  const isAdmin = currentUser?.username === 'admin';
  const myActiveTrip = useMemo(() => activeTrips.find(t => t.driverId === currentUser?.id), [activeTrips, currentUser]);

  // Edit states for Driver
  const [editingTrip, setEditingTrip] = useState(false);
  const [tempDestination, setTempDestination] = useState('');
  const [tempCity, setTempCity] = useState('');
  const [tempState, setTempState] = useState('');
  const [tempArrival, setTempArrival] = useState('');
  const [newWaypoint, setNewWaypoint] = useState('');

  // Sincronizar estados temporários quando o modal abre
  useEffect(() => {
    if (editingTrip && myActiveTrip) {
      setTempDestination(myActiveTrip.destination || '');
      setTempCity(myActiveTrip.city || '');
      setTempState(myActiveTrip.state || '');
      setTempArrival(myActiveTrip.plannedArrival ? myActiveTrip.plannedArrival.slice(0, 16) : '');
    }
  }, [editingTrip, myActiveTrip]);

  const usageStats = useMemo(() => {
    return vehicles.map(v => {
      const vChecklists = checklists.filter(c => c.vehicleId === v.id).sort((a, b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );

      const distanceDriven = vChecklists.length > 1 
        ? vChecklists[vChecklists.length - 1].km - vChecklists[0].km 
        : 0;

      const efficiencyFactor = v.model.includes('Sprinter') ? 12 : v.model.includes('Hilux') ? 9 : 10;
      const avgConsumption = (Math.random() * 2 + (efficiencyFactor - 1)).toFixed(1);

      return {
        id: v.id,
        plate: v.plate,
        model: v.model,
        totalKm: v.currentKm,
        drivenKm: distanceDriven,
        avgConsumption: parseFloat(avgConsumption),
        tripsCount: vChecklists.length,
        fuelScore: v.fuelLevel > 50 ? 'Bom' : 'Baixo'
      };
    });
  }, [vehicles, checklists]);

  const fleetStats = useMemo(() => {
    const total = vehicles.length || 1;
    const available = vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length;
    const inUse = vehicles.filter(v => v.status === VehicleStatus.IN_USE).length;
    const maintenance = vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length;

    return {
      available,
      inUse,
      maintenance,
      total: vehicles.length,
      pAvailable: (available / total * 100).toFixed(0),
      pInUse: (inUse / total * 100).toFixed(0),
      pMaintenance: (maintenance / total * 100).toFixed(0)
    };
  }, [vehicles]);

  const fleetAvgConsumption = useMemo(() => {
    if (usageStats.length === 0) return 0;
    return (usageStats.reduce((sum, s) => sum + s.avgConsumption, 0) / usageStats.length).toFixed(1);
  }, [usageStats]);

  useEffect(() => {
    const fetchInsights = async () => {
      const insights = await getFleetStatsAnalysis({ 
        totalVehicles: vehicles.length, 
        activeTrips: activeTrips.length,
        statusCounts: {
          available: fleetStats.available,
          maintenance: fleetStats.maintenance,
          inUse: fleetStats.inUse,
        },
        usageStats: usageStats,
        pendingAlerts: notifications.filter(n => !n.isRead).length,
        totalOccurrences: occurrences.length,
        highSeverityOccurrences: occurrences.filter(o => o.severity === OccurrenceSeverity.HIGH).length
      });
      setAiInsights(insights || "Não foi possível gerar insights agora.");
    };
    fetchInsights();
  }, [vehicles, activeTrips, notifications, usageStats, fleetStats, occurrences]);

  const kmData = vehicles.map(v => ({ name: v.plate, km: v.currentKm }));
  const activeAlerts = notifications.filter(n => !n.isRead).slice(0, 3);
  const recentOccurrences = occurrences.slice(0, 3);

  // Handlers for Driver Management
  const handleAdjustArrival = (hours: number) => {
    if (!myActiveTrip?.plannedArrival) return;
    const current = new Date(myActiveTrip.plannedArrival);
    current.setHours(current.getHours() + hours);
    updateTrip(myActiveTrip.id, { plannedArrival: current.toISOString() });
  };

  const handleUpdateRoute = () => {
    if (!myActiveTrip) return;
    const updates: Partial<Trip> = {};
    if (tempDestination) updates.destination = tempDestination;
    if (tempCity) updates.city = tempCity;
    if (tempState) updates.state = tempState;
    if (tempArrival) updates.plannedArrival = new Date(tempArrival).toISOString();

    updateTrip(myActiveTrip.id, updates);
    setEditingTrip(false);
    alert('Rota e informações de destino atualizadas!');
  };

  const handleAddWaypoint = () => {
    if (!myActiveTrip || !newWaypoint) return;
    const waypoints = [...(myActiveTrip.waypoints || []), newWaypoint];
    updateTrip(myActiveTrip.id, { waypoints });
    setNewWaypoint('');
  };

  const handleFinalArrival = () => {
    if (!myActiveTrip) return;
    const vehicle = vehicles.find(v => v.id === myActiveTrip.vehicleId);
    if (!vehicle) return;

    const km = prompt(`Informe o KM final do veículo ${vehicle.plate}:`, vehicle.currentKm.toString());
    if (km) {
      endTrip(myActiveTrip.id, parseInt(km), new Date().toISOString());
      alert('Viagem encerrada com sucesso! Veículo liberado.');
    }
  };

  return (
    <div className="space-y-6 pb-12">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Dashboard Geral</h2>
          <p className="text-xs text-slate-400 font-medium">Bem-vindo, {currentUser?.name}.</p>
        </div>
        <div className="flex gap-2">
           <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
            Consumo Médio: {fleetAvgConsumption} km/L
          </span>
          <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-bold">
            {isAdmin ? 'Acesso Administrativo' : 'Acesso Condutor'}
          </span>
        </div>
      </div>

      {/* DRIVER ACTIVE TRIP WIDGET */}
      {!isAdmin && myActiveTrip && (
        <div className="bg-slate-900 text-white rounded-3xl p-6 shadow-2xl border border-slate-800 overflow-hidden relative group">
          <div className="absolute top-4 right-4 flex gap-2">
            <span className="bg-emerald-500 text-white text-[10px] font-black px-2 py-1 rounded-full animate-pulse flex items-center gap-1">
              <i className="fas fa-satellite-dish"></i> EM ROTA
            </span>
          </div>

          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-xl shadow-lg shadow-blue-500/20">
                  <i className="fas fa-truck-moving"></i>
                </div>
                <div>
                  <h3 className="text-lg font-black uppercase tracking-tight">Gerenciar Viagem Ativa</h3>
                  <p className="text-blue-400 text-xs font-bold">{vehicles.find(v => v.id === myActiveTrip.vehicleId)?.plate} • {vehicles.find(v => v.id === myActiveTrip.vehicleId)?.model}</p>
                </div>
