        <div className="flex h-4 w-full bg-slate-100 rounded-full overflow-hidden mb-6">
          <div style={{ width: `${fleetStats.pAvailable}%` }} className="bg-emerald-500 h-full"></div>
          <div style={{ width: `${fleetStats.pInUse}%` }} className="bg-blue-500 h-full"></div>
          <div style={{ width: `${fleetStats.pMaintenance}%` }} className="bg-red-500 h-full"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="flex items-center gap-3 p-3 rounded-xl bg-emerald-50 border border-emerald-100">
            <div className="w-8 h-8 rounded-lg bg-emerald-500 flex items-center justify-center text-white"><i className="fas fa-check"></i></div>
            <div>
              <p className="text-[10px] font-bold text-emerald-600 uppercase">Disponível</p>
              <p className="text-lg font-bold text-emerald-800">{fleetStats.available}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-blue-50 border border-blue-100">
            <div className="w-8 h-8 rounded-lg bg-blue-500 flex items-center justify-center text-white"><i className="fas fa-route"></i></div>
            <div>
              <p className="text-[10px] font-bold text-blue-600 uppercase">Em Uso</p>
              <p className="text-lg font-bold text-blue-800">{fleetStats.inUse}</p>
            </div>
          </div>
          <div className="flex items-center gap-3 p-3 rounded-xl bg-red-50 border border-red-100">
            <div className="w-8 h-8 rounded-lg bg-red-500 flex items-center justify-center text-white"><i className="fas fa-wrench"></i></div>
            <div>
              <p className="text-[10px] font-bold text-red-600 uppercase">Manutenção</p>
              <p className="text-lg font-bold text-red-800">{fleetStats.maintenance}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Veículos Totais', value: vehicles.length, icon: 'fa-truck', color: 'bg-blue-500' },
          { label: 'Ocorrências', value: occurrences.length, icon: 'fa-triangle-exclamation', color: 'bg-orange-500' },
          { label: 'Viagens Ativas', value: activeTrips.length, icon: 'fa-play', color: 'bg-green-500' },
          { label: 'Alertas Ativos', value: notifications.filter(n => !n.isRead).length, icon: 'fa-exclamation-triangle', color: 'bg-orange-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center gap-4">
            <div className={`${stat.color} w-12 h-12 rounded-lg flex items-center justify-center text-white shadow-lg shadow-slate-200`}>
              <i className={`fas ${stat.icon} text-xl`}></i>
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Quilometragem por Veículo</h3>
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={kmData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <YAxis axisLine={false} tickLine={false} style={{ fontSize: '12px' }} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                  <Bar dataKey="km" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-6 rounded-xl text-white shadow-xl shadow-blue-900/10">
            <div className="flex items-center gap-3 mb-4">
              <div className="bg-white/20 p-2 rounded-lg"><i className="fas fa-brain text-xl"></i></div>
              <h3 className="text-lg font-bold">Insights de Gestão IA (Gemini)</h3>
            </div>
            <div className="bg-white/10 backdrop-blur-sm p-4 rounded-lg border border-white/20">
              <p className="text-blue-50 leading-relaxed whitespace-pre-wrap italic">"{aiInsights}"</p>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-bold">Ocorrências Recentes</h3>
              <i className="fas fa-history text-slate-300"></i>
            </div>
            <div className="space-y-3">
              {recentOccurrences.length > 0 ? (
                recentOccurrences.map(occ => (
                  <div key={occ.id} className={`p-3 border-l-4 rounded-r-lg group hover:bg-slate-50 transition-all ${
                    occ.severity === OccurrenceSeverity.HIGH ? 'border-red-500 bg-red-50/30' : 
                    occ.severity === OccurrenceSeverity.MEDIUM ? 'border-orange-500 bg-orange-50/30' : 'border-blue-500 bg-blue-50/30'
                  }`}>
                    <div className="flex justify-between items-start">
                      <p className="text-xs font-bold text-slate-800">{occ.type}</p>
                      <span className="text-[8px] font-bold text-slate-400">{new Date(occ.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-1">{occ.description}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <p className="text-xs font-medium italic">Nenhuma ocorrência registrada.</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-4">Alertas Críticos</h3>
            <div className="space-y-3">
              {activeAlerts.length > 0 ? (
                activeAlerts.map(alert => (
                  <div key={alert.id} className="p-3 bg-slate-50 border-l-4 border-orange-500 rounded-r-lg">
                    <p className="text-xs font-bold text-slate-800">{alert.title}</p>
                    <p className="text-[10px] text-slate-500 mt-0.5 line-clamp-2">{alert.message}</p>
                  </div>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 border-2 border-dashed border-slate-50 rounded-lg">
                  <i className="fas fa-check-circle text-xl mb-2 text-green-200"></i>
                  <p className="text-xs font-medium italic">Nenhum alerta ativo.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardOverview;

import React, { useState, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { ScheduledTrip, Vehicle } from '../types';
import { checkSPRodizio, getRodizioDayLabel } from '../utils/trafficRules';

const SchedulingPage: React.FC = () => {
  const { drivers, vehicles, scheduledTrips, addScheduledTrip, deleteScheduledTrip } = useFleet();
  const [showForm, setShowForm] = useState(false);
  const [newSchedule, setNewSchedule] = useState({
    driverId: '',
    vehicleId: '',
    scheduledDate: new Date().toISOString().split('T')[0],
    origin: '',
    destination: '',
    city: '',
    notes: ''
  });

  const selectedVehicle = vehicles.find(v => v.id === newSchedule.vehicleId);

  // Cálculo preciso do rodízio evitando deslocamento de fuso horário
  const isRestricted = useMemo(() => {
    if (!selectedVehicle || !newSchedule.scheduledDate) return false;
    const [year, month, day] = newSchedule.scheduledDate.split('-').map(Number);
    const dateObj = new Date(year, month - 1, day); // Mês é base 0
    return checkSPRodizio(selectedVehicle.plate, dateObj);
  }, [selectedVehicle, newSchedule.scheduledDate]);

  const handleOpenMaps = () => {
    if (!newSchedule.destination) return;
    const query = encodeURIComponent(`${newSchedule.destination}${newSchedule.city ? ', ' + newSchedule.city : ''}`);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const handleAddSchedule = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newSchedule.driverId || !newSchedule.vehicleId || !newSchedule.destination) return;

    const trip: ScheduledTrip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: newSchedule.driverId,
      vehicleId: newSchedule.vehicleId,
      scheduledDate: newSchedule.scheduledDate,
      origin: newSchedule.origin,
      destination: newSchedule.destination,
      city: newSchedule.city,
      notes: newSchedule.notes
    };

    addScheduledTrip(trip);
    setNewSchedule({
      driverId: '',
      vehicleId: '',
      scheduledDate: new Date().toISOString().split('T')[0],
      origin: '',
      destination: '',
      city: '',
      notes: ''
    });
    setShowForm(false);
    alert('Viagem agendada com sucesso!');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Agenda de Viagens</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-200 transition-all"
        >
          <i className={`fas ${showForm ? 'fa-times' : 'fa-calendar-plus'}`}></i>
          {showForm ? 'Cancelar' : 'Agendar Viagem'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleAddSchedule} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Motorista</label>
                <select
                  required
                  value={newSchedule.driverId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, driverId: e.target.value })}
                  className="w-full p-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950"
                >
                  <option value="">Selecione o condutor...</option>
                  {drivers.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Veículo</label>
                <select
                  required
                  value={newSchedule.vehicleId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, vehicleId: e.target.value })}
                  className={`w-full p-3 bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950 transition-all ${isRestricted ? 'border-amber-400' : 'border-slate-200'}`}
                >
                  <option value="">Selecione o veículo...</option>
                  {vehicles.map(v => (
                    <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Data da Viagem</label>
                <input
                  required
                  type="date"
                  value={newSchedule.scheduledDate}
                  onChange={(e) => setNewSchedule({ ...newSchedule, scheduledDate: e.target.value })}
                  className={`w-full p-3 bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950 transition-all ${isRestricted ? 'border-amber-400 ring-2 ring-amber-100 animate-pulse' : 'border-slate-200'}`}
                />
              </div>
            </div>

            {/* Alerta de Rodízio de SP */}
            {isRestricted && (
              <div className="bg-amber-50 border-2 border-amber-500/50 p-5 rounded-2xl flex items-start gap-4 animate-in slide-in-from-left-4 duration-500">
                <div className="w-12 h-12 bg-amber-500 text-white rounded-xl flex items-center justify-center text-xl font-black shrink-0 shadow-lg shadow-amber-200">
                  <i className="fas fa-exclamation-triangle"></i>
                </div>
                <div>
                  <h4 className="font-black text-amber-900 uppercase text-xs tracking-[0.2em] mb-1">Atenção: Rodízio Ativo</h4>
                  <p className="text-sm text-amber-800 font-medium leading-relaxed">
                    Este veículo (<span className="font-bold underline">{selectedVehicle?.plate}</span>) está sujeito ao rodízio em São Paulo às <span className="bg-amber-200 px-1.5 py-0.5 rounded font-black">{getRodizioDayLabel(selectedVehicle?.plate || '')}s</span>. 
                    Verifique se o trajeto ocorrerá entre <span className="font-bold">7h-10h</span> ou <span className="font-bold">17h-20h</span> para evitar infrações.
                  </p>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Origem</label>
                <input
                  placeholder="Ex: Garagem Central"
                  value={newSchedule.origin}
