                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                        <i className="fas fa-truck text-xl"></i>
                      </div>
                      <div className="flex-1">
                        <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                        <p className="text-sm text-slate-500">{v.brand} {v.model}</p>
                      </div>
                    </div>
                    <div className="flex justify-between items-end border-t border-slate-100 pt-3 mt-1">
                      <p className="text-xs text-slate-400">{v.currentKm.toLocaleString()} km</p>
