import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, addVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);

  // Filter State
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Maintenance Form State
  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    notes: ''
  });

  // Vehicle Form State
  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100'
  });

  const handleSubmitMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.vehicleId || !newRecord.serviceType || !newRecord.cost) return;

    const record: MaintenanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: newRecord.serviceType,
      cost: parseFloat(newRecord.cost),
      notes: newRecord.notes
    };

    addMaintenanceRecord(record);
    setNewRecord({
      vehicleId: '',
      date: new Date().toISOString().split('T')[0],
      serviceType: '',
      cost: '',
      notes: ''
    });
    setShowMaintenanceForm(false);
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    const vehicle: Vehicle = {
      id: Math.random().toString(36).substr(2, 9),
      plate: newVehicle.plate.toUpperCase(),
      brand: newVehicle.brand,
      model: newVehicle.model,
      year: parseInt(newVehicle.year),
      currentKm: parseInt(newVehicle.currentKm) || 0,
      fuelLevel: parseInt(newVehicle.fuelLevel),
      status: VehicleStatus.AVAILABLE
    };

    addVehicle(vehicle);
    setNewVehicle({
      plate: '',
      brand: '',
      model: '',
      year: new Date().getFullYear().toString(),
      currentKm: '',
      fuelLevel: '100'
    });
    setShowVehicleForm(false);
    alert('Veículo cadastrado com sucesso!');
  };

  // Filtering Logic
  const filteredVehicles = vehicles.filter(vehicle => {
    const matchesSearch = 
      vehicle.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
      vehicle.brand.toLowerCase().includes(searchTerm.toLowerCase()) ||
      vehicle.plate.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'ALL' || vehicle.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={() => {
              setShowMaintenanceForm(!showMaintenanceForm);
              setShowVehicleForm(false);
            }}
            className="bg-slate-800 text-white px-4 py-2 rounded-lg font-bold hover:bg-slate-700 flex items-center gap-2 transition-all"
          >
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i>
            {showMaintenanceForm ? 'Cancelar' : 'Registrar Manutenção'}
          </button>
          <button 
            onClick={() => {
              setShowVehicleForm(!showVehicleForm);
              setShowMaintenanceForm(false);
            }}
            className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200 transition-all"
          >
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i>
            {showVehicleForm ? 'Cancelar' : 'Novo Veículo'}
          </button>
