          scheduledTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const [y, m, d] = trip.scheduledDate.split('-').map(Number);
            const tripDate = new Date(y, m - 1, d);
            const restricted = vehicle && checkSPRodizio(vehicle.plate, tripDate);

            return (
              <div key={trip.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center gap-6 hover:shadow-md transition-all relative overflow-hidden">
                {restricted && <div className="absolute top-0 left-0 w-1 h-full bg-amber-500"></div>}

                <div className="w-full md:w-32 flex flex-col items-center justify-center p-3 bg-slate-50 rounded-xl border border-slate-100 shrink-0">
                  <span className="text-2xl font-black text-slate-800">{tripDate.getDate()}</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{tripDate.toLocaleDateString('pt-BR', { month: 'short' })}</span>
                </div>

                <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Motorista</p>
                    <p className="font-bold text-slate-800">{driver?.name}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Veículo</p>
                    <p className="font-bold text-indigo-600">{vehicle?.plate} {restricted && '⚠️'}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Destino</p>
                    <p className="font-bold text-slate-800">{trip.destination}</p>
                  </div>
                </div>

                <button onClick={() => deleteScheduledTrip(trip.id)} className="w-10 h-10 rounded-full bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-100 transition-colors">
                  <i className="fas fa-trash-alt"></i>
                </button>
              </div>
            );
          })
        ) : (
          <div className="py-12 text-center bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <p className="text-slate-400 font-medium italic">Nenhuma viagem agendada.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SchedulingPage;

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, addVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    notes: ''
  });

  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100'
  });

  const handleSubmitMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.vehicleId || !newRecord.serviceType || !newRecord.cost) return;

    const record: MaintenanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: newRecord.serviceType,
      cost: parseFloat(newRecord.cost),
      notes: newRecord.notes
    };

    addMaintenanceRecord(record);
    setNewRecord({ vehicleId: '', date: new Date().toISOString().split('T')[0], serviceType: '', cost: '', notes: '' });
    setShowMaintenanceForm(false);
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    const vehicle: Vehicle = {
      id: Math.random().toString(36).substr(2, 9),
      plate: newVehicle.plate.toUpperCase(),
      brand: newVehicle.brand,
      model: newVehicle.model,
      year: parseInt(newVehicle.year),
      currentKm: parseInt(newVehicle.currentKm) || 0,
      fuelLevel: parseInt(newVehicle.fuelLevel),
      status: VehicleStatus.AVAILABLE
    };

    addVehicle(vehicle);
    setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100' });
    setShowVehicleForm(false);
  };

  const filteredVehicles = vehicles.filter(v => {
    const matchesSearch = v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || v.model.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
        <div className="flex flex-wrap gap-2">
          <button onClick={() => setShowMaintenanceForm(!showMaintenanceForm)} className="bg-slate-800 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2">
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i> Manutenção
          </button>
          <button onClick={() => setShowVehicleForm(!showVehicleForm)} className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 shadow-lg shadow-blue-200">
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i> Novo Veículo
          </button>
        </div>
      </div>

      {showVehicleForm && (
        <form onSubmit={handleSubmitVehicle} className="bg-white p-6 rounded-xl shadow-md border-l-4 border-blue-600 grid grid-cols-1 md:grid-cols-3 gap-6">
          <input required placeholder="Placa" value={newVehicle.plate} onChange={(e) => setNewVehicle({ ...newVehicle, plate: e.target.value })} className="p-3 border rounded-lg text-slate-950 font-bold" />
          <input required placeholder="Marca" value={newVehicle.brand} onChange={(e) => setNewVehicle({ ...newVehicle, brand: e.target.value })} className="p-3 border rounded-lg text-slate-950 font-bold" />
          <input required placeholder="Modelo" value={newVehicle.model} onChange={(e) => setNewVehicle({ ...newVehicle, model: e.target.value })} className="p-3 border rounded-lg text-slate-950 font-bold" />
          <button type="submit" className="bg-blue-600 text-white py-3 rounded-lg font-bold md:col-span-3">Cadastrar</button>
        </form>
      )}

      {showMaintenanceForm && (
        <form onSubmit={handleSubmitMaintenance} className="bg-white p-6 rounded-xl shadow-md border-l-4 border-slate-800 grid grid-cols-1 md:grid-cols-2 gap-6">
          <select required value={newRecord.vehicleId} onChange={(e) => setNewRecord({ ...newRecord, vehicleId: e.target.value })} className="p-3 border rounded-lg text-slate-950 font-bold">
            <option value="">Selecione o veículo...</option>
            {vehicles.map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
          </select>
          <input required type="text" placeholder="Tipo de Serviço" value={newRecord.serviceType} onChange={(e) => setNewRecord({ ...newRecord, serviceType: e.target.value })} className="p-3 border rounded-lg text-slate-950 font-bold" />
          <button type="submit" className="bg-slate-900 text-white py-3 rounded-lg font-bold md:col-span-2">Salvar</button>
        </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredVehicles.map(vehicle => (
          <div key={vehicle.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex justify-between items-start mb-4">
              <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-lg font-mono text-xs font-bold">{vehicle.plate}</span>
              <span className={`text-[10px] font-black px-2 py-1 rounded-full uppercase ${vehicle.status === VehicleStatus.AVAILABLE ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                {vehicle.status}
              </span>
            </div>
            <h4 className="font-bold text-slate-800">{vehicle.brand} {vehicle.model}</h4>
            <div className="mt-4 flex justify-between text-xs text-slate-400">
              <span>{vehicle.currentKm.toLocaleString()} KM</span>
              <span>Ano {vehicle.year}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FleetManager;

