import React, { useState, useEffect } from 'react';
import { FleetProvider, useFleet } from './context/FleetContext';
import Layout from './components/Layout';
import DashboardOverview from './components/DashboardOverview';
import FleetManager from './pages/FleetManager';
import DriverManagement from './pages/DriverManagement';
import OperationWizard from './pages/OperationWizard';
import TripMonitoring from './pages/TripMonitoring';
import SchedulingPage from './pages/SchedulingPage';
import ReportsPage from './pages/ReportsPage';
import Login from './pages/Login';

const AppContent: React.FC = () => {
  const { currentUser } = useFleet();
  const [activeTab, setActiveTab] = useState('dashboard');

  const isAdmin = currentUser?.username === 'admin';

  useEffect(() => {
    const restrictedTabs = ['fleet', 'drivers', 'scheduling', 'monitoring', 'reports'];
    if (!isAdmin && restrictedTabs.includes(activeTab)) {
      setActiveTab('dashboard');
    }
  }, [activeTab, isAdmin]);

  if (!currentUser) {
    return <Login />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <DashboardOverview />;
      case 'fleet':
        return isAdmin ? <FleetManager /> : <DashboardOverview />;
      case 'drivers':
        return isAdmin ? <DriverManagement /> : <DashboardOverview />;
      case 'operation':
        return <OperationWizard />;
      case 'monitoring':
        return isAdmin ? <TripMonitoring /> : <DashboardOverview />;
      case 'scheduling':
        return isAdmin ? <SchedulingPage /> : <DashboardOverview />;
      case 'reports':
        return isAdmin ? <ReportsPage /> : <DashboardOverview />;
      default:
        return <DashboardOverview />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FleetProvider>
      <AppContent />
    </FleetProvider>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type ReportType = 'trips' | 'consumption' | 'fines' | 'management';

const ReportsPage: React.FC = () => {
  const { vehicles, drivers, completedTrips, fines, maintenanceRecords, checklists } = useFleet();
  const [activeReport, setActiveReport] = useState<ReportType>('trips');

  // Date Filters
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 30);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);

  // Data filtering logic
  const filteredTrips = useMemo(() => {
    return completedTrips.filter(t => {
      const tripDate = t.startTime.split('T')[0];
      return tripDate >= startDate && tripDate <= endDate;
    });
  }, [completedTrips, startDate, endDate]);

  const filteredFines = useMemo(() => {
    return fines.filter(f => f.date >= startDate && f.date <= endDate);
  }, [fines, startDate, endDate]);

  const filteredMaintenance = useMemo(() => {
    return maintenanceRecords.filter(m => m.date >= startDate && m.date <= endDate);
  }, [maintenanceRecords, startDate, endDate]);

  // Report 1: Trip Volume Data
  const tripChartData = useMemo(() => {
    const stats = drivers.map(d => {
      const count = filteredTrips.filter(t => t.driverId === d.id).length;
      return { name: d.name.split(' ')[0], viagens: count };
    }).filter(s => s.viagens > 0);
    return stats;
  }, [drivers, filteredTrips]);

  // Report 2: Fuel Consumption Data (Simulated calculation based on checklists)
  const consumptionData = useMemo(() => {
    return vehicles.map(v => {
      const efficiency = v.model.includes('Sprinter') ? 11.5 : v.model.includes('Hilux') ? 8.2 : 10.0;
      // In a real app, this would use (lastKM - firstKM) / totalFuelSpent
      return { 
        id: v.id, 
        plate: v.plate, 
        model: v.model, 
        avg: parseFloat((efficiency + (Math.random() * 1.5 - 0.75)).toFixed(1)) 
      };
    }).sort((a, b) => b.avg - a.avg);
  }, [vehicles]);

  // Report 3: Fines Per Driver
  const finesPerDriver = useMemo(() => {
    return drivers.map(d => {
      const driverFines = filteredFines.filter(f => f.driverId === d.id);
      const totalValue = driverFines.reduce((sum, f) => sum + f.value, 0);
      const totalPoints = driverFines.reduce((sum, f) => sum + f.points, 0);
      return { 
        id: d.id, 
        name: d.name, 
        count: driverFines.length, 
        value: totalValue, 
        points: totalPoints 
      };
    }).filter(s => s.count > 0);
  }, [drivers, filteredFines]);

  // Report 4: Management Summary
  const managementSummary = useMemo(() => {
    const totalDist = filteredTrips.reduce((sum, t) => sum + (t.distance || 0), 0);
    const totalMaintCost = filteredMaintenance.reduce((sum, m) => sum + m.cost, 0);
    const totalFineCost = filteredFines.reduce((sum, f) => sum + f.value, 0);
    const mostActiveVehicle = vehicles.reduce((prev, curr) => {
      const prevCount = filteredTrips.filter(t => t.vehicleId === prev.id).length;
      const currCount = filteredTrips.filter(t => t.vehicleId === curr.id).length;
      return currCount > prevCount ? curr : prev;
    }, vehicles[0]);

    return { totalDist, totalMaintCost, totalFineCost, mostActiveVehicle };
  }, [filteredTrips, filteredMaintenance, filteredFines, vehicles]);

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Centro de Relatórios</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Análise de Performance e Custos</p>
        </div>

        {/* Period Filter Panel */}
        <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-400 uppercase mb-1">Início</span>
            <input 
              type="date" 
              value={startDate} 
              onChange={(e) => setStartDate(e.target.value)}
              className="bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-950 outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-400 uppercase mb-1">Fim</span>
            <input 
              type="date" 
              value={endDate} 
              onChange={(e) => setEndDate(e.target.value)}
              className="bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-950 outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <button className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 mt-4">
            <i className="fas fa-sync-alt text-xs"></i>
          </button>
        </div>
      </div>

      {/* Tabs Submenu */}
      <div className="flex overflow-x-auto gap-2 p-1 bg-slate-100 rounded-2xl w-fit">
        {[
          { id: 'trips', label: 'Viagens', icon: 'fa-route' },
          { id: 'consumption', label: 'Consumo', icon: 'fa-gas-pump' },
          { id: 'fines', label: 'Multas', icon: 'fa-gavel' },
          { id: 'management', label: 'Gerencial', icon: 'fa-briefcase' },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveReport(tab.id as ReportType)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${
              activeReport === tab.id 
              ? 'bg-white text-blue-600 shadow-sm' 
              : 'text-slate-400 hover:text-slate-600'
            }`}
          >
            <i className={`fas ${tab.icon}`}></i>
            {tab.label}
          </button>
        ))}
      </div>

      {/* Report Content */}
      <div className="grid grid-cols-1 gap-8 animate-in fade-in duration-500">

        {/* REPORT: TRIPS */}
        {activeReport === 'trips' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Volume de Viagens por Condutor</h3>
              <div className="h-80 w-full">
                {tripChartData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={tripChartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                      <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                      <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Bar dataKey="viagens" fill="#3b82f6" radius={[6, 6, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex items-center justify-center text-slate-300 italic font-medium">Nenhum dado no período selecionado</div>
                )}
              </div>
            </div>
            <div className="bg-slate-900 rounded-3xl p-8 text-white flex flex-col justify-between shadow-2xl">
              <div>
                <i className="fas fa-info-circle text-blue-400 text-2xl mb-4"></i>
                <h4 className="text-lg font-black uppercase mb-4">Sumário de Viagens</h4>
                <div className="space-y-6">
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Total de Viagens</p>
                    <p className="text-4xl font-black tracking-tighter">{filteredTrips.length}</p>
                  </div>
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">KM Rodados no Período</p>
                    <p className="text-3xl font-black tracking-tighter">{managementSummary.totalDist.toLocaleString()} km</p>
                  </div>
                </div>
              </div>
              <p className="text-[10px] text-slate-500 font-medium leading-relaxed mt-8">Os dados acima referem-se exclusivamente às viagens concluídas no intervalo selecionado.</p>
            </div>
          </div>
        )}

        {/* REPORT: CONSUMPTION */}
        {activeReport === 'consumption' && (
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">Ranking de Eficiência de Combustível (Média km/L)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {consumptionData.map((v, i) => (
                <div key={v.id} className="bg-slate-50 border border-slate-100 p-6 rounded-2xl relative overflow-hidden group">
                  <div className={`absolute top-0 right-0 w-24 h-24 -mr-8 -mt-8 rounded-full opacity-10 ${i === 0 ? 'bg-emerald-500' : 'bg-slate-400'}`}></div>
                  <div className="flex justify-between items-start mb-4">
                    <span className="bg-white px-3 py-1 rounded-lg text-[10px] font-mono font-bold border border-slate-100 shadow-sm">{v.plate}</span>
                    {i === 0 && <i className="fas fa-trophy text-amber-500 animate-bounce"></i>}
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">{v.model}</p>
                  <p className="text-3xl font-black text-slate-800 tracking-tighter">{v.avg} <span className="text-xs text-slate-400 font-bold">km/L</span></p>
                  <div className="mt-4 h-1.5 w-full bg-slate-200 rounded-full overflow-hidden">
                    <div className={`h-full ${i === 0 ? 'bg-emerald-500' : 'bg-blue-500'}`} style={{ width: `${(v.avg / 13) * 100}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* REPORT: FINES */}
        {activeReport === 'fines' && (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-8 border-b border-slate-50">
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Resumo de Multas por Condutor</h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50">
                  <tr>
                    <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Motorista</th>
                    <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Qtde Multas</th>
                    <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Pontos Acumulados</th>
                    <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor Total (R$)</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {finesPerDriver.length > 0 ? (
                    finesPerDriver.map(row => (
                      <tr key={row.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 font-bold text-slate-800">{row.name}</td>
                        <td className="px-8 py-5 text-center font-bold text-slate-600">{row.count}</td>
                        <td className="px-8 py-5 text-center">
                          <span className={`px-3 py-1 rounded-full text-[10px] font-black ${row.points > 10 ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-600'}`}>
                            {row.points} pts
                          </span>
                        </td>
                        <td className="px-8 py-5 text-right font-black text-slate-900">R$ {row.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={4} className="px-8 py-20 text-center text-slate-300 italic font-medium">Nenhuma infração registrada no período.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* REPORT: MANAGEMENT */}
        {activeReport === 'management' && (
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
               {[
                 { label: 'Custo Manutenção', value: `R$ ${managementSummary.totalMaintCost.toLocaleString()}`, icon: 'fa-wrench', color: 'text-blue-600', bg: 'bg-blue-50' },
                 { label: 'Custo Multas', value: `R$ ${managementSummary.totalFineCost.toLocaleString()}`, icon: 'fa-gavel', color: 'text-red-600', bg: 'bg-red-50' },
                 { label: 'Distância Total', value: `${managementSummary.totalDist} KM`, icon: 'fa-road', color: 'text-emerald-600', bg: 'bg-emerald-50' },
                 { label: 'Ocorrências', value: '4 Registros', icon: 'fa-exclamation-triangle', color: 'text-orange-600', bg: 'bg-orange-50' },
               ].map((card, i) => (
                 <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4">
                    <div className={`w-12 h-12 ${card.bg} ${card.color} rounded-2xl flex items-center justify-center text-xl`}>
                      <i className={`fas ${card.icon}`}></i>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{card.label}</p>
                      <p className="text-lg font-black text-slate-900">{card.value}</p>
                    </div>
                 </div>
               ))}
            </div>

            <div className="bg-white p-10 rounded-3xl shadow-sm border border-slate-100 grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div>
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Distribuição de Custos Operacionais</h3>
                <div className="h-64">
                   <ResponsiveContainer width="100%" height="100%">
                     <PieChart>
                       <Pie
                         data={[
                           { name: 'Manutenção', value: managementSummary.totalMaintCost },
                           { name: 'Multas', value: managementSummary.totalFineCost }
                         ]}
                         innerRadius={60}
                         outerRadius={80}
                         paddingAngle={5}
                         dataKey="value"
                       >
                         <Cell fill="#3b82f6" />
                         <Cell fill="#ef4444" />
                       </Pie>
                       <Tooltip />
                     </PieChart>
                   </ResponsiveContainer>
                </div>
                <div className="flex justify-center gap-6 mt-4">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 bg-blue-500 rounded-full"></div>
                    <span className="text-[10px] font-bold text-slate-500">MANUTENÇÃO</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 bg-red-500 rounded-full"></div>
                    <span className="text-[10px] font-bold text-slate-500">MULTAS</span>
                  </div>
                </div>
              </div>

              <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100 flex flex-col justify-center">
                <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
                  <i className="fas fa-star text-amber-500"></i> Destaque da Frota
                </h4>
                <div className="flex items-center gap-6">
                  <div className="w-20 h-20 bg-white rounded-3xl shadow-sm border border-slate-200 flex items-center justify-center text-3xl text-slate-300">
                    <i className="fas fa-truck-pickup"></i>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Veículo mais produtivo</p>
                    <p className="text-2xl font-black text-slate-900">{managementSummary.mostActiveVehicle?.plate || '--'}</p>
                    <p className="text-xs font-bold text-slate-500">{managementSummary.mostActiveVehicle?.brand} {managementSummary.mostActiveVehicle?.model}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ReportsPage;

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, addVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    notes: ''
  });

  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100'
  });

  const handleSubmitMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.vehicleId || !newRecord.serviceType || !newRecord.cost) return;

    const record: MaintenanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: newRecord.serviceType,
      cost: parseFloat(newRecord.cost),
      notes: newRecord.notes
    };

    addMaintenanceRecord(record);
    setNewRecord({ vehicleId: '', date: new Date().toISOString().split('T')[0], serviceType: '', cost: '', notes: '' });
    setShowMaintenanceForm(false);
    alert('Manutenção registrada com sucesso!');
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    const vehicle: Vehicle = {
      id: Math.random().toString(36).substr(2, 9),
      plate: newVehicle.plate.toUpperCase(),
      brand: newVehicle.brand,
      model: newVehicle.model,
      year: parseInt(newVehicle.year),
      currentKm: parseInt(newVehicle.currentKm) || 0,
      fuelLevel: parseInt(newVehicle.fuelLevel),
      status: VehicleStatus.AVAILABLE
    };

    addVehicle(vehicle);
    setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100' });
    setShowVehicleForm(false);
    alert('Veículo cadastrado com sucesso!');
  };

  const filteredVehicles = vehicles.filter(v => {
    const matchesSearch = v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || v.model.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Controle de Ativos e Manutenções</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={() => {
              setShowMaintenanceForm(!showMaintenanceForm);
              setShowVehicleForm(false);
            }} 
            className="bg-slate-800 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-700 transition-all"
          >
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i> 
            {showMaintenanceForm ? 'Cancelar' : 'Registrar Manutenção'}
          </button>
          <button 
            onClick={() => {
              setShowVehicleForm(!showVehicleForm);
              setShowMaintenanceForm(false);
            }} 
            className="bg-blue-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all"
          >
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i> 
            {showVehicleForm ? 'Cancelar' : 'Novo Veículo'}
          </button>
        </div>
      </div>

      {/* Forms Section */}
      <div className="space-y-4">
        {showVehicleForm && (
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Cadastro de Veículo</h3>
            <form onSubmit={handleSubmitVehicle} className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Placa</label>
                <input required placeholder="ABC-1234" value={newVehicle.plate} onChange={(e) => setNewVehicle({ ...newVehicle, plate: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Marca</label>
                <input required placeholder="Ex: Mercedes-Benz" value={newVehicle.brand} onChange={(e) => setNewVehicle({ ...newVehicle, brand: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Modelo</label>
                <input required placeholder="Ex: Sprinter 415" value={newVehicle.model} onChange={(e) => setNewVehicle({ ...newVehicle, model: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <button type="submit" className="bg-blue-600 text-white py-4 rounded-xl font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all md:col-span-3">Salvar Veículo</button>
            </form>
          </div>
        )}

        {showMaintenanceForm && (
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Registrar Manutenção Técnica</h3>
            <form onSubmit={handleSubmitMaintenance} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Veículo Destinado</label>
                <select required value={newRecord.vehicleId} onChange={(e) => setNewRecord({ ...newRecord, vehicleId: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value="">Selecione o veículo...</option>
                  {vehicles.map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Tipo de Serviço</label>
                <input required type="text" placeholder="Ex: Troca de pastilhas de freio" value={newRecord.serviceType} onChange={(e) => setNewRecord({ ...newRecord, serviceType: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Custo Estimado (R$)</label>
                <input required type="number" step="0.01" placeholder="0.00" value={newRecord.cost} onChange={(e) => setNewRecord({ ...newRecord, cost: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Data do Serviço</label>
                <input required type="date" value={newRecord.date} onChange={(e) => setNewRecord({ ...newRecord, date: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <button type="submit" className="bg-slate-900 text-white py-4 rounded-xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all md:col-span-2">Confirmar Manutenção</button>
            </form>
          </div>
        )}
      </div>

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex-1 relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
          <input 
            type="text" 
            placeholder="Buscar por placa ou modelo..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-950 focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>
        <select 
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-black text-slate-700 uppercase outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="ALL">Todos os Status</option>
          <option value={VehicleStatus.AVAILABLE}>Disponível</option>
          <option value={VehicleStatus.IN_USE}>Em Uso</option>
          <option value={VehicleStatus.MAINTENANCE}>Manutenção</option>
        </select>
      </div>

      {/* Vehicle Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredVehicles.map(vehicle => {
          const vehicleMaintenances = maintenanceRecords
            .filter(m => m.vehicleId === vehicle.id)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

          return (
            <div key={vehicle.id} className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden flex flex-col hover:shadow-md transition-all">
              <div className="p-6 border-b border-slate-50">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex flex-col gap-1">
                    <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-mono text-xs font-black shadow-sm tracking-widest">{vehicle.plate}</span>
                    <p className="text-[10px] font-black text-slate-400 uppercase">{vehicle.brand}</p>
                  </div>
                  <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border-2 ${
                    vehicle.status === VehicleStatus.AVAILABLE ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                    vehicle.status === VehicleStatus.IN_USE ? 'bg-blue-50 text-blue-600 border-blue-100' : 
                    'bg-red-50 text-red-600 border-red-100'
                  }`}>
                    {vehicle.status === VehicleStatus.AVAILABLE ? 'Livre' : vehicle.status === VehicleStatus.IN_USE ? 'Em Rota' : 'Oficina'}
                  </span>
                </div>
                <h4 className="text-lg font-black text-slate-800 tracking-tight">{vehicle.model}</h4>
                <div className="mt-4 grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Odômetro</p>
                    <p className="text-sm font-black text-slate-800">{vehicle.currentKm.toLocaleString()} KM</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Fabricação</p>
                    <p className="text-sm font-black text-slate-800">Ano {vehicle.year}</p>
                  </div>
                </div>
              </div>

              {/* Maintenance History Section */}
              <div className="p-6 flex-1 bg-slate-50/50">
                <div className="flex items-center justify-between mb-4">
                  <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <i className="fas fa-history"></i> Histórico de Manutenções
                  </h5>
                  <span className="text-[9px] font-bold text-slate-300">{vehicleMaintenances.length} registros</span>
                </div>

                <div className="space-y-3 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                  {vehicleMaintenances.length > 0 ? (
                    vehicleMaintenances.map(m => (
                      <div key={m.id} className="bg-white p-3 rounded-2xl border border-slate-100 shadow-sm group hover:border-blue-200 transition-colors">
                        <div className="flex justify-between items-start">
                          <p className="text-xs font-black text-slate-900 leading-tight mb-1">{m.serviceType}</p>
                          <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded uppercase">R$ {m.cost.toFixed(2)}</span>
                        </div>
                        <div className="flex items-center justify-between mt-2">
                          <p className="text-[10px] text-slate-400 font-bold">{new Date(m.date).toLocaleDateString('pt-BR')}</p>
                          {m.notes && (
                            <i className="fas fa-comment-dots text-slate-200 group-hover:text-blue-300" title={m.notes}></i>
                          )}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="py-8 text-center border-2 border-dashed border-slate-200 rounded-3xl">
                      <p className="text-[10px] font-black text-slate-300 uppercase italic">Sem manutenções registradas</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="p-4 bg-white border-t border-slate-50">
                <button className="w-full py-2 bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-all">
                  Ver Ficha Completa
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default FleetManager;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  serviceType: string;
  cost: number;
  km: number; // Adicionado para rastreamento de revisões
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string; // Base64 image string
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  waypoints?: string[]; // Novos locais adicionados durante a rota
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  distance?: number;
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

export interface AppState {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence, ScheduledTrip } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  updateTrip: (tripId: string, updates: Partial<Trip>) => void;
  addScheduledTrip: (trip: ScheduledTrip) => void;
  deleteScheduledTrip: (id: string) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

const KM_MAINTENANCE_INTERVAL = 10000;
const KM_ALERT_THRESHOLD = 500;
const DAYS_MAINTENANCE_INTERVAL = 180;
const DAYS_ALERT_THRESHOLD = 15;

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [scheduledTrips, setScheduledTrips] = useState<ScheduledTrip[]>(() => {
    const saved = localStorage.getItem('fleet_scheduled_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [occurrences, setOccurrences] = useState<Occurrence[]>(() => {
    const saved = localStorage.getItem('fleet_occurrences');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
    checkMaintenanceAlerts();
  }, [vehicles, maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords));
  }, [maintenanceRecords]);

  useEffect(() => {
    localStorage.setItem('fleet_fines', JSON.stringify(fines));
  }, [fines]);

  useEffect(() => {
    localStorage.setItem('fleet_drivers', JSON.stringify(drivers));
  }, [drivers]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_scheduled_trips', JSON.stringify(scheduledTrips));
  }, [scheduledTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_checklists', JSON.stringify(checklists));
  }, [checklists]);

  useEffect(() => {
    localStorage.setItem('fleet_occurrences', JSON.stringify(occurrences));
  }, [occurrences]);

  const checkMaintenanceAlerts = useCallback(() => {
    const newNotifications: AppNotification[] = [];
    const now = new Date();

    vehicles.forEach(vehicle => {
      const vMaintenances = maintenanceRecords
        .filter(r => r.vehicleId === vehicle.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

      const lastRecord = vMaintenances[0];

      // Alerta por KM: Usa o KM da última manutenção como base, ou o múltiplo de 10k mais próximo
      let nextKmMaintenance;
      if (lastRecord && lastRecord.km) {
        nextKmMaintenance = lastRecord.km + KM_MAINTENANCE_INTERVAL;
      } else {
        nextKmMaintenance = Math.ceil((vehicle.currentKm + 1) / KM_MAINTENANCE_INTERVAL) * KM_MAINTENANCE_INTERVAL;
      }

      if (nextKmMaintenance - vehicle.currentKm <= KM_ALERT_THRESHOLD) {
        newNotifications.push({
          id: `km-${vehicle.id}-${nextKmMaintenance}`,
          type: 'maintenance_km',
          title: 'Manutenção por KM Próxima',
          message: `O veículo ${vehicle.plate} está chegando a ${nextKmMaintenance}km. Última revisão foi em ${lastRecord?.km || 'registro inicial'}km.`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }

      // Alerta por Data: 6 meses após a última revisão
      if (lastRecord) {
        const lastDate = new Date(lastRecord.date);
        const nextDate = new Date(lastDate);
        nextDate.setDate(lastDate.getDate() + DAYS_MAINTENANCE_INTERVAL);
        const diffTime = nextDate.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        if (diffDays <= DAYS_ALERT_THRESHOLD) {
          newNotifications.push({
            id: `date-${vehicle.id}-${nextDate.toISOString()}`,
            type: 'maintenance_date',
            title: 'Manutenção por Prazo Próxima',
            message: `O veículo ${vehicle.plate} deve passar por revisão em ${diffDays <= 0 ? 'breve' : diffDays + ' dias'} (intervalo de 6 meses).`,
            vehicleId: vehicle.id,
            timestamp: now.toISOString(),
            isRead: false
          });
        }
      }

      if (vehicle.fuelLevel < 15) {
        newNotifications.push({
          id: `fuel-${vehicle.id}`,
          type: 'low_fuel',
          title: 'Combustível Baixo',
          message: `O veículo ${vehicle.plate} está com nível crítico de combustível (${vehicle.fuelLevel}%).`,
          vehicleId: vehicle.id,
          timestamp: now.toISOString(),
          isRead: false
        });
      }
    });

    setNotifications(prev => {
      const activeNewIds = new Set(newNotifications.map(n => n.id));
      const filteredOld = prev.filter(n => {
        const isMaintenance = n.type === 'maintenance_km' || n.type === 'maintenance_date';
        // Se for uma manutenção antiga que não está mais na lista de ativos calculados, removemos
        if (isMaintenance && !activeNewIds.has(n.id)) return false;
        return true;
      });

      const currentIds = new Set(filteredOld.map(n => n.id));
      const trulyNew = newNotifications.filter(n => !currentIds.has(n.id));

      return [...trulyNew, ...filteredOld].slice(0, 50);
    });
  }, [vehicles, maintenanceRecords]);

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const addVehicle = (v: Vehicle) => setVehicles([...vehicles, v]);
  const addDriver = (d: Driver) => setDrivers([...drivers, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => {
    setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
    if (currentUser?.id === id) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const deleteDriver = (id: string) => {
    setDrivers(prev => prev.filter(d => d.id !== id));
    if (currentUser?.id === id) logout();
  };

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = () => setCurrentUser(null);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips([...activeTrips, trip]);
    setChecklists([...checklists, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const updateTrip = (tripId: string, updates: Partial<Trip>) => {
    setActiveTrips(prev => prev.map(t => t.id === tripId ? { ...t, ...updates } : t));
  };

  const addScheduledTrip = (trip: ScheduledTrip) => {
    setScheduledTrips(prev => [trip, ...prev]);
    setNotifications(prev => [{
      id: trip.id,
      type: 'schedule',
      title: 'Nova Viagem Agendada',
      message: `Uma nova viagem para ${trip.destination} foi agendada para o dia ${new Date(trip.scheduledDate).toLocaleDateString('pt-BR')}.`,
      vehicleId: trip.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteScheduledTrip = (id: string) => {
    setScheduledTrips(prev => prev.filter(t => t.id !== id));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const finishedTrip = { ...trip, endTime, distance: currentKm - (trip.distance || 0) }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
    // A limpeza de notificações antigas e o recálculo acontecem via useEffect disparado pela alteração em maintenanceRecords
  };

  const addFine = (fine: Fine) => {
    setFines(prev => [fine, ...prev]);
    setNotifications(prev => [{
      id: fine.id,
      type: 'new_fine',
      title: 'Nova Multa Registrada',
      message: `Uma nova multa foi registrada para o condutor no veículo ${vehicles.find(v => v.id === fine.vehicleId)?.plate}.`,
      vehicleId: fine.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  const deleteFine = (id: string) => {
    setFines(prev => prev.filter(f => f.id !== id));
  };

  const addOccurrence = (occ: Occurrence) => {
    setOccurrences(prev => [occ, ...prev]);
    setNotifications(prev => [{
      id: occ.id,
      type: 'occurrence',
      title: `Ocorrência: ${occ.type}`,
      message: `Nova ocorrência relatada pelo condutor ${drivers.find(d => d.id === occ.driverId)?.name} no veículo ${vehicles.find(v => v.id === occ.vehicleId)?.plate}.`,
      vehicleId: occ.vehicleId,
      timestamp: new Date().toISOString(),
      isRead: false
    }, ...prev]);
  };

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, scheduledTrips, checklists, maintenanceRecords, notifications, fines, occurrences,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, updateTrip, addScheduledTrip, deleteScheduledTrip, endTrip, cancelTrip, addMaintenanceRecord, addFine, deleteFine, addOccurrence, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, addVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    km: '', // Campo para o hodômetro no momento da manutenção
    notes: ''
  });

  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100'
  });

