import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle, Occurrence, OccurrenceSeverity } from '../types';
import { getOptimizedRoute } from '../services/geminiService';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, occurrences, endTrip, cancelTrip, addOccurrence } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [now, setNow] = useState(new Date());

  // Optimization State
  const [optimizingTripId, setOptimizingTripId] = useState<string | null>(null);
  const [optimizationResult, setOptimizationResult] = useState<{text: string, grounding: any[]} | null>(null);
  const [loadingOptimization, setLoadingOptimization] = useState(false);

  // Occurrence Modal State
  const [reportingTrip, setReportingTrip] = useState<Trip | null>(null);
  const [newOccurrence, setNewOccurrence] = useState({
    type: '',
    description: '',
    severity: OccurrenceSeverity.LOW
  });

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      // Captura o horário do dispositivo no exato momento da confirmação
      const deviceTime = new Date().toISOString();
      endTrip(finishingTripId, endKm, deviceTime);
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso! Horário de chegada registrado automaticamente.');
    }
  };

  const handleCancel = (tripId: string) => {
    if (confirm('ATENÇÃO: Deseja realmente cancelar esta operação? O veículo e o motorista serão liberados imediatamente.')) {
      cancelTrip(tripId);
    }
  };

  const handleOptimize = async (trip: Trip) => {
    setOptimizingTripId(trip.id);
    setLoadingOptimization(true);
    setOptimizationResult(null);
    try {
      const result = await getOptimizedRoute(trip.origin, trip.destination, trip.waypoints);
      setOptimizationResult(result);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingOptimization(false);
    }
  };

  const handleReportOccurrence = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reportingTrip || !newOccurrence.type || !newOccurrence.description) return;

    const occ: Occurrence = {
      id: Math.random().toString(36).substr(2, 9),
      tripId: reportingTrip.id,
      vehicleId: reportingTrip.vehicleId,
      driverId: reportingTrip.driverId,
      type: newOccurrence.type,
      description: newOccurrence.description,
      severity: newOccurrence.severity,
      timestamp: new Date().toISOString(),
      resolved: false
    };

    addOccurrence(occ);
    setReportingTrip(null);
    setNewOccurrence({ type: '', description: '', severity: OccurrenceSeverity.LOW });
    alert('Ocorrência registrada com sucesso.');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase shadow-sm">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);
            const tripOccurrences = occurrences.filter(o => o.tripId === trip.id);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all transform hover:-translate-y-1 relative">
                {tripOccurrences.length > 0 && (
                  <div className="absolute top-2 left-2 z-10 flex gap-1">
                    <span className="bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-full animate-bounce shadow-lg">
                      {tripOccurrences.length} Ocorrência(s)
                    </span>
                  </div>
                )}

                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs shadow-inner">
                      {vehicle?.plate}
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                      <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Saída</p>
                    <p className="text-xs font-medium">{new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                    {trip.plannedArrival && (
                      <span className="text-[10px] text-slate-400 font-medium">
                        ETA: {new Date(trip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white shadow-sm overflow-hidden ring-1 ring-slate-100">
                      {driver?.avatar ? (
                        <img src={driver.avatar} alt="" className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">
                          {driver?.name.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                      <p className="text-[10px] text-slate-500 uppercase font-medium">CNH: {driver?.license}</p>
