            <div className="p-8 space-y-6">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-3 tracking-widest">KM Atual (Hodômetro)</label>
                <div className="relative">
                  <i className="fas fa-gauge absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                  <input 
                    type="number"
                    value={endKm}
                    onChange={(e) => setEndKm(parseInt(e.target.value))}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none font-black text-lg text-slate-800 transition-all"
                    placeholder="000000"
                    autoFocus
                  />
                </div>
                <p className="text-[10px] text-slate-400 mt-3 font-bold uppercase text-center">Data e Horário serão registrados automaticamente pelo sistema</p>
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setFinishingTripId(null)} className="flex-1 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-colors">Voltar</button>
                <button onClick={confirmFinish} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Finalizar Agora</button>
