    </div>
  );
};

export default TripMonitoring;

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { getRouteInsights } from '../services/geminiService';
import { checkSPRodizio } from '../utils/trafficRules';

const OperationWizard: React.FC = () => {
  const { vehicles, currentUser, startTrip } = useFleet();
  const [step, setStep] = useState(1);

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: '',
    city: '',
    state: '',
    zipCode: '',
    plannedDeparture: new Date().toISOString().slice(0, 16), // Inicia com o horário do dispositivo
    plannedArrival: '',
    observations: ''
  });

  const [routeInfo, setRouteInfo] = useState<any>(null);
  const [loadingRoute, setLoadingRoute] = useState(false);

  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ 
        ...prev, 
        km: selectedVehicle.currentKm, 
        fuelLevel: selectedVehicle.fuelLevel,
        oilChecked: false,
        waterChecked: false,
        tiresChecked: false 
      }));
    }
  }, [selectedVehicle]);

  const isChecklistValid = 
    checklist.oilChecked && 
    checklist.waterChecked && 
    checklist.tiresChecked && 
    (checklist.km ?? 0) >= (selectedVehicle?.currentKm ?? 0);

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    // Captura o tempo real de início do dispositivo
    const deviceStartTime = new Date().toISOString();

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      city: route.city,
      state: route.state,
      zipCode: route.zipCode,
      plannedDeparture: route.plannedDeparture || deviceStartTime,
      plannedArrival: route.plannedArrival,
      startTime: deviceStartTime,
      observations: route.observations
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: deviceStartTime
    };

    startTrip(newTrip, finalChecklist);
    alert('Viagem iniciada! Tenha uma excelente jornada.');
    setStep(1);
    setSelectedVehicle(null);
    setRoute({
      origin: '',
      destination: '',
      city: '',
      state: '',
      zipCode: '',
      plannedDeparture: new Date().toISOString().slice(0, 16),
      plannedArrival: '',
      observations: ''
    });
  };

  const fetchRouteDetails = async () => {
    if (!route.origin || !route.destination) return;
    setLoadingRoute(true);
    const locationContext = `${route.destination}, ${route.city} - ${route.state}`;
    const info = await getRouteInsights(route.origin, locationContext);
    setRouteInfo(info);
    setLoadingRoute(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-4">
      {/* Stepper Header */}
      <div className="flex items-center justify-between mb-8 px-4">
        {[
          { step: 1, label: 'Veículo', icon: 'fa-truck-pickup' },
          { step: 2, label: 'Checklist', icon: 'fa-clipboard-check' },
          { step: 3, label: 'Rota', icon: 'fa-map-marked-alt' }
        ].map((s) => (
          <div key={s.step} className="flex flex-col items-center flex-1">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${
              step >= s.step ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white border-slate-200 text-slate-400'
            }`}>
              <i className={`fas ${s.icon}`}></i>
            </div>
            <span className={`text-[10px] mt-2 font-black uppercase tracking-wider ${step >= s.step ? 'text-blue-600' : 'text-slate-300'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        {step === 1 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Qual veículo você está pegando?</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => {
                const restrictedToday = checkSPRodizio(v.plate);
                return (
                  <button
                    key={v.id}
                    onClick={() => setSelectedVehicle(v)}
                    className={`p-6 rounded-2xl border-2 text-left transition-all flex flex-col gap-4 relative ${
                      selectedVehicle?.id === v.id ? 'border-blue-600 bg-blue-50 ring-4 ring-blue-100' : 'border-slate-100 hover:border-blue-200'
                    }`}
                  >
                    {restrictedToday && (
                       <div className="absolute top-2 right-2 flex items-center gap-1 bg-amber-500 text-black font-black text-[8px] px-1.5 py-0.5 rounded shadow-sm">
                         <i className="fas fa-exclamation-triangle"></i> RODÍZIO SP HOJE
                       </div>
                    )}
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                        <i className="fas fa-truck text-xl"></i>
                      </div>
                      <div className="flex-1">
                        <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                        <p className="text-xs text-slate-400 font-bold uppercase">{v.brand} {v.model}</p>
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
            <div className="mt-8 flex justify-end">
              <button
                disabled={!selectedVehicle}
                onClick={() => setStep(2)}
                className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-blue-700 disabled:opacity-50 transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-2">Checklist de Saída</h3>
            <p className="text-slate-400 text-xs font-bold uppercase mb-8">Veículo: <span className="text-blue-600 underline">{selectedVehicle?.plate}</span></p>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Quilometragem Inicial</label>
                  <input
                    type="number"
                    min={selectedVehicle?.currentKm}
                    value={checklist.km}
                    onChange={(e) => setChecklist({ ...checklist, km: parseInt(e.target.value) })}
                    className="w-full p-4 rounded-2xl border border-slate-200 font-black text-slate-800 text-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                  <p className="text-[10px] mt-2 text-slate-400 font-bold italic">Mínimo registrado: {selectedVehicle?.currentKm} km</p>
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Combustível</label>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={checklist.fuelLevel}
                    onChange={(e) => setChecklist({ ...checklist, fuelLevel: parseInt(e.target.value) })}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 mt-6"
                  />
                  <div className="flex justify-between text-[10px] font-black text-slate-400 mt-3 uppercase tracking-widest">
                    <span>Vazio</span>
                    <span className="text-blue-600 text-sm">{checklist.fuelLevel}%</span>
                    <span>Cheio</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4">
                {[
                  { key: 'oilChecked', label: 'Óleo', icon: 'fa-oil-can' },
                  { key: 'waterChecked', label: 'Água', icon: 'fa-tint' },
                  { key: 'tiresChecked', label: 'Pneus', icon: 'fa-car' }
                ].map(item => {
                  const isChecked = checklist[item.key as keyof Checklist];
                  return (
                    <button
                      key={item.key}
                      onClick={() => setChecklist({ ...checklist, [item.key]: !isChecked })}
                      className={`p-5 rounded-2xl border-2 flex flex-col items-center justify-center gap-3 transition-all ${
                        isChecked ? 'bg-emerald-50 border-emerald-500 text-emerald-600' : 'bg-slate-50 border-slate-100 text-slate-300'
                      }`}
                    >
                      <i className={`fas ${item.icon} text-xl`}></i>
                      <span className="font-black text-[10px] uppercase">{item.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="mt-10 flex justify-between">
              <button onClick={() => setStep(1)} className="px-6 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-all">Voltar</button>
              <button
                disabled={!isChecklistValid}
                onClick={() => setStep(3)}
                className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-blue-100 disabled:opacity-30 transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-8">Planejamento de Rota</h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Ponto de Saída</label>
                  <input
                    placeholder="Ex: Garagem Norte"
                    value={route.origin}
                    onChange={(e) => setRoute({ ...route, origin: e.target.value })}
                    className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                  />
                </div>

                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Destino Final</label>
                  <div className="space-y-3">
                    <input
                      placeholder="Endereço / Nome do Local"
                      value={route.destination}
                      onChange={(e) => setRoute({ ...route, destination: e.target.value })}
                      className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                    <div className="grid grid-cols-2 gap-3">
                      <input
                        placeholder="Cidade"
                        value={route.city}
                        onChange={(e) => setRoute({ ...route, city: e.target.value })}
                        className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                      />
                      <input
                        placeholder="UF"
                        maxLength={2}
                        value={route.state}
                        onChange={(e) => setRoute({ ...route, state: e.target.value.toUpperCase() })}
                        className="w-full p-4 rounded-xl border border-slate-200 text-center focus:ring-2 focus:ring-blue-500 outline-none font-black text-slate-800"
                      />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Saída Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedDeparture}
                      onChange={(e) => setRoute({ ...route, plannedDeparture: e.target.value })}
                      className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Chegada Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedArrival}
                      onChange={(e) => setRoute({ ...route, plannedArrival: e.target.value })}
                      className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-12 flex justify-between border-t border-slate-50 pt-8">
              <button onClick={() => setStep(2)} className="px-6 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-all">Voltar</button>
              <button
                onClick={handleStartTrip}
                disabled={!route.origin || !route.destination || !route.city}
                className="bg-emerald-600 text-white px-10 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all flex items-center gap-3 disabled:opacity-30"
              >
                Confirmar Saída <i className="fas fa-check-double"></i>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default OperationWizard;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  serviceType: string;
  cost: number;
  km: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string;
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  waypoints?: string[];
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  startKm: number; // KM no momento da saída
  distance?: number; // Calculado no final
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime' | 'startKm'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence, ScheduledTrip } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  updateTrip: (tripId: string, updates: Partial<Trip>) => void;
  addScheduledTrip: (trip: ScheduledTrip) => void;
  deleteScheduledTrip: (id: string) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
