              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowFinishModal(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-2xl">Cancelar</button>
                <button onClick={confirmFinish} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Confirmar Chegada</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ... Rest of the component (Charts, Stats, etc) remains the same ... */}
      {/* Edit Trip Modal (Driver) */}
      {editingTrip && (
