import React, { useState, useRef, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import Logo from './Logo';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, onTabChange }) => {
  const { currentUser, logout, notifications, markNotificationAsRead } = useFleet();
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter(n => !n.isRead).length;
  const isAdmin = currentUser?.username === 'admin';

  const menuItems = [
    { id: 'dashboard', icon: 'fa-chart-pie', label: 'Dashboard', adminOnly: false },
    { id: 'fleet', icon: 'fa-truck', label: 'Frota', adminOnly: true },
    { id: 'drivers', icon: 'fa-users', label: 'Motoristas', adminOnly: true },
    { id: 'scheduling', icon: 'fa-calendar-alt', label: 'Agenda', adminOnly: true },
    { id: 'operation', icon: 'fa-key', label: 'Operação (Saída)', adminOnly: false },
    { id: 'history', icon: 'fa-clock-rotate-left', label: 'Histórico', adminOnly: false },
    { id: 'monitoring', icon: 'fa-map-location-dot', label: 'Monitoramento', adminOnly: true },
    { id: 'reports', icon: 'fa-file-contract', label: 'Relatórios', adminOnly: false },
  ];

  const visibleMenuItems = menuItems.filter(item => !item.adminOnly || isAdmin);

  const handleLogout = () => {
    logout();
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      {/* Sidebar Desktop */}
      <aside className="w-64 bg-white border-r border-slate-100 flex flex-col hidden md:flex shadow-sm z-20">
        <div className="p-8 flex justify-center">
          <Logo size="sm" />
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          <div className="px-4 mb-4 flex items-center justify-between">
             <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Menu Principal</span>
             {isAdmin && <span className="text-[8px] bg-blue-100 text-blue-600 px-1.5 py-0.5 rounded font-black uppercase">Admin</span>}
          </div>
          {visibleMenuItems.map(item => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all group ${
                activeTab === item.id 
                ? 'bg-slate-900 text-white shadow-xl shadow-slate-200' 
                : 'text-slate-400 hover:bg-slate-50 hover:text-slate-900'
              }`}
            >
              <i className={`fas ${item.icon} w-5 text-sm transition-transform group-hover:scale-110`}></i>
              <span className="font-bold text-xs uppercase tracking-tight">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-6">
          <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-10 h-10 rounded-2xl bg-white border border-slate-100 shadow-sm flex items-center justify-center font-bold overflow-hidden ring-2 ring-slate-100 ring-offset-2">
                {currentUser?.avatar ? (
                  <img src={currentUser.avatar} alt="" className="w-full h-full object-cover" />
                ) : (
                  <span className="text-slate-400 font-bold">{currentUser?.name.charAt(0)}</span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-black text-slate-800 truncate uppercase tracking-tighter">{currentUser?.name}</p>
                <p className="text-[10px] text-slate-400 truncate font-bold">@{currentUser?.username}</p>
              </div>
            </div>
            <button 
              onClick={handleLogout} 
              className="w-full py-2.5 bg-white text-red-500 rounded-xl text-[10px] font-black uppercase tracking-widest border border-red-50 hover:bg-red-50 hover:border-red-100 transition-all flex items-center justify-center gap-2"
            >
              <i className="fas fa-sign-out-alt"></i>
              Sair do Sistema
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header Superior */}
        <header className="bg-white/80 backdrop-blur-md border-b border-slate-100 p-4 flex items-center justify-between gap-4 shadow-sm z-10">
          <div className="md:hidden">
            <Logo size="sm" />
          </div>

          <div className="hidden md:block flex-1 px-4">
             <h1 className="text-xs font-black text-slate-400 uppercase tracking-widest">
               {menuItems.find(m => m.id === activeTab)?.label || 'Sistema'}
             </h1>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="relative" ref={notificationRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)} 
                className="w-11 h-11 rounded-2xl bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-slate-600 shadow-sm transition-all hover:bg-slate-50"
              >
                <i className="fas fa-bell text-sm"></i>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-blue-600 text-white text-[9px] font-black w-5 h-5 rounded-lg flex items-center justify-center border-2 border-white">
                    {unreadCount}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in zoom-in duration-200 z-50">
                  <div className="p-5 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="font-black text-slate-800 text-[10px] uppercase tracking-[0.2em]">Notificações</h3>
                  </div>
                  <div className="max-h-[400px] overflow-y-auto">
                    {notifications.length > 0 ? (
                      notifications.map(n => (
                        <div key={n.id} onClick={() => markNotificationAsRead(n.id)} className={`p-5 border-b border-slate-50 hover:bg-slate-50 cursor-pointer flex gap-4 ${!n.isRead ? 'bg-blue-50/20' : ''}`}>
                          <div className={`w-9 h-9 rounded-2xl flex items-center justify-center flex-shrink-0 ${n.type === 'occurrence' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                            <i className="fas fa-info-circle"></i>
                          </div>
                          <div className="flex-1">
                            <p className="text-[10px] font-black text-slate-800 uppercase">{n.title}</p>
                            <p className="text-xs text-slate-500 leading-relaxed">{n.message}</p>
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="p-12 text-center text-slate-400 font-medium italic text-xs">Sem novas notificações.</div>
                    )}
                  </div>
                </div>
              )}
            </div>

            <button 
              onClick={handleLogout}
              className="flex items-center gap-2 px-3 py-2.5 md:px-5 md:py-2.5 rounded-2xl bg-red-50 text-red-600 border border-red-100 shadow-sm hover:bg-red-100 transition-all group"
              title="Sair do Sistema"
            >
              <i className="fas fa-power-off text-sm transition-transform group-hover:rotate-12"></i>
              <span className="hidden sm:inline font-black text-[10px] uppercase tracking-widest">Sair</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          {children}
        </div>

        {/* Bottom Nav Mobile */}
        <nav className="md:hidden bg-white/95 backdrop-blur-md border-t border-slate-100 flex items-center justify-around p-2 z-20 pb-safe">
          {visibleMenuItems.slice(0, 5).map(item => (
            <button 
              key={item.id} 
              onClick={() => onTabChange(item.id)} 
              className={`flex flex-col items-center p-2 rounded-2xl transition-all flex-1 ${activeTab === item.id ? 'text-blue-600 bg-blue-50/50 font-black' : 'text-slate-300'}`}
            >
              <i className={`fas ${item.icon} text-lg`}></i>
              <span className="text-[8px] font-bold mt-1 uppercase truncate w-full text-center">{item.label.split(' ')[0]}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { FleetProvider, useFleet } from './context/FleetContext';
import Layout from './components/Layout';
import DashboardOverview from './components/DashboardOverview';
import FleetManager from './pages/FleetManager';
import DriverManagement from './pages/DriverManagement';
import OperationWizard from './pages/OperationWizard';
import TripMonitoring from './pages/TripMonitoring';
import SchedulingPage from './pages/SchedulingPage';
import ReportsPage from './pages/ReportsPage';
import HistoryPage from './pages/HistoryPage';
import Login from './pages/Login';

const AppContent: React.FC = () => {
  const { currentUser } = useFleet();
  const [activeTab, setActiveTab] = useState('dashboard');

  const isAdmin = currentUser?.username === 'admin';

  useEffect(() => {
    const restrictedTabs = ['fleet', 'drivers', 'scheduling', 'monitoring'];
    if (!isAdmin && restrictedTabs.includes(activeTab)) {
      setActiveTab('dashboard');
    }
  }, [activeTab, isAdmin]);

  if (!currentUser) {
    return <Login />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <DashboardOverview />;
      case 'fleet':
        return isAdmin ? <FleetManager /> : <DashboardOverview />;
      case 'drivers':
        return isAdmin ? <DriverManagement /> : <DashboardOverview />;
      case 'operation':
        return <OperationWizard />;
      case 'history':
        return <HistoryPage />;
      case 'monitoring':
        return isAdmin ? <TripMonitoring /> : <DashboardOverview />;
      case 'scheduling':
        return isAdmin ? <SchedulingPage /> : <DashboardOverview />;
      case 'reports':
        return <ReportsPage />;
      default:
        return <DashboardOverview />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FleetProvider>
      <AppContent />
    </FleetProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';

const HistoryPage: React.FC = () => {
  const { completedTrips, vehicles, drivers, currentUser } = useFleet();
  const [searchTerm, setSearchTerm] = useState('');

  const isAdmin = currentUser?.username === 'admin';

  const myTrips = completedTrips.filter(t => 
    isAdmin ? true : t.driverId === currentUser?.id
  );

  const filteredHistory = myTrips.filter(t => {
    const vehicle = vehicles.find(v => v.id === t.vehicleId);
    const driver = drivers.find(d => d.id === t.driverId);
    const searchString = `${vehicle?.plate} ${driver?.name} ${t.destination} ${t.city}`.toLowerCase();
    return searchString.includes(searchTerm.toLowerCase());
  });

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Histórico de Viagens</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">
            {isAdmin ? 'Registro Geral da Frota' : 'Minhas Jornadas Concluídas'}
          </p>
        </div>

        <div className="relative flex-1 max-w-md">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
          <input 
            type="text" 
            placeholder="Buscar por placa, destino ou cidade..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-white border border-slate-100 rounded-2xl text-sm font-bold text-slate-950 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
          />
        </div>
      </div>

      <div className="space-y-4">
        {filteredHistory.length > 0 ? (
          filteredHistory.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const dateObj = new Date(trip.startTime);

            return (
              <div key={trip.id} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 hover:shadow-md transition-all flex flex-col md:flex-row items-center gap-6">
                <div className="w-full md:w-32 flex flex-col items-center justify-center p-4 bg-slate-50 rounded-2xl border border-slate-100 shrink-0">
                  <span className="text-2xl font-black text-slate-800">{dateObj.getDate()}</span>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{dateObj.toLocaleDateString('pt-BR', { month: 'short' })}</span>
                  <span className="text-[9px] font-bold text-slate-300 mt-1">{dateObj.getFullYear()}</span>
                </div>

                <div className="flex-1 grid grid-cols-1 md:grid-cols-4 gap-6 w-full">
                  <div>
                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Veículo</p>
                    <p className="text-sm font-bold text-slate-800 flex items-center gap-2">
                      <span className="bg-slate-900 text-white px-2 py-0.5 rounded text-[10px] font-mono">{vehicle?.plate}</span>
                      {vehicle?.model}
                    </p>
                  </div>

                  {isAdmin && (
                    <div>
                      <p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Condutor</p>
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                    </div>
                  )}

                  <div>
                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Trajeto</p>
                    <p className="text-sm font-bold text-slate-800 truncate">{trip.destination}</p>
                    <p className="text-[10px] text-slate-400 font-medium">{trip.city}, {trip.state}</p>
                  </div>

                  <div className="text-right md:text-left">
                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Distância</p>
                    <p className="text-sm font-black text-blue-600">{trip.distance?.toFixed(1) || '0.0'} KM</p>
                    <p className="text-[10px] text-slate-400 font-medium">Início: {new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="flex gap-2 w-full md:w-auto">
                  <button className="flex-1 md:w-10 md:h-10 rounded-xl bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-blue-50 hover:text-blue-600 transition-all">
                    <i className="fas fa-file-invoice"></i>
                  </button>
                </div>
              </div>
            );
          })
        ) : (
          <div className="py-24 text-center bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-200">
              <i className="fas fa-box-open text-3xl"></i>
            </div>
            <p className="text-slate-400 font-black uppercase text-[10px] tracking-[0.2em]">Nenhum registro encontrado</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryPage;

import React, { useState, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type ReportType = 'trips' | 'consumption' | 'fines' | 'management';

const ReportsPage: React.FC = () => {
  const { vehicles, drivers, completedTrips, fines, maintenanceRecords, currentUser } = useFleet();
  const [activeReport, setActiveReport] = useState<ReportType>('trips');

  const isAdmin = currentUser?.username === 'admin';

  // Date Filters
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 30);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);

  // Data filtering logic
  const filteredTrips = useMemo(() => {
    return completedTrips.filter(t => {
      const tripDate = t.startTime.split('T')[0];
      const matchesDate = tripDate >= startDate && tripDate <= endDate;
      const matchesUser = isAdmin ? true : t.driverId === currentUser?.id;
      return matchesDate && matchesUser;
    });
  }, [completedTrips, startDate, endDate, isAdmin, currentUser]);

  const filteredFines = useMemo(() => {
    return fines.filter(f => {
      const matchesDate = f.date >= startDate && f.date <= endDate;
      const matchesUser = isAdmin ? true : f.driverId === currentUser?.id;
      return matchesDate && matchesUser;
    });
  }, [fines, startDate, endDate, isAdmin, currentUser]);

  const filteredMaintenance = useMemo(() => {
    return maintenanceRecords.filter(m => m.date >= startDate && m.date <= endDate);
  }, [maintenanceRecords, startDate, endDate]);

  // Report 1: Trip Volume Data
  const tripChartData = useMemo(() => {
    if (isAdmin) {
      return drivers.map(d => {
        const count = filteredTrips.filter(t => t.driverId === d.id).length;
        return { name: d.name.split(' ')[0], viagens: count };
      }).filter(s => s.viagens > 0);
    } else {
      // For single driver, show trips by day
      const dailyMap: Record<string, number> = {};
      filteredTrips.forEach(t => {
        const day = new Date(t.startTime).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
        dailyMap[day] = (dailyMap[day] || 0) + 1;
      });
      return Object.entries(dailyMap).map(([name, viagens]) => ({ name, viagens }));
    }
  }, [drivers, filteredTrips, isAdmin]);

  // Report 4: Management Summary
  const managementSummary = useMemo(() => {
    const totalDist = filteredTrips.reduce((sum, t) => sum + (t.distance || 0), 0);
    const totalMaintCost = filteredMaintenance.reduce((sum, m) => sum + m.cost, 0);
    const totalFineCost = filteredFines.reduce((sum, f) => sum + f.value, 0);

    return { totalDist, totalMaintCost, totalFineCost };
  }, [filteredTrips, filteredMaintenance, filteredFines]);

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Indicadores de Performance</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">
            {isAdmin ? 'Análise Gerencial da Frota' : 'Meus Resultados Operacionais'}
          </p>
        </div>

        <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-400 uppercase mb-1">Início</span>
            <input 
              type="date" 
              value={startDate} 
              onChange={(e) => setStartDate(e.target.value)}
              className="bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-950 outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-400 uppercase mb-1">Fim</span>
            <input 
              type="date" 
              value={endDate} 
              onChange={(e) => setEndDate(e.target.value)}
              className="bg-slate-50 border border-slate-100 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-950 outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>
      </div>

      <div className="flex overflow-x-auto gap-2 p-1 bg-slate-100 rounded-2xl w-fit">
        {[
          { id: 'trips', label: 'Viagens', icon: 'fa-route', adminOnly: false },
          { id: 'consumption', label: 'Consumo', icon: 'fa-gas-pump', adminOnly: true },
          { id: 'fines', label: 'Multas', icon: 'fa-gavel', adminOnly: false },
          { id: 'management', label: 'Gerencial', icon: 'fa-briefcase', adminOnly: true },
        ].filter(t => !t.adminOnly || isAdmin).map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveReport(tab.id as ReportType)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${
              activeReport === tab.id 
              ? 'bg-white text-blue-600 shadow-sm' 
              : 'text-slate-400 hover:text-slate-600'
            }`}
          >
            <i className={`fas ${tab.icon}`}></i>
            {tab.label}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 gap-8 animate-in fade-in duration-500">
        {activeReport === 'trips' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">
                {isAdmin ? 'Volume de Viagens por Condutor' : 'Viagens Realizadas no Período'}
              </h3>
              <div className="h-80 w-full">
                {tripChartData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={tripChartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                      <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                      <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Bar dataKey="viagens" fill="#3b82f6" radius={[6, 6, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex items-center justify-center text-slate-300 italic font-medium">Nenhum dado no período selecionado</div>
                )}
              </div>
            </div>
            <div className="bg-slate-900 rounded-3xl p-8 text-white flex flex-col justify-between shadow-2xl">
              <div>
                <i className="fas fa-info-circle text-blue-400 text-2xl mb-4"></i>
                <h4 className="text-lg font-black uppercase mb-4">Sumário</h4>
                <div className="space-y-6">
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Total de Viagens</p>
                    <p className="text-4xl font-black tracking-tighter">{filteredTrips.length}</p>
                  </div>
                  <div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">KM Rodados</p>
                    <p className="text-3xl font-black tracking-tighter">{managementSummary.totalDist.toLocaleString()} km</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeReport === 'fines' && (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden p-8 text-center">
             <i className="fas fa-gavel text-4xl text-slate-200 mb-4"></i>
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-2">Multas e Infrações</h3>
             <p className="text-4xl font-black text-red-600 mb-2">{filteredFines.length}</p>
             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Multas acumuladas no período selecionado</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ReportsPage;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  returnDate?: string; // Data de retorno efetivo
  serviceType: string;
  cost: number;
  km: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string;
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  waypoints?: string[];
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  startKm: number; // KM no momento da saída
  distance?: number; // Calculado no final
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime' | 'startKm'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence, ScheduledTrip } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  updateTrip: (tripId: string, updates: Partial<Trip>) => void;
  addScheduledTrip: (trip: ScheduledTrip) => void;
  deleteScheduledTrip: (id: string) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  resolveMaintenance: (recordId: string, currentKm: number, returnDate: string) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [scheduledTrips, setScheduledTrips] = useState<ScheduledTrip[]>(() => {
    const saved = localStorage.getItem('fleet_scheduled_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    return saved ? JSON.parse(saved) : [];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [occurrences, setOccurrences] = useState<Occurrence[]>(() => {
    const saved = localStorage.getItem('fleet_occurrences');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
  }, [vehicles]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => { localStorage.setItem('fleet_drivers', JSON.stringify(drivers)); }, [drivers]);
  useEffect(() => { localStorage.setItem('fleet_checklists', JSON.stringify(checklists)); }, [checklists]);
  useEffect(() => { localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords)); }, [maintenanceRecords]);
  useEffect(() => { localStorage.setItem('fleet_fines', JSON.stringify(fines)); }, [fines]);
  useEffect(() => { localStorage.setItem('fleet_occurrences', JSON.stringify(occurrences)); }, [occurrences]);
  useEffect(() => { localStorage.setItem('fleet_scheduled_trips', JSON.stringify(scheduledTrips)); }, [scheduledTrips]);

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = useCallback(() => {
    setCurrentUser(null);
  }, []);

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips(prev => [...prev, trip]);
    setChecklists(prev => [...prev, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const distance = currentKm - trip.startKm;
    const finishedTrip = { ...trip, endTime, distance }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
    // Muda o status do veículo para manutenção ao criar o registro
    setVehicles(prev => prev.map(v => 
      v.id === record.vehicleId ? { ...v, status: VehicleStatus.MAINTENANCE } : v
    ));
  };

  const resolveMaintenance = (recordId: string, currentKm: number, returnDate: string) => {
    const record = maintenanceRecords.find(m => m.id === recordId);
    if (!record) return;

    setMaintenanceRecords(prev => prev.map(m => 
      m.id === recordId ? { ...m, returnDate } : m
    ));

    setVehicles(prev => prev.map(v => 
      v.id === record.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v
    ));
  };

  const addVehicle = (v: Vehicle) => setVehicles(prev => [...prev, v]);
  const addDriver = (d: Driver) => setDrivers(prev => [...prev, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
  const deleteDriver = (id: string) => setDrivers(prev => prev.filter(d => d.id !== id));
  const updateTrip = (tripId: string, updates: Partial<Trip>) => setActiveTrips(prev => prev.map(t => t.id === tripId ? { ...t, ...updates } : t));
  const addScheduledTrip = (trip: ScheduledTrip) => setScheduledTrips(prev => [trip, ...prev]);
  const deleteScheduledTrip = (id: string) => setScheduledTrips(prev => prev.filter(t => t.id !== id));
  const addFine = (fine: Fine) => setFines(prev => [fine, ...prev]);
  const deleteFine = (id: string) => setFines(prev => prev.filter(f => f.id !== id));
  const addOccurrence = (occ: Occurrence) => setOccurrences(prev => [occ, ...prev]);
  const markNotificationAsRead = (id: string) => setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, scheduledTrips, checklists, maintenanceRecords, notifications, fines, occurrences,
      addVehicle, addDriver, updateDriver, deleteDriver, startTrip, updateTrip, addScheduledTrip, deleteScheduledTrip, endTrip, cancelTrip, addMaintenanceRecord, resolveMaintenance, addFine, deleteFine, addOccurrence, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

