      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: newRecord.serviceType,
      cost: parseFloat(newRecord.cost),
      km: parseInt(newRecord.km),
      notes: newRecord.notes
    };

    addMaintenanceRecord(record);
    setNewRecord({ vehicleId: '', date: new Date().toISOString().split('T')[0], serviceType: '', cost: '', km: '', notes: '' });
    setShowMaintenanceForm(false);
    alert('Manutenção registrada! O veículo agora está em status de MANUTENÇÃO.');
  };

  const handleResolveMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!resolvingMaintenance || !resolveKm) return;

    resolveMaintenance(resolvingMaintenance.vehicleId, resolvingMaintenance.recordId, resolveKm, resolveDate);
    setResolvingMaintenance(null);
    alert('Manutenção finalizada! O veículo retornou ao status DISPONÍVEL.');
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    const vehicle: Vehicle = {
      id: Math.random().toString(36).substr(2, 9),
      plate: newVehicle.plate.toUpperCase(),
      brand: newVehicle.brand,
      model: newVehicle.model,
      year: parseInt(newVehicle.year),
      currentKm: parseInt(newVehicle.currentKm) || 0,
      fuelLevel: parseInt(newVehicle.fuelLevel),
      status: VehicleStatus.AVAILABLE
    };

    addVehicle(vehicle);
    setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100' });
    setShowVehicleForm(false);
    alert('Veículo cadastrado com sucesso!');
  };

  const filteredVehicles = vehicles.filter(v => {
    const matchesSearch = v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || v.model.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Controle de Ativos e Manutenções</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={() => {
              setShowMaintenanceForm(!showMaintenanceForm);
              setShowVehicleForm(false);
            }} 
            className="bg-slate-800 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-700 transition-all"
          >
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i> 
            {showMaintenanceForm ? 'Cancelar' : 'Registrar Manutenção'}
          </button>
          <button 
            onClick={() => {
              setShowVehicleForm(!showVehicleForm);
              setShowMaintenanceForm(false);
            }} 
            className="bg-blue-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all"
          >
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i> 
            {showVehicleForm ? 'Cancelar' : 'Novo Veículo'}
          </button>
        </div>
      </div>

      {/* Form Cadastro Veículo */}
      {showVehicleForm && (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Cadastro de Veículo</h3>
          <form onSubmit={handleSubmitVehicle} className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Placa</label>
              <input required placeholder="ABC-1234" value={newVehicle.plate} onChange={(e) => setNewVehicle({ ...newVehicle, plate: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Marca</label>
              <input required placeholder="Ex: Mercedes-Benz" value={newVehicle.brand} onChange={(e) => setNewVehicle({ ...newVehicle, brand: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Modelo</label>
              <input required placeholder="Ex: Sprinter 415" value={newVehicle.model} onChange={(e) => setNewVehicle({ ...newVehicle, model: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <button type="submit" className="bg-blue-600 text-white py-4 rounded-xl font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all md:col-span-3">Salvar Veículo</button>
          </form>
        </div>
      )}

      {/* Form Registro Manutenção */}
      {showMaintenanceForm && (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Registrar Saída para Manutenção</h3>
          <form onSubmit={handleSubmitMaintenance} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Veículo Destinado</label>
              <select required value={newRecord.vehicleId} onChange={(e) => setNewRecord({ ...newRecord, vehicleId: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                <option value="">Selecione o veículo...</option>
                {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Tipo de Serviço</label>
              <input required type="text" placeholder="Ex: Troca de pastilhas de freio" value={newRecord.serviceType} onChange={(e) => setNewRecord({ ...newRecord, serviceType: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">KM de Saída</label>
              <input required type="number" placeholder="Ex: 45000" value={newRecord.km} onChange={(e) => setNewRecord({ ...newRecord, km: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Custo Estimado (R$)</label>
              <input required type="number" step="0.01" placeholder="0.00" value={newRecord.cost} onChange={(e) => setNewRecord({ ...newRecord, cost: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Data de Saída</label>
              <input required type="date" value={newRecord.date} onChange={(e) => setNewRecord({ ...newRecord, date: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <button type="submit" className="bg-slate-900 text-white py-4 rounded-xl font-black uppercase text-xs tracking-widest hover:bg-slate-800 transition-all lg:col-span-1 md:col-span-2">Confirmar Envio</button>
          </form>
        </div>
      )}

      {/* Modal Finalizar Manutenção */}
      {resolvingMaintenance && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-800 text-white">
              <h3 className="text-lg font-black uppercase tracking-tight">Finalizar Manutenção</h3>
              <p className="text-slate-400 text-[10px] uppercase font-bold mt-1">Registrar retorno do veículo</p>
            </div>
            <form onSubmit={handleResolveMaintenance} className="p-8 space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">KM Atual de Retorno</label>
                <input 
                  type="number" 
                  required 
                  value={resolveKm} 
                  onChange={(e) => setResolveKm(parseInt(e.target.value))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-black text-xl text-slate-800 text-center"
                  placeholder="000000"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Data/Hora do Retorno</label>
                <input 
                  type="datetime-local" 
                  required 
                  value={resolveDate} 
                  onChange={(e) => setResolveDate(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setResolvingMaintenance(null)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-2xl">Voltar</button>
                <button type="submit" className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Confirmar Retorno</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex-1 relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
          <input 
            type="text" 
            placeholder="Buscar por placa ou modelo..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-950 focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>
        <select 
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-black text-slate-700 uppercase outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="ALL">Todos os Status</option>
          <option value={VehicleStatus.AVAILABLE}>Disponível</option>
          <option value={VehicleStatus.IN_USE}>Em Uso</option>
          <option value={VehicleStatus.MAINTENANCE}>Manutenção</option>
        </select>
      </div>

      {/* Vehicle Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredVehicles.map(vehicle => {
          const vehicleMaintenances = maintenanceRecords
            .filter(m => m.vehicleId === vehicle.id)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

          const activeMaintenance = vehicle.status === VehicleStatus.MAINTENANCE 
            ? vehicleMaintenances.find(m => !m.returnDate) 
            : null;

          return (
            <div key={vehicle.id} className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden flex flex-col hover:shadow-md transition-all">
              <div className="p-6 border-b border-slate-50">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex flex-col gap-1">
                    <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-mono text-xs font-black shadow-sm tracking-widest">{vehicle.plate}</span>
                    <p className="text-[10px] font-black text-slate-400 uppercase">{vehicle.brand}</p>
                  </div>
                  <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border-2 ${
                    vehicle.status === VehicleStatus.AVAILABLE ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                    vehicle.status === VehicleStatus.IN_USE ? 'bg-blue-50 text-blue-600 border-blue-100' : 
                    'bg-red-50 text-red-600 border-red-100'
                  }`}>
                    {vehicle.status === VehicleStatus.AVAILABLE ? 'Livre' : vehicle.status === VehicleStatus.IN_USE ? 'Em Rota' : 'Oficina'}
                  </span>
                </div>
                <h4 className="text-lg font-black text-slate-800 tracking-tight">{vehicle.model}</h4>
                <div className="mt-4 grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Odômetro</p>
                    <p className="text-sm font-black text-slate-800">{vehicle.currentKm.toLocaleString()} KM</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Fabricação</p>
                    <p className="text-sm font-black text-slate-800">Ano {vehicle.year}</p>
                  </div>
                </div>

                {activeMaintenance && (
                  <div className="mt-6 p-4 bg-red-50 rounded-2xl border border-red-100 animate-pulse">
                    <div className="flex justify-between items-center mb-2">
                       <span className="text-[9px] font-black text-red-600 uppercase tracking-widest">Manutenção em Aberto</span>
                       <i className="fas fa-wrench text-red-400"></i>
                    </div>
                    <p className="text-xs font-bold text-slate-800">{activeMaintenance.serviceType}</p>
                    <button 
                      onClick={() => {
                        setResolvingMaintenance({recordId: activeMaintenance.id, vehicleId: vehicle.id});
                        setResolveKm(vehicle.currentKm);
                      }}
                      className="w-full mt-3 py-2 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg shadow-red-200"
                    >
                      Finalizar Manutenção
                    </button>
                  </div>
                )}
              </div>

              {/* Maintenance History Section */}
              <div className="p-6 flex-1 bg-slate-50/50">
                <div className="flex items-center justify-between mb-4">
                  <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <i className="fas fa-history"></i> Histórico Técnico
                  </h5>
                  <span className="text-[9px] font-bold text-slate-300">{vehicleMaintenances.length} registros</span>
                </div>

                <div className="space-y-3 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                  {vehicleMaintenances.length > 0 ? (
                    vehicleMaintenances.map(m => (
                      <div key={m.id} className={`bg-white p-3 rounded-2xl border shadow-sm group hover:border-blue-200 transition-colors ${m.returnDate ? 'border-slate-100' : 'border-red-200 bg-red-50/20'}`}>
                        <div className="flex justify-between items-start">
                          <p className="text-xs font-black text-slate-900 leading-tight mb-1">{m.serviceType}</p>
                          <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded uppercase">R$ {m.cost.toFixed(2)}</span>
                        </div>
                        <div className="flex items-center justify-between mt-2">
                          <div className="flex flex-col">
                            <p className="text-[10px] text-slate-400 font-bold">Saída: {new Date(m.date).toLocaleDateString('pt-BR')} | {m.km} KM</p>
                            {m.returnDate && (
                              <p className="text-[9px] text-emerald-600 font-black uppercase mt-0.5">Retorno: {new Date(m.returnDate).toLocaleDateString('pt-BR')}</p>
                            )}
                          </div>

                          {m.notes && (
                            <div className="relative group/note">
                              <i className="fas fa-comment-dots text-slate-300 cursor-help hover:text-blue-500 transition-colors"></i>
                              <div className="absolute bottom-full right-0 mb-2 w-48 p-3 bg-slate-800 text-white text-[10px] rounded-2xl opacity-0 invisible group-hover/note:opacity-100 group-hover/note:visible transition-all z-50 pointer-events-none shadow-2xl border border-slate-700 translate-y-2 group-hover/note:translate-y-0">
                                <div className="font-black uppercase text-[8px] text-blue-400 mb-1.5 border-b border-slate-700 pb-1 flex items-center gap-1">
                                  <i className="fas fa-info-circle"></i> Observações
                                </div>
                                <p className="leading-relaxed text-slate-200 font-medium">{m.notes}</p>
                                <div className="absolute top-full right-3 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="py-8 text-center border-2 border-dashed border-slate-200 rounded-3xl">
                      <p className="text-[10px] font-black text-slate-300 uppercase italic">Sem manutenções registradas</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="p-4 bg-white border-t border-slate-50">
                <button className="w-full py-2 bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-all">
                  Ver Ficha Completa
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default FleetManager;

export enum VehicleStatus {
  AVAILABLE = 'AVAILABLE',
  IN_USE = 'IN_USE',
  MAINTENANCE = 'MAINTENANCE'
}

export enum OccurrenceSeverity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export interface Occurrence {
  id: string;
  tripId: string;
  vehicleId: string;
  driverId: string;
  type: string;
  description: string;
  severity: OccurrenceSeverity;
  timestamp: string;
  resolved: boolean;
}

export interface MaintenanceRecord {
  id: string;
  vehicleId: string;
  date: string;
  returnDate?: string; // Data de retorno efetivo
  serviceType: string;
  cost: number;
  km: number;
  notes: string;
}

export interface Fine {
  id: string;
  driverId: string;
  vehicleId: string;
  date: string;
  value: number;
  points: number;
  description: string;
}

export interface Vehicle {
  id: string;
  plate: string;
  model: string;
  brand: string;
  year: number;
  currentKm: number;
  fuelLevel: number;
  fuelType: 'Diesel' | 'Gasolina' | 'Flex' | 'Elétrico' | 'GNV';
  status: VehicleStatus;
  lastChecklist?: Checklist;
}

export interface Driver {
  id: string;
  name: string;
  license: string;
  username: string;
  password?: string;
  activeVehicleId?: string;
  avatar?: string;
}

export interface Checklist {
  id: string;
  vehicleId: string;
  driverId: string;
  timestamp: string;
  km: number;
  fuelLevel: number;
  oilChecked: boolean;
  waterChecked: boolean;
  tiresChecked: boolean;
  comments: string;
}

export interface Trip {
  id: string;
  driverId: string;
  vehicleId: string;
  origin: string;
  destination: string;
  waypoints?: string[];
  city?: string;
  state?: string;
  zipCode?: string;
  plannedDeparture?: string;
  plannedArrival?: string;
  startTime: string;
  endTime?: string;
  startKm: number; // KM no momento da saída
  distance?: number; // Calculado no final
  observations?: string;
}

export interface ScheduledTrip extends Omit<Trip, 'startTime' | 'startKm'> {
  scheduledDate: string;
  notes?: string;
}

export interface AppNotification {
  id: string;
  type: 'maintenance_km' | 'maintenance_date' | 'low_fuel' | 'new_fine' | 'occurrence' | 'schedule';
  title: string;
  message: string;
  vehicleId: string;
  timestamp: string;
  isRead: boolean;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Vehicle, Driver, Trip, Checklist, VehicleStatus, MaintenanceRecord, AppNotification, Fine, Occurrence, ScheduledTrip } from '../types';

interface FleetContextType {
  vehicles: Vehicle[];
  drivers: Driver[];
  activeTrips: Trip[];
  completedTrips: Trip[];
  scheduledTrips: ScheduledTrip[];
  checklists: Checklist[];
  maintenanceRecords: MaintenanceRecord[];
  notifications: AppNotification[];
  fines: Fine[];
  occurrences: Occurrence[];
  addVehicle: (v: Vehicle) => void;
  updateVehicle: (id: string, updates: Partial<Vehicle>) => void;
  addDriver: (d: Driver) => void;
  updateDriver: (id: string, updates: Partial<Driver>) => void;
  deleteDriver: (id: string) => void;
  startTrip: (trip: Trip, checklist: Checklist) => void;
  updateTrip: (tripId: string, updates: Partial<Trip>) => void;
  addScheduledTrip: (trip: ScheduledTrip) => void;
  deleteScheduledTrip: (id: string) => void;
  endTrip: (tripId: string, currentKm: number, endTime: string) => void;
  cancelTrip: (tripId: string) => void;
  addMaintenanceRecord: (record: MaintenanceRecord) => void;
  resolveMaintenance: (vehicleId: string, recordId: string | null | undefined, currentKm: number, returnDate: string) => void;
  addFine: (fine: Fine) => void;
  deleteFine: (id: string) => void;
  addOccurrence: (occ: Occurrence) => void;
  markNotificationAsRead: (id: string) => void;
  currentUser: Driver | null;
  login: (username: string, pass: string) => boolean;
  logout: () => void;
}

const FleetContext = createContext<FleetContextType | undefined>(undefined);

export const FleetProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(() => {
    const saved = localStorage.getItem('fleet_vehicles');
    return saved ? JSON.parse(saved) : [
      { id: '1', plate: 'ABC-1234', model: 'Sprinter', brand: 'Mercedes', year: 2022, currentKm: 45000, fuelLevel: 75, fuelType: 'Diesel', status: VehicleStatus.AVAILABLE },
      { id: '2', plate: 'XYZ-5678', model: 'Hilux', brand: 'Toyota', year: 2023, currentKm: 12000, fuelLevel: 100, fuelType: 'Diesel', status: VehicleStatus.AVAILABLE },
      { id: '3', plate: 'DEF-9012', model: 'Daily', brand: 'Iveco', year: 2021, currentKm: 89000, fuelLevel: 40, fuelType: 'Diesel', status: VehicleStatus.MAINTENANCE },
    ];
  });

  const [drivers, setDrivers] = useState<Driver[]>(() => {
    const saved = localStorage.getItem('fleet_drivers');
    return saved ? JSON.parse(saved) : [
      { id: 'd1', name: 'João Silva', license: '12345678', username: 'joao', password: '123' },
      { id: 'd2', name: 'Maria Santos', license: '87654321', username: 'maria', password: '123' },
      { id: 'admin', name: 'Gestor de Frota', license: '0000', username: 'admin', password: 'admin' },
    ];
  });

  const [activeTrips, setActiveTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_active_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [scheduledTrips, setScheduledTrips] = useState<ScheduledTrip[]>(() => {
    const saved = localStorage.getItem('fleet_scheduled_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [completedTrips, setCompletedTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem('fleet_completed_trips');
    return saved ? JSON.parse(saved) : [];
  });

  const [checklists, setChecklists] = useState<Checklist[]>(() => {
    const saved = localStorage.getItem('fleet_checklists');
    return saved ? JSON.parse(saved) : [];
  });

  const [maintenanceRecords, setMaintenanceRecords] = useState<MaintenanceRecord[]>(() => {
    const saved = localStorage.getItem('fleet_maintenance');
    if (saved) return JSON.parse(saved);
    return [
      { id: 'm-initial-3', vehicleId: '3', date: '2023-12-01', serviceType: 'Revisão de Motor', cost: 1200, km: 88900, notes: 'Veículo enviado para oficina para revisão periódica.' }
    ];
  });

  const [fines, setFines] = useState<Fine[]>(() => {
    const saved = localStorage.getItem('fleet_fines');
    return saved ? JSON.parse(saved) : [];
  });

  const [occurrences, setOccurrences] = useState<Occurrence[]>(() => {
    const saved = localStorage.getItem('fleet_occurrences');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [currentUser, setCurrentUser] = useState<Driver | null>(null);

  useEffect(() => {
    localStorage.setItem('fleet_vehicles', JSON.stringify(vehicles));
  }, [vehicles]);

  useEffect(() => {
    localStorage.setItem('fleet_active_trips', JSON.stringify(activeTrips));
  }, [activeTrips]);

  useEffect(() => {
    localStorage.setItem('fleet_completed_trips', JSON.stringify(completedTrips));
  }, [completedTrips]);

  useEffect(() => { localStorage.setItem('fleet_drivers', JSON.stringify(drivers)); }, [drivers]);
  useEffect(() => { localStorage.setItem('fleet_checklists', JSON.stringify(checklists)); }, [checklists]);
  useEffect(() => { localStorage.setItem('fleet_maintenance', JSON.stringify(maintenanceRecords)); }, [maintenanceRecords]);
  useEffect(() => { localStorage.setItem('fleet_fines', JSON.stringify(fines)); }, [fines]);
  useEffect(() => { localStorage.setItem('fleet_occurrences', JSON.stringify(occurrences)); }, [occurrences]);
  useEffect(() => { localStorage.setItem('fleet_scheduled_trips', JSON.stringify(scheduledTrips)); }, [scheduledTrips]);

  const login = (user: string, pass: string) => {
    const driver = drivers.find(d => d.username === user && d.password === pass);
    if (driver) {
      setCurrentUser(driver);
      return true;
    }
    return false;
  };

  const logout = useCallback(() => {
    setCurrentUser(null);
  }, []);

  const addVehicle = (v: Vehicle) => setVehicles(prev => [...prev, v]);

  const updateVehicle = (id: string, updates: Partial<Vehicle>) => {
    setVehicles(prev => prev.map(v => v.id === id ? { ...v, ...updates } : v));
  };

  const startTrip = (trip: Trip, checklist: Checklist) => {
    setActiveTrips(prev => [...prev, trip]);
    setChecklists(prev => [...prev, checklist]);
    setVehicles(prev => prev.map(v => 
      v.id === trip.vehicleId ? { ...v, status: VehicleStatus.IN_USE, currentKm: checklist.km, fuelLevel: checklist.fuelLevel, lastChecklist: checklist } : v
    ));
    setDrivers(prev => prev.map(d => 
      d.id === trip.driverId ? { ...d, activeVehicleId: trip.vehicleId } : d
    ));
  };

  const endTrip = (tripId: string, currentKm: number, endTime: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;

    const distance = currentKm - trip.startKm;
    const finishedTrip = { ...trip, endTime, distance }; 

    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setCompletedTrips(prev => [finishedTrip, ...prev]);
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const cancelTrip = (tripId: string) => {
    const trip = activeTrips.find(t => t.id === tripId);
    if (!trip) return;
    setActiveTrips(prev => prev.filter(t => t.id !== tripId));
    setVehicles(prev => prev.map(v => v.id === trip.vehicleId ? { ...v, status: VehicleStatus.AVAILABLE } : v));
    setDrivers(prev => prev.map(d => d.id === trip.driverId ? { ...d, activeVehicleId: undefined } : d));
  };

  const addMaintenanceRecord = (record: MaintenanceRecord) => {
    setMaintenanceRecords(prev => [record, ...prev]);
    setVehicles(prev => prev.map(v => 
      v.id === record.vehicleId ? { ...v, status: VehicleStatus.MAINTENANCE } : v
    ));
  };

  const resolveMaintenance = useCallback((vehicleId: string, recordId: string | null | undefined, currentKm: number, returnDate: string) => {
    setVehicles(prev => prev.map(v => 
      v.id === vehicleId ? { ...v, status: VehicleStatus.AVAILABLE, currentKm } : v
    ));

    setMaintenanceRecords(prev => {
      let targetId = recordId;
      if (!targetId) {
        const openRecord = prev.find(m => m.vehicleId === vehicleId && !m.returnDate);
        targetId = openRecord?.id;
      }
      if (targetId) {
        return prev.map(m => m.id === targetId ? { ...m, returnDate } : m);
      }
      return prev;
    });
  }, []);

  const addDriver = (d: Driver) => setDrivers(prev => [...prev, d]);
  const updateDriver = (id: string, updates: Partial<Driver>) => setDrivers(prev => prev.map(d => d.id === id ? { ...d, ...updates } : d));
  const deleteDriver = (id: string) => setDrivers(prev => prev.filter(d => d.id !== id));
  const updateTrip = (tripId: string, updates: Partial<Trip>) => setActiveTrips(prev => prev.map(t => t.id === tripId ? { ...t, ...updates } : t));
  const addScheduledTrip = (trip: ScheduledTrip) => setScheduledTrips(prev => [trip, ...prev]);
  const deleteScheduledTrip = (id: string) => setScheduledTrips(prev => prev.filter(t => t.id !== id));
  const addFine = (fine: Fine) => setFines(prev => [fine, ...prev]);
  const deleteFine = (id: string) => setFines(prev => prev.filter(f => f.id !== id));
  const addOccurrence = (occ: Occurrence) => setOccurrences(prev => [occ, ...prev]);
  const markNotificationAsRead = (id: string) => setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));

  return (
    <FleetContext.Provider value={{
      vehicles, drivers, activeTrips, completedTrips, scheduledTrips, checklists, maintenanceRecords, notifications, fines, occurrences,
      addVehicle, updateVehicle, addDriver, updateDriver, deleteDriver, startTrip, updateTrip, addScheduledTrip, deleteScheduledTrip, endTrip, cancelTrip, addMaintenanceRecord, resolveMaintenance, addFine, deleteFine, addOccurrence, markNotificationAsRead,
      currentUser, login, logout
    }}>
      {children}
    </FleetContext.Provider>
  );
};

export const useFleet = () => {
  const context = useContext(FleetContext);
  if (!context) throw new Error('useFleet must be used within a FleetProvider');
  return context;
};

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, resolveMaintenance, addVehicle, updateVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);
  const [editingVehicleId, setEditingVehicleId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Modal para finalizar manutenção
  const [resolvingMaintenance, setResolvingMaintenance] = useState<{recordId: string, vehicleId: string} | null>(null);
  const [resolveKm, setResolveKm] = useState<number>(0);
  const [resolveDate, setResolveDate] = useState(new Date().toISOString().slice(0, 16));

  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    km: '',
    notes: ''
  });

  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100',
    fuelType: 'Diesel' as Vehicle['fuelType']
  });

  const handleSubmitMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.vehicleId || !newRecord.serviceType || !newRecord.cost || !newRecord.km) return;

    const record: MaintenanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: newRecord.serviceType,
      cost: parseFloat(newRecord.cost),
      km: parseInt(newRecord.km),
      notes: newRecord.notes
    };

    addMaintenanceRecord(record);
    setNewRecord({ vehicleId: '', date: new Date().toISOString().split('T')[0], serviceType: '', cost: '', km: '', notes: '' });
    setShowMaintenanceForm(false);
    alert('Manutenção registrada! O veículo agora está em status de MANUTENÇÃO.');
  };

  const handleResolveMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!resolvingMaintenance || !resolveKm) return;

    resolveMaintenance(resolvingMaintenance.vehicleId, resolvingMaintenance.recordId, resolveKm, resolveDate);
    setResolvingMaintenance(null);
    alert('Manutenção finalizada! O veículo retornou ao status DISPONÍVEL.');
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    if (editingVehicleId) {
      updateVehicle(editingVehicleId, {
        plate: newVehicle.plate.toUpperCase(),
        brand: newVehicle.brand,
        model: newVehicle.model,
        year: parseInt(newVehicle.year),
        currentKm: parseInt(newVehicle.currentKm) || 0,
        fuelType: newVehicle.fuelType
      });
      alert('Veículo atualizado com sucesso!');
    } else {
      const vehicle: Vehicle = {
        id: Math.random().toString(36).substr(2, 9),
        plate: newVehicle.plate.toUpperCase(),
        brand: newVehicle.brand,
        model: newVehicle.model,
        year: parseInt(newVehicle.year),
        currentKm: parseInt(newVehicle.currentKm) || 0,
        fuelLevel: parseInt(newVehicle.fuelLevel),
        fuelType: newVehicle.fuelType,
        status: VehicleStatus.AVAILABLE
      };
      addVehicle(vehicle);
      alert('Veículo cadastrado com sucesso!');
    }

    setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100', fuelType: 'Diesel' });
    setShowVehicleForm(false);
    setEditingVehicleId(null);
  };

  const handleEditVehicle = (vehicle: Vehicle) => {
    setNewVehicle({
      plate: vehicle.plate,
      brand: vehicle.brand,
      model: vehicle.model,
      year: vehicle.year.toString(),
      currentKm: vehicle.currentKm.toString(),
      fuelLevel: vehicle.fuelLevel.toString(),
      fuelType: vehicle.fuelType
    });
    setEditingVehicleId(vehicle.id);
    setShowVehicleForm(true);
    setShowMaintenanceForm(false);
  };

  const filteredVehicles = vehicles.filter(v => {
    const matchesSearch = v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || v.model.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Controle de Ativos e Manutenções</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={() => {
              setShowMaintenanceForm(!showMaintenanceForm);
              setShowVehicleForm(false);
              setEditingVehicleId(null);
            }} 
            className="bg-slate-800 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-700 transition-all"
          >
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i> 
            {showMaintenanceForm ? 'Cancelar' : 'Registrar Manutenção'}
          </button>
          <button 
            onClick={() => {
              if (showVehicleForm && editingVehicleId) {
                 setEditingVehicleId(null);
                 setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100', fuelType: 'Diesel' });
              }
              setShowVehicleForm(!showVehicleForm);
              setShowMaintenanceForm(false);
            }} 
            className="bg-blue-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all"
          >
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i> 
            {showVehicleForm ? 'Cancelar' : (editingVehicleId ? 'Cancelar Edição' : 'Novo Veículo')}
          </button>
        </div>
      </div>

      {/* Form Cadastro/Edição Veículo */}
      {showVehicleForm && (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">
            {editingVehicleId ? 'Editar Veículo' : 'Cadastro de Veículo'}
          </h3>
          <form onSubmit={handleSubmitVehicle} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Placa</label>
              <input required placeholder="ABC-1234" value={newVehicle.plate} onChange={(e) => setNewVehicle({ ...newVehicle, plate: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Marca</label>
              <input required placeholder="Ex: Mercedes-Benz" value={newVehicle.brand} onChange={(e) => setNewVehicle({ ...newVehicle, brand: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Modelo</label>
              <input required placeholder="Ex: Sprinter 415" value={newVehicle.model} onChange={(e) => setNewVehicle({ ...newVehicle, model: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
