                <option value="Gasolina">Gasolina</option>
                <option value="Flex">Flex</option>
                <option value="Elétrico">Elétrico</option>
                <option value="GNV">GNV</option>
              </select>
            </div>
            <button type="submit" className="bg-blue-600 text-white py-4 rounded-xl font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all md:col-span-3">
              {editingVehicleId ? 'Salvar Alterações' : 'Salvar Veículo'}
