            <form onSubmit={handleResolveMaintenance} className="p-8 space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">KM Atual de Retorno</label>
                <input 
                  type="number" 
                  required 
                  value={resolveKm} 
                  onChange={(e) => setResolveKm(parseInt(e.target.value))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-black text-xl text-slate-800 text-center"
                  placeholder="000000"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Data/Hora do Retorno</label>
                <input 
                  type="datetime-local" 
                  required 
                  value={resolveDate} 
                  onChange={(e) => setResolveDate(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setResolvingMaintenance(null)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-2xl">Voltar</button>
                <button type="submit" className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Confirmar Retorno</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex-1 relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
          <input 
            type="text" 
            placeholder="Buscar por placa ou modelo..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-950 focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>
        <select 
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-black text-slate-700 uppercase outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="ALL">Todos os Status</option>
          <option value={VehicleStatus.AVAILABLE}>Disponível</option>
          <option value={VehicleStatus.IN_USE}>Em Uso</option>
          <option value={VehicleStatus.MAINTENANCE}>Manutenção</option>
        </select>
      </div>

      {/* Vehicle Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredVehicles.map(vehicle => {
          const vehicleMaintenances = maintenanceRecords
            .filter(m => m.vehicleId === vehicle.id)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

          const activeMaintenance = vehicle.status === VehicleStatus.MAINTENANCE 
            ? vehicleMaintenances.find(m => !m.returnDate) 
            : null;

          return (
