              {/* Maintenance History Section */}
              <div className="p-6 flex-1 bg-slate-50/50">
                <div className="flex items-center justify-between mb-4">
                  <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <i className="fas fa-history"></i> Histórico Técnico
                  </h5>
                  <span className="text-[9px] font-bold text-slate-300">{vehicleMaintenances.length} registros</span>
                </div>

                <div className="space-y-3 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                  {vehicleMaintenances.length > 0 ? (
                    vehicleMaintenances.map(m => (
                      <div key={m.id} className={`bg-white p-3 rounded-2xl border shadow-sm group hover:border-blue-200 transition-colors ${m.returnDate ? 'border-slate-100' : 'border-red-200 bg-red-50/20'}`}>
                        <div className="flex justify-between items-start">
                          <p className="text-xs font-black text-slate-900 leading-tight mb-1">{m.serviceType}</p>
                          <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded uppercase">R$ {m.cost.toFixed(2)}</span>
