              <div className="p-4 bg-white border-t border-slate-50">
                <button className="w-full py-2 bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-all">
                  Ver Ficha Completa
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

