                      />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Saída Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedDeparture}
                      onChange={(e) => setRoute({ ...route, plannedDeparture: e.target.value })}
                      className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Chegada Prevista</label>
                    <input
                      type="datetime-local"
                      value={route.plannedArrival}
                      onChange={(e) => setRoute({ ...route, plannedArrival: e.target.value })}
                      className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-12 flex justify-between border-t border-slate-50 pt-8">
              <button onClick={() => setStep(2)} className="px-6 py-3 text-slate-400 font-write uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-all">Voltar</button>
              <button
                onClick={handleStartTrip}
                disabled={!route.origin || !route.destination || !route.city}
