import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle, Occurrence, OccurrenceSeverity } from '../types';
import { getOptimizedRoute } from '../services/geminiService';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, occurrences, endTrip, cancelTrip, addOccurrence } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [now, setNow] = useState(new Date());

  // Optimization State
  const [optimizingTripId, setOptimizingTripId] = useState<string | null>(null);
  const [optimizationResult, setOptimizationResult] = useState<{text: string, grounding: any[]} | null>(null);
  const [loadingOptimization, setLoadingOptimization] = useState(false);

  // Occurrence Modal State
  const [reportingTrip, setReportingTrip] = useState<Trip | null>(null);
  const [newOccurrence, setNewOccurrence] = useState({
    type: '',
    description: '',
    severity: OccurrenceSeverity.LOW
  });

  // Update "now" every minute to refresh status indicators
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };

    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    const startTime = new Date(trip.startTime).getTime();

    if (currentTime > arrivalTime) {
      return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    }

    const totalDuration = arrivalTime - startTime;
    const elapsed = currentTime - startTime;
    const progress = elapsed / totalDuration;

    if (progress > 0.85) {
      return { label: 'Próximo ao Destino', color: 'bg-amber-100 text-amber-700', icon: 'fa-location-crosshairs' };
    }

    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      // Captura o horário do dispositivo no exato momento da confirmação
      const deviceTime = new Date().toISOString();
      endTrip(finishingTripId, endKm, deviceTime);
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso! Horário de chegada registrado automaticamente.');
    }
  };

  const handleCancel = (tripId: string) => {
    if (confirm('ATENÇÃO: Deseja realmente cancelar esta operação? O veículo e o motorista serão liberados imediatamente.')) {
      cancelTrip(tripId);
    }
  };

  const handleOptimize = async (trip: Trip) => {
    setOptimizingTripId(trip.id);
    setLoadingOptimization(true);
    setOptimizationResult(null);
    try {
      const result = await getOptimizedRoute(trip.origin, trip.destination, trip.waypoints);
      setOptimizationResult(result);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingOptimization(false);
    }
  };

  const handleReportOccurrence = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reportingTrip || !newOccurrence.type || !newOccurrence.description) return;

    const occ: Occurrence = {
      id: Math.random().toString(36).substr(2, 9),
      tripId: reportingTrip.id,
      vehicleId: reportingTrip.vehicleId,
      driverId: reportingTrip.driverId,
      type: newOccurrence.type,
      description: newOccurrence.description,
      severity: newOccurrence.severity,
      timestamp: new Date().toISOString(),
      resolved: false
    };

    addOccurrence(occ);
    setReportingTrip(null);
    setNewOccurrence({ type: '', description: '', severity: OccurrenceSeverity.LOW });
    alert('Ocorrência registrada com sucesso.');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase shadow-sm">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);
            const tripOccurrences = occurrences.filter(o => o.tripId === trip.id);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all transform hover:-translate-y-1 relative">
                {tripOccurrences.length > 0 && (
                  <div className="absolute top-2 left-2 z-10 flex gap-1">
                    <span className="bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-full animate-bounce shadow-lg">
                      {tripOccurrences.length} Ocorrência(s)
                    </span>
                  </div>
                )}

                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs shadow-inner">
                      {vehicle?.plate}
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Veículo</p>
                      <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Saída</p>
                    <p className="text-xs font-medium">{new Date(trip.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                    {trip.plannedArrival && (
                      <span className="text-[10px] text-slate-400 font-medium">
                        ETA: {new Date(trip.plannedArrival).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white shadow-sm overflow-hidden ring-1 ring-slate-100">
                      {driver?.avatar ? (
                        <img src={driver.avatar} alt="" className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">
                          {driver?.name.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                      <p className="text-[10px] text-slate-500 uppercase font-medium">CNH: {driver?.license}</p>
                    </div>
                    <div className="flex gap-1">
                      <button 
                        onClick={() => handleOptimize(trip)}
                        className="w-8 h-8 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center hover:bg-blue-100 transition-colors"
                        title="Otimizar Rota Inteligente"
                      >
                        <i className="fas fa-wand-magic-sparkles"></i>
                      </button>
                      <button 
                        onClick={() => setReportingTrip(trip)}
                        className="w-8 h-8 rounded-full bg-orange-50 text-orange-600 flex items-center justify-center hover:bg-orange-100 transition-colors"
                        title="Relatar Ocorrência"
                      >
                        <i className="fas fa-triangle-exclamation"></i>
                      </button>
                    </div>
                  </div>

                  <div className="space-y-3">
                    <div className="flex gap-3">
                      <div className="flex flex-col items-center">
                        <i className="fas fa-circle-dot text-blue-500 text-[10px] mt-1"></i>
                        <div className="w-px h-full bg-slate-200 my-1"></div>
                        <i className="fas fa-location-dot text-red-500 text-[10px]"></i>
                      </div>
                      <div className="flex-1 space-y-3">
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Origem</p>
                          <p className="text-sm text-slate-700 font-medium truncate">{trip.origin}</p>
                        </div>
                        <div>
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Destino</p>
                          <p className="text-sm text-slate-800 font-bold truncate">{trip.destination}, {trip.city}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="pt-4 flex gap-2">
                    <button 
                      onClick={() => handleFinish(trip)}
                      className="flex-1 bg-emerald-600 text-white py-2.5 rounded-xl font-bold text-xs hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100 active:scale-95"
                    >
                      <i className="fas fa-check-circle mr-2"></i> Encerrar Viagem
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border border-dashed border-slate-200 shadow-sm">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
              <i className="fas fa-map-location-dot text-4xl"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Sem Movimentação</h3>
            <p className="text-slate-400 text-sm mt-2 max-w-xs mx-auto">Nenhuma viagem em andamento no momento.</p>
          </div>
        )}
      </div>

      {/* Finishing Modal */}
      {finishingTripId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-900 text-white">
              <h3 className="text-lg font-bold">Encerrar Viagem</h3>
              <p className="text-slate-400 text-xs mt-1">Informe a quilometragem atual do veículo para finalizar.</p>
            </div>
            <div className="p-8 space-y-6">
              <div>
                <label className="block text-xs font-write text-slate-400 uppercase mb-3 tracking-widest">KM Atual (Hodômetro)</label>
                <div className="relative">
                  <i className="fas fa-gauge absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                  <input 
                    type="number"
                    value={endKm}
                    onChange={(e) => setEndKm(parseInt(e.target.value))}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none font-write text-lg text-slate-800 transition-all"
                    placeholder="000000"
                    autoFocus
                  />
                </div>
                <p className="text-[10px] text-slate-400 mt-3 font-bold uppercase text-center">Data e Horário serão registrados automaticamente pelo sistema</p>
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setFinishingTripId(null)} className="flex-1 py-3 text-slate-400 font-write uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-colors">Voltar</button>
                <button onClick={confirmFinish} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-write uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Finalizar Agora</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripMonitoring;

import React, { useState, useMemo } from 'react';
import { useFleet } from '../context/FleetContext';
import { ScheduledTrip, Vehicle } from '../types';
import { checkSPRodizio, getRodizioDayLabel } from '../utils/trafficRules';

const SchedulingPage: React.FC = () => {
  const { drivers, vehicles, scheduledTrips, addScheduledTrip, deleteScheduledTrip } = useFleet();
  const [showForm, setShowForm] = useState(false);
  const [newSchedule, setNewSchedule] = useState({
    driverId: '',
    vehicleId: '',
    scheduledDate: new Date().toISOString().split('T')[0],
    origin: '',
    destination: '',
    city: '',
    notes: ''
  });

  const selectedVehicle = vehicles.find(v => v.id === newSchedule.vehicleId);

  const isRestricted = useMemo(() => {
    if (!selectedVehicle || !newSchedule.scheduledDate) return false;
    const [year, month, day] = newSchedule.scheduledDate.split('-').map(Number);
    const dateObj = new Date(year, month - 1, day);
    return checkSPRodizio(selectedVehicle.plate, dateObj);
  }, [selectedVehicle, newSchedule.scheduledDate]);

  const handleOpenMaps = () => {
    if (!newSchedule.destination) return;
    const query = encodeURIComponent(`${newSchedule.destination}${newSchedule.city ? ', ' + newSchedule.city : ''}`);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const handleAddSchedule = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newSchedule.driverId || !newSchedule.vehicleId || !newSchedule.destination) return;

    const trip: ScheduledTrip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: newSchedule.driverId,
      vehicleId: newSchedule.vehicleId,
      scheduledDate: newSchedule.scheduledDate,
      origin: newSchedule.origin,
      destination: newSchedule.destination,
      city: newSchedule.city,
      notes: newSchedule.notes
    };

    addScheduledTrip(trip);
    setNewSchedule({
      driverId: '',
      vehicleId: '',
      scheduledDate: new Date().toISOString().split('T')[0],
      origin: '',
      destination: '',
      city: '',
      notes: ''
    });
    setShowForm(false);
    alert('Viagem agendada com sucesso!');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Agenda de Viagens</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-200 transition-all"
        >
          <i className={`fas ${showForm ? 'fa-times' : 'fa-calendar-plus'}`}></i>
          {showForm ? 'Cancelar' : 'Agendar Viagem'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <form onSubmit={handleAddSchedule} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Motorista</label>
                <select
                  required
                  value={newSchedule.driverId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, driverId: e.target.value })}
                  className="w-full p-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950"
                >
                  <option value="">Selecione o condutor...</option>
                  {drivers.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Veículo</label>
                <select
                  required
                  value={newSchedule.vehicleId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, vehicleId: e.target.value })}
                  className={`w-full p-3 bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950 transition-all ${isRestricted ? 'border-amber-400' : 'border-slate-200'}`}
                >
                  <option value="">Selecione o veículo...</option>
                  {vehicles.map(v => (
                    <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Data da Viagem</label>
                <input
                  required
                  type="date"
                  value={newSchedule.scheduledDate}
                  onChange={(e) => setNewSchedule({ ...newSchedule, scheduledDate: e.target.value })}
                  className={`w-full p-3 bg-white border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950 transition-all ${isRestricted ? 'border-amber-400 ring-2 ring-amber-100 animate-pulse' : 'border-slate-200'}`}
                />
              </div>
            </div>

            {isRestricted && (
              <div className="bg-amber-50 border-2 border-amber-500/50 p-5 rounded-2xl flex items-start gap-4 animate-in slide-in-from-left-4 duration-500">
                <div className="w-12 h-12 bg-amber-500 text-white rounded-xl flex items-center justify-center text-xl font-write shrink-0 shadow-lg shadow-amber-200">
                  <i className="fas fa-exclamation-triangle"></i>
                </div>
                <div>
                  <h4 className="font-write text-amber-900 uppercase text-xs tracking-[0.2em] mb-1">Atenção: Rodízio Ativo</h4>
                  <p className="text-sm text-amber-800 font-medium leading-relaxed">
                    Este veículo (<span className="font-bold underline">{selectedVehicle?.plate}</span>) está sujeito ao rodízio em São Paulo às <span className="bg-amber-200 px-1.5 py-0.5 rounded font-write">{getRodizioDayLabel(selectedVehicle?.plate || '')}s</span>. 
                  </p>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Origem</label>
                <input
                  placeholder="Ex: Garagem Central"
                  value={newSchedule.origin}
                  onChange={(e) => setNewSchedule({ ...newSchedule, origin: e.target.value })}
                  className="w-full p-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Destino</label>
                <div className="flex gap-2">
                  <input
                    required
                    placeholder="Ex: Cliente Alfa"
                    value={newSchedule.destination}
                    onChange={(e) => setNewSchedule({ ...newSchedule, destination: e.target.value })}
                    className="flex-1 p-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950"
                  />
                  <button
                    type="button"
                    onClick={handleOpenMaps}
                    disabled={!newSchedule.destination}
                    className="w-11 h-11 bg-white border border-slate-200 text-slate-400 hover:text-red-600 hover:border-red-100 rounded-xl flex items-center justify-center transition-all shadow-sm"
                  >
                    <i className="fas fa-map-location-dot"></i>
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Cidade/UF</label>
                <input
                  placeholder="Ex: São Paulo / SP"
                  value={newSchedule.city}
                  onChange={(e) => setNewSchedule({ ...newSchedule, city: e.target.value })}
                  className="w-full p-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950"
                />
              </div>
            </div>

            <textarea
              placeholder="Notas Adicionais..."
              value={newSchedule.notes}
              onChange={(e) => setNewSchedule({ ...newSchedule, notes: e.target.value })}
              className="w-full p-4 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-bold text-slate-950 h-24 resize-none"
            />

            <div className="flex justify-end">
              <button type="submit" className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg transition-all">
                Salvar Agendamento
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest px-2">Viagens Planejadas</h3>
        {scheduledTrips.length > 0 ? (
          scheduledTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const [y, m, d] = trip.scheduledDate.split('-').map(Number);
            const tripDate = new Date(y, m - 1, d);
            const restricted = vehicle && checkSPRodizio(vehicle.plate, tripDate);

            return (
              <div key={trip.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row items-center gap-6 hover:shadow-md transition-all relative overflow-hidden">
                {restricted && <div className="absolute top-0 left-0 w-1 h-full bg-amber-500"></div>}

                <div className="w-full md:w-32 flex flex-col items-center justify-center p-3 bg-slate-50 rounded-2xl border border-slate-100 shrink-0">
                  <span className="text-2xl font-write text-slate-800">{tripDate.getDate()}</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase">{tripDate.toLocaleDateString('pt-BR', { month: 'short' })}</span>
                </div>

                <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Motorista</p>
                    <p className="font-bold text-slate-800">{driver?.name}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Veículo</p>
                    <p className="font-bold text-indigo-600">{vehicle?.plate} {restricted && '⚠️'}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Destino</p>
                    <p className="font-bold text-slate-800">{trip.destination}</p>
                  </div>
                </div>

                <button onClick={() => deleteScheduledTrip(trip.id)} className="w-10 h-10 rounded-full bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-100 transition-colors">
                  <i className="fas fa-trash-alt"></i>
                </button>
              </div>
            );
          })
        ) : (
          <div className="py-12 text-center bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <p className="text-slate-400 font-medium italic">Nenhuma viagem agendada.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SchedulingPage;

