import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Vehicle, Checklist, Trip, VehicleStatus } from '../types';
import { checkSPRodizio } from '../utils/trafficRules';

interface OperationWizardProps {
  scheduledTripId?: string;
  onComplete?: () => void;
}

const OperationWizard: React.FC<OperationWizardProps> = ({ scheduledTripId, onComplete }) => {
  const { vehicles, scheduledTrips, currentUser, startTrip, deleteScheduledTrip } = useFleet();
  const [step, setStep] = useState(1);

  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [checklist, setChecklist] = useState<Partial<Checklist>>({
    km: 0,
    fuelLevel: 50,
    oilChecked: false,
    waterChecked: false,
    tiresChecked: false,
    comments: ''
  });

  const [route, setRoute] = useState({
    origin: '',
    destination: '',
    waypoints: [] as string[],
    city: '',
    state: '',
    zipCode: '',
    plannedDeparture: new Date().toISOString().slice(0, 16),
    plannedArrival: '',
    observations: ''
  });

  useEffect(() => {
    if (scheduledTripId) {
      const schedule = scheduledTrips.find(s => s.id === scheduledTripId);
      if (schedule) {
        const vehicle = vehicles.find(v => v.id === schedule.vehicleId);
        if (vehicle) {
          setSelectedVehicle(vehicle);
          setRoute({
            origin: schedule.origin || '',
            destination: schedule.destination || '',
            waypoints: schedule.waypoints || [],
            city: schedule.city || '',
            state: schedule.state || '',
            zipCode: schedule.zipCode || '',
            plannedDeparture: new Date().toISOString().slice(0, 16),
            plannedArrival: schedule.plannedArrival || '',
            observations: schedule.notes || ''
          });
          setStep(2);
        }
      }
    }
  }, [scheduledTripId, scheduledTrips, vehicles]);

  useEffect(() => {
    if (selectedVehicle) {
      setChecklist(prev => ({ 
        ...prev, 
        km: selectedVehicle.currentKm, 
        fuelLevel: selectedVehicle.fuelLevel,
        oilChecked: false,
        waterChecked: false,
        tiresChecked: false 
      }));
    }
  }, [selectedVehicle]);

  const isKmInvalid = (checklist.km ?? 0) < (selectedVehicle?.currentKm ?? 0);

  const isChecklistValid = 
    checklist.oilChecked && 
    checklist.waterChecked && 
    checklist.tiresChecked && 
    !isKmInvalid &&
    (checklist.km ?? 0) > 0;

  const handleStartTrip = () => {
    if (!selectedVehicle || !currentUser) return;

    const deviceStartTime = new Date().toISOString();

    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      origin: route.origin,
      destination: route.destination,
      waypoints: route.waypoints,
      city: route.city,
      state: route.state,
      zipCode: route.zipCode,
      plannedDeparture: route.plannedDeparture || deviceStartTime,
      plannedArrival: route.plannedArrival,
      startTime: deviceStartTime,
      startKm: checklist.km || selectedVehicle.currentKm,
      observations: route.observations
    };

    const finalChecklist: Checklist = {
      ...checklist as Checklist,
      id: Math.random().toString(36).substr(2, 9),
      driverId: currentUser.id,
      vehicleId: selectedVehicle.id,
      timestamp: deviceStartTime
    };

    startTrip(newTrip, finalChecklist);

    if (scheduledTripId) {
      deleteScheduledTrip(scheduledTripId);
    }

    alert('Viagem iniciada! Tenha uma excelente jornada.');
    setStep(1);
    setSelectedVehicle(null);
    setRoute({
      origin: '',
      destination: '',
      waypoints: [],
      city: '',
      state: '',
      zipCode: '',
      plannedDeparture: new Date().toISOString().slice(0, 16),
      plannedArrival: '',
      observations: ''
    });
    onComplete?.();
  };

  return (
    <div className="max-w-4xl mx-auto py-4">
      <div className="flex items-center justify-between mb-8 px-4">
        {[
          { step: 1, label: 'Veículo', icon: 'fa-truck-pickup' },
          { step: 2, label: 'Checklist', icon: 'fa-clipboard-check' },
          { step: 3, label: 'Rota', icon: 'fa-map-marked-alt' }
        ].map((s) => (
          <div key={s.step} className="flex flex-col items-center flex-1">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${
              step >= s.step ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white border-slate-200 text-slate-400'
            }`}>
              <i className={`fas ${s.icon}`}></i>
            </div>
            <span className={`text-[10px] mt-2 font-write uppercase tracking-wider ${step >= s.step ? 'text-blue-600' : 'text-slate-300'}`}>
              {s.label}
            </span>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        {step === 1 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Qual veículo você está pegando?</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => {
                const restrictedToday = checkSPRodizio(v.plate);
                return (
                  <button
                    key={v.id}
                    onClick={() => setSelectedVehicle(v)}
                    className={`p-6 rounded-2xl border-2 text-left transition-all flex flex-col gap-4 relative ${
                      selectedVehicle?.id === v.id ? 'border-blue-600 bg-blue-50 ring-4 ring-blue-100' : 'border-slate-100 hover:border-blue-200'
                    }`}
                  >
                    {restrictedToday && (
                       <div className="absolute top-2 right-2 flex items-center gap-1 bg-amber-500 text-black font-write text-[8px] px-1.5 py-0.5 rounded shadow-sm">
                         <i className="fas fa-exclamation-triangle"></i> RODÍZIO SP HOJE
                       </div>
                    )}
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                        <i className="fas fa-truck text-xl"></i>
                      </div>
                      <div className="flex-1">
                        <p className="text-lg font-bold text-slate-800">{v.plate}</p>
                        <p className="text-xs text-slate-400 font-bold uppercase">{v.brand} {v.model}</p>
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
            <div className="mt-8 flex justify-end">
              <button
                disabled={!selectedVehicle}
                onClick={() => setStep(2)}
                className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-write uppercase text-xs tracking-widest hover:bg-blue-700 disabled:opacity-50 transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-2">Checklist de Saída</h3>
            <p className="text-slate-400 text-xs font-bold uppercase mb-8">Veículo: <span className="text-blue-600 underline">{selectedVehicle?.plate}</span></p>

            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Quilometragem Inicial</label>
                  <input
                    type="number"
                    min={selectedVehicle?.currentKm}
                    value={checklist.km}
                    onChange={(e) => setChecklist({ ...checklist, km: parseInt(e.target.value) || 0 })}
                    className={`w-full p-4 rounded-2xl border font-write text-slate-800 text-lg focus:ring-2 outline-none transition-all ${
                      isKmInvalid ? 'border-red-500 bg-red-50 focus:ring-red-200' : 'border-slate-200 bg-white focus:ring-blue-500'
                    }`}
                  />
                  {isKmInvalid ? (
                    <p className="text-[10px] mt-2 text-red-500 font-write uppercase animate-pulse">
                      <i className="fas fa-circle-exclamation mr-1"></i> A quilometragem não pode ser menor que o registro atual ({selectedVehicle?.currentKm} km)
                    </p>
                  ) : (
                    <p className="text-[10px] mt-2 text-slate-400 font-bold italic">Mínimo registrado: {selectedVehicle?.currentKm} km</p>
                  )}
                </div>
                <div>
                  <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Combustível</label>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={checklist.fuelLevel}
                    onChange={(e) => setChecklist({ ...checklist, fuelLevel: parseInt(e.target.value) })}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 mt-6"
                  />
                  <div className="flex justify-between text-[10px] font-write text-slate-400 mt-3 uppercase tracking-widest">
                    <span>Vazio</span>
                    <span className="text-blue-600 text-sm">{checklist.fuelLevel}%</span>
                    <span>Cheio</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4">
                {[
                  { key: 'oilChecked', label: 'Óleo', icon: 'fa-oil-can' },
                  { key: 'waterChecked', label: 'Água', icon: 'fa-tint' },
                  { key: 'tiresChecked', label: 'Pneus', icon: 'fa-car' }
                ].map(item => {
                  const isChecked = checklist[item.key as keyof Checklist];
                  return (
                    <button
                      key={item.key}
                      onClick={() => setChecklist({ ...checklist, [item.key]: !isChecked })}
                      className={`p-5 rounded-2xl border-2 flex flex-col items-center justify-center gap-3 transition-all ${
                        isChecked ? 'bg-emerald-50 border-emerald-500 text-emerald-600' : 'bg-slate-50 border-slate-100 text-slate-300'
                      }`}
                    >
                      <i className={`fas ${item.icon} text-xl`}></i>
                      <span className="font-write text-[10px] uppercase">{item.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="mt-10 flex justify-between">
              <button 
                onClick={() => scheduledTripId ? onComplete?.() : setStep(1)} 
                className="px-6 py-3 text-slate-400 font-write uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-all"
              >
                {scheduledTripId ? 'Cancelar' : 'Voltar'}
              </button>
              <button
                disabled={!isChecklistValid}
                onClick={() => setStep(3)}
                className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-write uppercase text-xs tracking-widest shadow-xl shadow-blue-100 disabled:opacity-30 transition-all flex items-center gap-2"
              >
                Próximo Passo <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="p-8">
            <h3 className="text-xl font-bold text-slate-800 mb-8">Confirmar Rota</h3>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Ponto de Saída</label>
                  <input
                    placeholder="Ex: Garagem Norte"
                    value={route.origin}
                    onChange={(e) => setRoute({ ...route, origin: e.target.value })}
                    className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                  />
                </div>

                <div>
                  <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Destino Final</label>
                  <input
                    placeholder="Endereço / Nome do Local"
                    value={route.destination}
                    onChange={(e) => setRoute({ ...route, destination: e.target.value })}
                    className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                  />
                </div>

                {/* Waypoints review in Wizard */}
                {route.waypoints.length > 0 && (
                  <div>
                    <label className="block text-xs font-write text-slate-400 uppercase tracking-widest mb-2">Paradas Confirmadas ({route.waypoints.length})</label>
                    <div className="space-y-2">
                      {route.waypoints.map((wp, i) => (
                        <div key={i} className="p-3 bg-slate-50 rounded-xl border border-slate-100 text-xs font-bold text-slate-600 flex items-center gap-3">
                          <span className="w-5 h-5 bg-white rounded-full flex items-center justify-center text-[10px] border border-slate-200">{i+1}</span>
                          {wp}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                <div className="grid grid-cols-2 gap-3">
                  <input
                    placeholder="Cidade"
                    value={route.city}
                    onChange={(e) => setRoute({ ...route, city: e.target.value })}
                    className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                  />
                  <input
                    placeholder="UF"
                    maxLength={2}
                    value={route.state}
                    onChange={(e) => setRoute({ ...route, state: e.target.value.toUpperCase() })}
                    className="w-full p-4 rounded-xl border border-slate-200 text-center focus:ring-2 focus:ring-blue-500 outline-none font-write text-slate-800"
                  />
                </div>
              </div>
            </div>

            <div className="mt-12 flex justify-between border-t border-slate-50 pt-8">
              <button onClick={() => setStep(2)} className="px-6 py-3 text-slate-400 font-write uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-xl transition-all">Voltar</button>
              <button
                onClick={handleStartTrip}
                disabled={!route.origin || !route.destination || !route.city}
                className="bg-emerald-600 text-white px-10 py-4 rounded-2xl font-write uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all flex items-center gap-3 disabled:opacity-30"
              >
                Confirmar Saída <i className="fas fa-check-double"></i>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default OperationWizard;

import React, { useState, useEffect } from 'react';
import { useFleet } from '../context/FleetContext';
import { Trip, Vehicle, Occurrence, OccurrenceSeverity } from '../types';
import { getOptimizedRoute } from '../services/geminiService';

const TripMonitoring: React.FC = () => {
  const { activeTrips, vehicles, drivers, occurrences, updateTrip, endTrip, cancelTrip, addOccurrence } = useFleet();
  const [finishingTripId, setFinishingTripId] = useState<string | null>(null);
  const [endKm, setEndKm] = useState<number>(0);
  const [now, setNow] = useState(new Date());

  // Route Editing State
  const [editingRouteTrip, setEditingRouteTrip] = useState<Trip | null>(null);
  const [editRouteForm, setEditRouteForm] = useState({
    destination: '',
    waypoints: [] as string[]
  });

  // Optimization State
  const [optimizingTripId, setOptimizingTripId] = useState<string | null>(null);
  const [optimizationResult, setOptimizationResult] = useState<{text: string, grounding: any[]} | null>(null);
  const [loadingOptimization, setLoadingOptimization] = useState(false);

  // Occurrence Modal State
  const [reportingTrip, setReportingTrip] = useState<Trip | null>(null);
  const [newOccurrence, setNewOccurrence] = useState({
    type: '',
    description: '',
    severity: OccurrenceSeverity.LOW
  });

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const getTripStatus = (trip: Trip) => {
    if (!trip.plannedArrival) return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
    const arrivalTime = new Date(trip.plannedArrival).getTime();
    const currentTime = now.getTime();
    if (currentTime > arrivalTime) return { label: 'Atrasado', color: 'bg-red-100 text-red-700 animate-pulse', icon: 'fa-clock' };
    return { label: 'Em Rota', color: 'bg-blue-100 text-blue-700', icon: 'fa-truck-moving' };
  };

  const handleOpenEditRoute = (trip: Trip) => {
    setEditingRouteTrip(trip);
    setEditRouteForm({
      destination: trip.destination,
      waypoints: trip.waypoints || []
    });
  };

  const handleUpdateActiveRoute = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingRouteTrip) {
      updateTrip(editingRouteTrip.id, {
        destination: editRouteForm.destination,
        waypoints: editRouteForm.waypoints.filter(w => w.trim() !== '')
      });
      setEditingRouteTrip(null);
      alert('Rota atualizada! O motorista receberá os novos dados.');
    }
  };

  const handleAddWaypointEdit = () => {
    setEditRouteForm(prev => ({ ...prev, waypoints: [...prev.waypoints, ''] }));
  };

  const handleUpdateWaypointEdit = (idx: number, val: string) => {
    const wps = [...editRouteForm.waypoints];
    wps[idx] = val;
    setEditRouteForm(prev => ({ ...prev, waypoints: wps }));
  };

  const handleRemoveWaypointEdit = (idx: number) => {
    setEditRouteForm(prev => ({ ...prev, waypoints: prev.waypoints.filter((_, i) => i !== idx) }));
  };

  const handleFinish = (trip: Trip) => {
    const vehicle = vehicles.find(v => v.id === trip.vehicleId);
    setFinishingTripId(trip.id);
    setEndKm(vehicle?.currentKm || 0);
  };

  const confirmFinish = () => {
    if (finishingTripId) {
      const deviceTime = new Date().toISOString();
      endTrip(finishingTripId, endKm, deviceTime);
      setFinishingTripId(null);
      alert('Viagem encerrada com sucesso!');
    }
  };

  const handleOptimize = async (trip: Trip) => {
    setOptimizingTripId(trip.id);
    setLoadingOptimization(true);
    try {
      const result = await getOptimizedRoute(trip.origin, trip.destination, trip.waypoints);
      setOptimizationResult(result);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingOptimization(false);
    }
  };

  const handleReportOccurrence = (e: React.FormEvent) => {
    e.preventDefault();
    if (!reportingTrip || !newOccurrence.type || !newOccurrence.description) return;
    const occ: Occurrence = {
      id: Math.random().toString(36).substr(2, 9),
      tripId: reportingTrip.id,
      vehicleId: reportingTrip.vehicleId,
      driverId: reportingTrip.driverId,
      type: newOccurrence.type,
      description: newOccurrence.description,
      severity: newOccurrence.severity,
      timestamp: new Date().toISOString(),
      resolved: false
    };
    addOccurrence(occ);
    setReportingTrip(null);
    setNewOccurrence({ type: '', description: '', severity: OccurrenceSeverity.LOW });
    alert('Ocorrência registrada.');
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Monitoramento de Viagens</h2>
        <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase">
          {activeTrips.length} Ativas
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {activeTrips.length > 0 ? (
          activeTrips.map(trip => {
            const vehicle = vehicles.find(v => v.id === trip.vehicleId);
            const driver = drivers.find(d => d.id === trip.driverId);
            const status = getTripStatus(trip);
            const tripOccurrences = occurrences.filter(o => o.tripId === trip.id);

            return (
              <div key={trip.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all relative">
                <div className="bg-slate-900 p-4 text-white flex justify-between items-center">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-mono text-xs">
                      {vehicle?.plate}
                    </div>
                    <p className="text-sm font-bold truncate leading-tight">{vehicle?.model}</p>
                  </div>
                  <button onClick={() => handleOpenEditRoute(trip)} className="text-[9px] font-write uppercase tracking-widest text-blue-400 hover:text-white transition-colors">
                    Alterar Rota
                  </button>
                </div>

                <div className="p-6 space-y-4">
                  <div className="flex items-center justify-between">
                    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase ${status.color}`}>
                      <i className={`fas ${status.icon}`}></i>
                      {status.label}
                    </span>
                  </div>

                  <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
                    <div className="w-10 h-10 rounded-full bg-slate-100 border overflow-hidden">
                      {driver?.avatar ? <img src={driver.avatar} alt="" className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center font-bold text-slate-400">{driver?.name.charAt(0)}</div>}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-800">{driver?.name}</p>
                      <p className="text-[10px] text-slate-500 uppercase">CNH: {driver?.license}</p>
                    </div>
                    <div className="flex gap-1">
                      <button onClick={() => handleOptimize(trip)} className="w-8 h-8 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center hover:bg-blue-100" title="Otimizar">
                        <i className="fas fa-wand-magic-sparkles"></i>
                      </button>
                      <button onClick={() => setReportingTrip(trip)} className="w-8 h-8 rounded-full bg-orange-50 text-orange-600 flex items-center justify-center hover:bg-orange-100" title="Ocorrência">
                        <i className="fas fa-triangle-exclamation"></i>
                      </button>
                    </div>
                  </div>

                  <div className="space-y-3">
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Origem</p>
                      <p className="text-sm text-slate-700 font-medium truncate">{trip.origin}</p>
                    </div>

                    {trip.waypoints && trip.waypoints.length > 0 && (
                      <div className="pl-2 border-l-2 border-slate-100 space-y-1">
                        <p className="text-[9px] font-bold text-indigo-400 uppercase tracking-widest mb-1">Paradas ({trip.waypoints.length})</p>
                        {trip.waypoints.map((wp, i) => (
                          <p key={i} className="text-[10px] text-slate-500 font-medium truncate">• {wp}</p>
                        ))}
                      </div>
                    )}

                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Destino</p>
                      <p className="text-sm text-slate-800 font-bold truncate">{trip.destination}</p>
                    </div>
                  </div>

                  <div className="pt-4 flex gap-2">
                    <button onClick={() => handleFinish(trip)} className="flex-1 bg-emerald-600 text-white py-2.5 rounded-xl font-bold text-xs hover:bg-emerald-700 shadow-md">
                      Encerrar Viagem
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full py-24 text-center bg-white rounded-3xl border border-dashed border-slate-200 shadow-sm">
            <p className="text-slate-400 text-sm mt-2">Nenhuma viagem em andamento.</p>
          </div>
        )}
      </div>

      {/* Modal Alterar Rota */}
      {editingRouteTrip && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-800 text-white flex justify-between items-center">
              <h3 className="text-lg font-write uppercase">Alterar Rota Ativa</h3>
              <button onClick={() => setEditingRouteTrip(null)} className="text-slate-400 hover:text-white"><i className="fas fa-times"></i></button>
            </div>
            <form onSubmit={handleUpdateActiveRoute} className="p-8 space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-2 tracking-widest">Novo Destino Final</label>
                <input 
                  required
                  value={editRouteForm.destination}
                  onChange={(e) => setEditRouteForm(prev => ({ ...prev, destination: e.target.value }))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                />
              </div>

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest">Paradas Intermediárias</label>
                  <button type="button" onClick={handleAddWaypointEdit} className="text-[10px] font-write text-blue-600 uppercase tracking-widest"><i className="fas fa-plus"></i> Adicionar</button>
                </div>
                <div className="max-h-48 overflow-y-auto space-y-3 pr-2">
                  {editRouteForm.waypoints.map((wp, i) => (
                    <div key={i} className="flex gap-2">
                      <input 
                        value={wp}
                        onChange={(e) => handleUpdateWaypointEdit(i, e.target.value)}
                        className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-xs font-bold"
                        placeholder={`Parada ${i+1}`}
                      />
                      <button type="button" onClick={() => handleRemoveWaypointEdit(i)} className="text-red-300 hover:text-red-500"><i className="fas fa-trash-alt"></i></button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="flex gap-3 pt-4 border-t border-slate-50">
                <button type="button" onClick={() => setEditingRouteTrip(null)} className="flex-1 py-4 text-slate-400 font-write uppercase text-[10px]">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-write uppercase text-xs shadow-xl shadow-blue-100">Atualizar Rota</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Finishing Modal */}
      {finishingTripId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
            <div className="p-6 bg-slate-900 text-white">
              <h3 className="text-lg font-bold">Encerrar Viagem</h3>
            </div>
            <div className="p-8 space-y-6">
              <div>
                <label className="block text-xs font-write text-slate-400 uppercase mb-3">KM Atual (Hodômetro)</label>
                <input 
                  type="number"
                  value={endKm}
                  onChange={(e) => setEndKm(parseInt(e.target.value))}
                  className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none font-write text-lg text-slate-800 text-center"
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setFinishingTripId(null)} className="flex-1 py-3 text-slate-400 font-write uppercase text-[10px]">Voltar</button>
                <button onClick={confirmFinish} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-write uppercase text-xs">Finalizar Agora</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TripMonitoring;

import React, { useState } from 'react';
import { useFleet } from '../context/FleetContext';
import { VehicleStatus, MaintenanceRecord, Vehicle } from '../types';

const FleetManager: React.FC = () => {
  const { vehicles, maintenanceRecords, addMaintenanceRecord, resolveMaintenance, addVehicle, updateVehicle } = useFleet();
  const [showMaintenanceForm, setShowMaintenanceForm] = useState(false);
  const [showVehicleForm, setShowVehicleForm] = useState(false);
  const [editingVehicleId, setEditingVehicleId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');

  // Modal para finalizar manutenção
  const [resolvingMaintenance, setResolvingMaintenance] = useState<{recordId: string, vehicleId: string} | null>(null);
  const [resolveKm, setResolveKm] = useState<number>(0);
  const [resolveDate, setResolveDate] = useState(new Date().toISOString().slice(0, 16));

  const [newRecord, setNewRecord] = useState({
    vehicleId: '',
    date: new Date().toISOString().split('T')[0],
    serviceType: '',
    cost: '',
    km: '',
    notes: '',
    isTireChange: false,
    tireBrand: '',
    tireModel: ''
  });

  const [newVehicle, setNewVehicle] = useState({
    plate: '',
    brand: '',
    model: '',
    year: new Date().getFullYear().toString(),
    currentKm: '',
    fuelLevel: '100',
    fuelType: 'Diesel' as Vehicle['fuelType']
  });

  const handleSubmitMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecord.vehicleId || !newRecord.serviceType || !newRecord.cost || !newRecord.km) return;

    let finalNotes = newRecord.notes;
    let finalServiceType = newRecord.serviceType;

    if (newRecord.isTireChange) {
      finalServiceType = 'Troca de Pneus';
      const tireDetails = `Pneus: ${newRecord.tireBrand} ${newRecord.tireModel}`;
      finalNotes = finalNotes ? `${tireDetails} | ${finalNotes}` : tireDetails;
    }

    const record: MaintenanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      vehicleId: newRecord.vehicleId,
      date: newRecord.date,
      serviceType: finalServiceType,
      cost: parseFloat(newRecord.cost),
      km: parseInt(newRecord.km),
      notes: finalNotes
    };

    addMaintenanceRecord(record);
    setNewRecord({ 
      vehicleId: '', 
      date: new Date().toISOString().split('T')[0], 
      serviceType: '', 
      cost: '', 
      km: '', 
      notes: '',
      isTireChange: false,
      tireBrand: '',
      tireModel: ''
    });
    setShowMaintenanceForm(false);
    alert('Manutenção registrada!');
  };

  const handleResolveMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!resolvingMaintenance || !resolveKm) return;

    resolveMaintenance(resolvingMaintenance.vehicleId, resolvingMaintenance.recordId, resolveKm, resolveDate);
    setResolvingMaintenance(null);
    alert('Manutenção finalizada! O veículo retornou ao status DISPONÍVEL.');
  };

  const handleSubmitVehicle = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newVehicle.plate || !newVehicle.brand || !newVehicle.model) return;

    if (editingVehicleId) {
      updateVehicle(editingVehicleId, {
        plate: newVehicle.plate.toUpperCase(),
        brand: newVehicle.brand,
        model: newVehicle.model,
        year: parseInt(newVehicle.year),
        currentKm: parseInt(newVehicle.currentKm) || 0,
        fuelType: newVehicle.fuelType
      });
      alert('Veículo atualizado com sucesso!');
    } else {
      const vehicle: Vehicle = {
        id: Math.random().toString(36).substr(2, 9),
        plate: newVehicle.plate.toUpperCase(),
        brand: newVehicle.brand,
        model: newVehicle.model,
        year: parseInt(newVehicle.year),
        currentKm: parseInt(newVehicle.currentKm) || 0,
        fuelLevel: parseInt(newVehicle.fuelLevel),
        fuelType: newVehicle.fuelType,
        status: VehicleStatus.AVAILABLE
      };
      addVehicle(vehicle);
      alert('Veículo cadastrado com sucesso!');
    }

    setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100', fuelType: 'Diesel' });
    setShowVehicleForm(false);
    setEditingVehicleId(null);
  };

  const handleEditVehicle = (vehicle: Vehicle) => {
    setNewVehicle({
      plate: vehicle.plate,
      brand: vehicle.brand,
      model: vehicle.model,
      year: vehicle.year.toString(),
      currentKm: vehicle.currentKm.toString(),
      fuelLevel: vehicle.fuelLevel.toString(),
      fuelType: vehicle.fuelType
    });
    setEditingVehicleId(vehicle.id);
    setShowVehicleForm(true);
    setShowMaintenanceForm(false);
  };

  const filteredVehicles = vehicles.filter(v => {
    const matchesSearch = v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || v.model.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestão da Frota</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Controle de Ativos e Manutenções</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button 
            onClick={() => {
              setShowMaintenanceForm(!showMaintenanceForm);
              setShowVehicleForm(false);
              setEditingVehicleId(null);
            }} 
            className="bg-slate-800 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-700 transition-all"
          >
            <i className={`fas ${showMaintenanceForm ? 'fa-times' : 'fa-wrench'}`}></i> 
            {showMaintenanceForm ? 'Cancelar' : 'Registrar Manutenção'}
          </button>
          <button 
            onClick={() => {
              if (showVehicleForm && editingVehicleId) {
                 setEditingVehicleId(null);
                 setNewVehicle({ plate: '', brand: '', model: '', year: new Date().getFullYear().toString(), currentKm: '', fuelLevel: '100', fuelType: 'Diesel' });
              }
              setShowVehicleForm(!showVehicleForm);
              setShowMaintenanceForm(false);
            }} 
            className="bg-blue-600 text-white px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all"
          >
            <i className={`fas ${showVehicleForm ? 'fa-times' : 'fa-plus'}`}></i> 
            {showVehicleForm ? 'Cancelar' : (editingVehicleId ? 'Cancelar Edição' : 'Novo Veículo')}
          </button>
        </div>
      </div>

      {/* Form Cadastro/Edição Veículo */}
      {showVehicleForm && (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-sm font-write text-slate-800 uppercase tracking-widest mb-6">
            {editingVehicleId ? 'Editar Veículo' : 'Cadastro de Veículo'}
          </h3>
          <form onSubmit={handleSubmitVehicle} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Placa</label>
              <input required placeholder="ABC-1234" value={newVehicle.plate} onChange={(e) => setNewVehicle({ ...newVehicle, plate: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Marca</label>
              <input required placeholder="Ex: Mercedes-Benz" value={newVehicle.brand} onChange={(e) => setNewVehicle({ ...newVehicle, brand: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Modelo</label>
              <input required placeholder="Ex: Sprinter 415" value={newVehicle.model} onChange={(e) => setNewVehicle({ ...newVehicle, model: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Ano</label>
              <input required type="number" placeholder="2024" value={newVehicle.year} onChange={(e) => setNewVehicle({ ...newVehicle, year: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">KM Atual</label>
              <input required type="number" placeholder="0" value={newVehicle.currentKm} onChange={(e) => setNewVehicle({ ...newVehicle, currentKm: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Tipo de Combustível</label>
              <select required value={newVehicle.fuelType} onChange={(e) => setNewVehicle({ ...newVehicle, fuelType: e.target.value as Vehicle['fuelType'] })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                <option value="Diesel">Diesel</option>
                <option value="Gasolina">Gasolina</option>
                <option value="Flex">Flex</option>
                <option value="Elétrico">Elétrico</option>
                <option value="GNV">GNV</option>
              </select>
            </div>
            <button type="submit" className="bg-blue-600 text-white py-4 rounded-xl font-write uppercase text-xs tracking-widest shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all md:col-span-3">
              {editingVehicleId ? 'Salvar Alterações' : 'Salvar Veículo'}
            </button>
          </form>
        </div>
      )}

      {/* Form Registro Manutenção */}
      {showMaintenanceForm && (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-sm font-write text-slate-800 uppercase tracking-widest mb-6">Registrar Saída para Manutenção</h3>
          <form onSubmit={handleSubmitMaintenance} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Veículo Destinado</label>
                <select required value={newRecord.vehicleId} onChange={(e) => setNewRecord({ ...newRecord, vehicleId: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none">
                  <option value="">Selecione o veículo...</option>
                  {vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).map(v => <option key={v.id} value={v.id}>{v.plate} - {v.model}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Tipo de Serviço</label>
                {!newRecord.isTireChange ? (
                  <input required type="text" placeholder="Ex: Troca de pastilhas de freio" value={newRecord.serviceType} onChange={(e) => setNewRecord({ ...newRecord, serviceType: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
                ) : (
                  <div className="w-full p-3 bg-slate-100 border border-slate-200 rounded-xl text-slate-400 font-bold flex items-center gap-2">
                    <i className="fas fa-circle-check text-emerald-500"></i> Troca de Pneus
                  </div>
                )}
              </div>
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Opções Especiais</label>
                <button 
                  type="button"
                  onClick={() => setNewRecord({ ...newRecord, isTireChange: !newRecord.isTireChange, serviceType: !newRecord.isTireChange ? 'Troca de Pneus' : '' })}
                  className={`w-full p-3 border rounded-xl font-bold text-xs uppercase transition-all flex items-center justify-center gap-2 ${newRecord.isTireChange ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:border-emerald-200'}`}
                >
                  <i className="fas fa-car-rear"></i> {newRecord.isTireChange ? 'Troca de Pneus Ativada' : 'É Troca de Pneus?'}
                </button>
              </div>
            </div>

            {newRecord.isTireChange && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-emerald-50 p-6 rounded-2xl border border-emerald-100 animate-in slide-in-from-left-4 duration-300">
                <div>
                  <label className="block text-[10px] font-write text-emerald-800 uppercase mb-2">Marca dos Pneus</label>
                  <input required placeholder="Ex: Michelin, Pirelli..." value={newRecord.tireBrand} onChange={(e) => setNewRecord({ ...newRecord, tireBrand: e.target.value })} className="w-full p-3 bg-white border border-emerald-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
                </div>
                <div>
                  <label className="block text-[10px] font-write text-emerald-800 uppercase mb-2">Modelo dos Pneus</label>
                  <input required placeholder="Ex: Primacy 4, PZero..." value={newRecord.tireModel} onChange={(e) => setNewRecord({ ...newRecord, tireModel: e.target.value })} className="w-full p-3 bg-white border border-emerald-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-emerald-500 outline-none" />
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">KM de Saída</label>
                <input required type="number" placeholder="Ex: 45000" value={newRecord.km} onChange={(e) => setNewRecord({ ...newRecord, km: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Custo Estimado (R$)</label>
                <input required type="number" step="0.01" placeholder="0.00" value={newRecord.cost} onChange={(e) => setNewRecord({ ...newRecord, cost: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Data de Saída</label>
                <input required type="date" value={newRecord.date} onChange={(e) => setNewRecord({ ...newRecord, date: e.target.value })} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div className="md:col-span-2 lg:col-span-3">
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Observações Adicionais</label>
                <textarea value={newRecord.notes} onChange={(e) => setNewRecord({ ...newRecord, notes: e.target.value })} placeholder="Alguma observação importante sobre o serviço?" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-950 font-bold focus:ring-2 focus:ring-blue-500 outline-none min-h-[100px]"></textarea>
              </div>
              <button type="submit" className="bg-slate-900 text-white py-4 rounded-xl font-write uppercase text-xs tracking-widest hover:bg-slate-800 transition-all lg:col-span-1 md:col-span-2">Confirmar Envio</button>
            </div>
          </form>
        </div>
      )}

      {/* Modal Finalizar Manutenção */}
      {resolvingMaintenance && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-6 bg-slate-800 text-white">
              <h3 className="text-lg font-write uppercase tracking-tight">Finalizar Manutenção</h3>
              <p className="text-slate-400 text-[10px] uppercase font-bold mt-1">Registrar retorno do veículo</p>
            </div>
            <form onSubmit={handleResolveMaintenance} className="p-8 space-y-6">
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">KM Atual de Retorno</label>
                <input 
                  type="number" 
                  required 
                  value={resolveKm} 
                  onChange={(e) => setResolveKm(parseInt(e.target.value))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-write text-xl text-slate-800 text-center"
                  placeholder="000000"
                />
              </div>
              <div>
                <label className="block text-[10px] font-write text-slate-400 uppercase mb-2">Data/Hora do Retorno</label>
                <input 
                  type="datetime-local" 
                  required 
                  value={resolveDate} 
                  onChange={(e) => setResolveDate(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-800"
                />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setResolvingMaintenance(null)} className="flex-1 py-4 text-slate-400 font-write uppercase text-[10px] tracking-widest hover:bg-slate-50 rounded-2xl">Voltar</button>
                <button type="submit" className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-write uppercase text-xs tracking-widest shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all">Confirmar Retorno</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex-1 relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
          <input 
            type="text" 
            placeholder="Buscar por placa ou modelo..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-950 focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>
        <select 
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-write text-slate-700 uppercase outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="ALL">Todos os Status</option>
          <option value={VehicleStatus.AVAILABLE}>Disponível</option>
          <option value={VehicleStatus.IN_USE}>Em Uso</option>
          <option value={VehicleStatus.MAINTENANCE}>Manutenção</option>
        </select>
      </div>

      {/* Vehicle Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredVehicles.map(vehicle => {
          const vehicleMaintenances = maintenanceRecords
            .filter(m => m.vehicleId === vehicle.id)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

          const activeMaintenance = vehicle.status === VehicleStatus.MAINTENANCE 
            ? vehicleMaintenances.find(m => !m.returnDate) 
            : null;

          return (
            <div key={vehicle.id} className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden flex flex-col hover:shadow-md transition-all">
              <div className="p-6 border-b border-slate-50">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex flex-col gap-1">
                    <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-mono text-xs font-write shadow-sm tracking-widest">{vehicle.plate}</span>
                    <p className="text-[10px] font-write text-slate-400 uppercase">{vehicle.brand}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => handleEditVehicle(vehicle)}
                      className="w-8 h-8 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:text-blue-600 hover:bg-blue-50 transition-all"
                      title="Editar Veículo"
                    >
                      <i className="fas fa-edit text-xs"></i>
                    </button>
                    <span className={`text-[10px] font-write px-3 py-1 rounded-full uppercase tracking-widest border-2 ${
                      vehicle.status === VehicleStatus.AVAILABLE ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                      vehicle.status === VehicleStatus.IN_USE ? 'bg-blue-50 text-blue-600 border-blue-100' : 
                      'bg-red-50 text-red-600 border-red-100'
                    }`}>
                      {vehicle.status === VehicleStatus.AVAILABLE ? 'Livre' : vehicle.status === VehicleStatus.IN_USE ? 'Em Rota' : 'Oficina'}
                    </span>
                  </div>
                </div>
                <h4 className="text-lg font-write text-slate-800 tracking-tight">{vehicle.model}</h4>
                <div className="mt-4 grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-write text-slate-400 uppercase tracking-widest mb-1">Odômetro</p>
                    <p className="text-sm font-write text-slate-800">{vehicle.currentKm.toLocaleString()} KM</p>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-write text-slate-400 uppercase tracking-widest mb-1">Ano/Combustível</p>
                    <p className="text-xs font-write text-slate-800">{vehicle.year} • {vehicle.fuelType}</p>
                  </div>
                </div>

                {activeMaintenance && (
                  <div className="mt-6 p-4 bg-red-50 rounded-2xl border border-red-100 animate-pulse">
                    <div className="flex justify-between items-center mb-2">
                       <span className="text-[9px] font-write text-red-600 uppercase tracking-widest">Manutenção em Aberto</span>
                       <i className="fas fa-wrench text-red-400"></i>
                    </div>
                    <p className="text-xs font-bold text-slate-800">{activeMaintenance.serviceType}</p>
                    <button 
                      onClick={() => {
                        setResolvingMaintenance({recordId: activeMaintenance.id, vehicleId: vehicle.id});
                        setResolveKm(vehicle.currentKm);
                      }}
                      className="w-full mt-3 py-2 bg-red-600 text-white rounded-xl text-[10px] font-write uppercase tracking-widest hover:bg-red-700 transition-all shadow-lg shadow-red-200"
                    >
                      Finalizar Manutenção
                    </button>
                  </div>
                )}
              </div>

              {/* Maintenance History Section */}
              <div className="p-6 flex-1 bg-slate-50/50">
                <div className="flex items-center justify-between mb-4">
                  <h5 className="text-[10px] font-write text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <i className="fas fa-history"></i> Histórico Técnico
                  </h5>
                  <span className="text-[9px] font-bold text-slate-300">{vehicleMaintenances.length} registros</span>
                </div>

                <div className="space-y-3 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                  {vehicleMaintenances.length > 0 ? (
                    vehicleMaintenances.map(m => {
                      const isTireService = m.serviceType === 'Troca de Pneus' || m.notes.toLowerCase().includes('pneus:');
                      return (
                        <div key={m.id} className={`bg-white p-3 rounded-2xl border shadow-sm group hover:border-blue-200 transition-colors ${m.returnDate ? 'border-slate-100' : 'border-red-200 bg-red-50/20'} ${isTireService ? 'border-emerald-100 ring-1 ring-emerald-50' : ''}`}>
                          <div className="flex justify-between items-start">
                            <p className="text-xs font-write text-slate-900 leading-tight mb-1 flex items-center gap-2">
                              {isTireService && <i className="fas fa-car-rear text-emerald-500 text-[10px]"></i>}
                              {m.serviceType}
                            </p>
                            <span className="text-[9px] font-write text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded uppercase">R$ {m.cost.toFixed(2)}</span>
                          </div>
                          <div className="flex items-center justify-between mt-2">
                            <div className="flex flex-col">
                              <p className="text-[10px] text-slate-400 font-bold">Saída: {new Date(m.date).toLocaleDateString('pt-BR')} | {m.km} KM</p>
                              {m.returnDate && (
                                <p className="text-[9px] text-emerald-600 font-write uppercase mt-0.5">Retorno: {new Date(m.returnDate).toLocaleDateString('pt-BR')}</p>
                              )}
                            </div>

                            {m.notes && (
                              <div className="relative group/note">
                                <i className="fas fa-comment-dots text-slate-300 cursor-help hover:text-blue-500 transition-colors"></i>
                                <div className="absolute bottom-full right-0 mb-2 w-48 p-3 bg-slate-800 text-white text-[10px] rounded-2xl opacity-0 invisible group-hover/note:opacity-100 group-hover/note:visible transition-all z-50 pointer-events-none shadow-2xl border border-slate-700 translate-y-2 group-hover/note:translate-y-0">
                                  <div className="font-write uppercase text-[8px] text-blue-400 mb-1.5 border-b border-slate-700 pb-1 flex items-center gap-1">
                                    <i className="fas fa-info-circle"></i> {isTireService ? 'Detalhes dos Pneus' : 'Observações'}
                                  </div>
                                  <p className="leading-relaxed text-slate-200 font-medium">{m.notes}</p>
                                  <div className="absolute top-full right-3 -mt-1 border-4 border-transparent border-t-slate-800"></div>
                                </div>
                              </div>
                            )}
                          </div>
                        </div>
                      );
                    })
                  ) : (
                    <div className="py-8 text-center border-2 border-dashed border-slate-200 rounded-3xl">
                      <p className="text-[10px] font-write text-slate-300 uppercase italic">Sem manutenções registradas</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="p-4 bg-white border-t border-slate-50">
                <button className="w-full py-2 bg-slate-50 text-slate-400 text-[10px] font-write uppercase tracking-widest rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-all">
                  Ver Ficha Completa
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default FleetManager;
